SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

-- ----------------------------
-- 表结构: activity
-- ----------------------------
DROP TABLE IF EXISTS `activity`;
CREATE TABLE `activity` (
  `id` int NOT NULL AUTO_INCREMENT,
  `creator_id` int NOT NULL,
  `created_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `type` varchar(256) NOT NULL DEFAULT '',
  `level` varchar(256) NOT NULL DEFAULT 'INFO',
  `payload` text NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 activity 无数据

-- ----------------------------
-- 表结构: idp
-- ----------------------------
DROP TABLE IF EXISTS `idp`;
CREATE TABLE `idp` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` text NOT NULL,
  `type` text NOT NULL,
  `identifier_filter` varchar(256) NOT NULL DEFAULT '',
  `config` text NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 idp 无数据

-- ----------------------------
-- 表结构: inbox
-- ----------------------------
DROP TABLE IF EXISTS `inbox`;
CREATE TABLE `inbox` (
  `id` int NOT NULL AUTO_INCREMENT,
  `created_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `sender_id` int NOT NULL,
  `receiver_id` int NOT NULL,
  `status` text NOT NULL,
  `message` text NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 inbox 无数据

-- ----------------------------
-- 表结构: memo
-- ----------------------------
DROP TABLE IF EXISTS `memo`;
CREATE TABLE `memo` (
  `id` int NOT NULL AUTO_INCREMENT,
  `uid` varchar(256) NOT NULL,
  `creator_id` int NOT NULL,
  `created_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `row_status` varchar(256) NOT NULL DEFAULT 'NORMAL',
  `content` text NOT NULL,
  `visibility` varchar(256) NOT NULL DEFAULT 'PRIVATE',
  `pinned` tinyint(1) NOT NULL DEFAULT '0',
  `payload` json NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uid` (`uid`)
) ENGINE=InnoDB AUTO_INCREMENT=3562 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 memo 数据
\n　　1、一杯清水因滴入一滴污水而变污浊，一杯污水却不会因一滴清水的存在而变清澈。\n　　2、这世上有三样东西是别人抢不走的：一是吃进胃里的食物，二是藏在心中的梦想，三是读进大脑的书。\n　　3、马在松软的土地上易失蹄，人在甜言蜜语中易摔跤。\n　　4、世界没有悲剧和喜剧之分，如果你能从悲剧中走出来，那就是喜剧，如果你沉缅于喜剧之中，那它就是悲剧。\n　　5、如果不读书，行万里路也不过是个邮差。\n　　6、当你的邻居在深夜两点弹钢琴时你别气恼，你可以在四点钟时叫醒他，并告并告诉他你很欣赏他的演奏。\n　　7、如果你只是等待，发生的事情只会是你变老了。\n　　8、真正的朋友不是在一起有聊不完的话，而是即使不说一句话也不觉得尴尬。\n　　9、时间是治疗心灵创伤的大师，但绝不是解决问题的高手。\n　　1 0、宁愿做过了后悔，也不要错过了后悔!  #精彩剪辑', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {"hasLink": true}}'),
(3139, 'ceeCtwXSBzNbVSsakrsGBt', 1, '2025-02-12 15:44:12', '2025-02-14 15:44:28', 'NORMAL', '今天是 2025 年 2 月 12 日，\n敬中午带我妈去庚玖医院看眼睛说是白内障早起不适合做手术，具体也不懂\n今天是元宵节明天是加加的生日，加加的生日一起过了，我妈包了饺子买了汤圆，敬今天不上班，下午 16 点左右我妈出去买汤圆。有些饿了就下了点饺子先吃着想晚会在做正事的饭吃，我妈出去回来了，就把汤圆也煮了，我们先吃了我煮的一些，不会她煮了一大锅饺子没人吃，她叫了没人吃，我吃了些，敬吃几个娃们没咋吃，就怕我饿着了，就开始不愉快说过个节不像过节的样，加加生日也不想多弄些菜，我妈说敬不做饭。\n晚上果果画画写作业，好兴奋，和我聊了好多，她开心我也开心，开心是她打开心扉，这很重要。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3140, 'e3qNj2KkHMbtp4dTAmMJGT', 1, '2025-02-11 15:44:57', '2025-02-14 15:44:57', 'NORMAL', '今天是 2025 年 2 月 11 日，中午让我睡觉，坐会困了躺下睡了，果果 15 点多要接，15:35 的时候醒了，加加一个人在家，奶奶去接果果了，问加加在家怕不怕不怕，家里有人呀睡着了也不怕，觉得自己在孩子心中还是有用的。\n这两天拉稀每次不多，一点点，想应该是最近油的食物吃的太多了吧。\n从天津寄过来的快递到了一个，口破了被子少了一个，很担心后面一个快递呀里面琐碎的东西多，里面还有药呢，认为系的挺好的了怎会散架呢即使散架他们也应该在包装下吧。太没责任了\n加入我真的没了，敬是最累的，半路夫妻有几个幸福的\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3141, '2xZFLHrtaoDkejUYE56gmm', 1, '2025-02-14 15:45:23', '2025-02-14 15:45:23', 'NORMAL', '今天 2025 年 2 月 9 日，昨天座车回合肥了，刚走还觉得近 4 个小时时间好长，到了觉得还挺快的，车上人不多。\n早上 6 点多被闹钟吵醒的，吃个药就坐着了，我妈在管这那的就烦。\n泰康的报销说重复申请了，说是因为 1 月 15 的报销过了那是门诊，这是住院说是重复了，应该是有解决办法的，明天周一上班了她来问问。\n在家待一天手就痒了，貌似是冻的，嘿才一天，洗手水是凉的好不喜欢呀。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3142, 'gBQHUDchSDqQTx7yvwFykf', 1, '2025-02-14 15:45:46', '2025-02-14 15:45:46', 'NORMAL', '今天是2025 年 2 月 8 日，凌晨 0 点左右睡着的，5 点多醒的，夜间做梦，在学校的时候班级养了头大象要轮流照顾负责它，我给他喂冰棍，最终养死了，老师反正原因是那一组出现的问题。\n早上不知怎的想到有 2 次 敬要离家出走了，有次还跑到火车站后给她接回来。那时我们真的有那么大的矛盾吗？都是晚上的的时候，我记不得因为什么了，性吗好像是，她不同意我就在外面生闷气，她大声说话我怕打扰孩子睡觉，她就气跑了。\n快递打了申通和京东的，申通的说今天去不了要送过去，京东的说 21 点时间不确定，15 点左右出去走走，我妈要去快递的地方看看，问驿站有没小推车确认有去借了，一车就推过去了，那帮快递的体积大按体积重的按重量，120 元左右 3 个包寄走了，也没本事拿到别的地方了。来回折腾了。\n我妈给我说件事说我结婚那年和我爸回去砍树把电线砸坏了还找的人处理的赔了 70 元，觉得官呀。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3143, 'L4pMj7q9fJfyHVLjh2cTyx', 1, '2025-02-14 15:46:01', '2025-02-14 15:46:01', 'NORMAL', '今天是 2025 年 2 月 7 日，时间过得很快明天就要回合肥了。牵涉到一个问题我妈的问题。\n我是不想让我妈在合肥待的，和她在一起生活的够够的，一天和她一句话也不想说，吃饭每天都会有顿面条，我在看视频听书她来句像学校爱说话的学生，我有一点不舒服状况看她满脸的愁像就烦，听她喊我儿子别扭，和她在一起没有安全感操心她收拾东西不放心，不像敬她收拾我什么都不用管。\n敬应是应是希望的，她的角度是能做做饭照顾我接接娃的，我不会累到。我认为我的身体是没问题的可以干这些的，我也不想一直闲着，觉得自己是个无用的人，我妈在天津的这段时间干干着那的非要给我洗头也是这么想的吧。假如真的复发了我觉得和开些活也没啥关系。\n娃们呢估计他们也不想在合肥待着，带给他们不好的习惯，时间长娃们的性格会随她。我被她害了不能在害娃了，想着用很多性格像她我就烦恨他，觉得没生在好的家庭。想起父母都不识字就觉得自己起点太低。小时没出去不觉得，大了和人交往就暴漏了，带出来的闺女儿在家庭中都是笨的弱势的。\n我妈呢不只是真的想照顾我还是想让我给她养老了，即使养老我也不想和父母们住一起只会活的时间更短，和我妈在这待这么久够够的，听敬说家里冷她还想在天津住不知是真的想着我还是真的住舒服安逸了。嘴上不说脑子心眼也多，想着她的孩子夫妻之前会吵架打架，应是小时候和我爸老打架有关吧。\n我爸肯定是想让我妈回去的，还等着种菜卖菜呢，他一个人在上虞待的也急\n客观条件是睡不开，假如我妈睡客厅。一个方案敬和果果一个房间，我和加加一个房间，我和敬一直分开着吗生活沟通交流也少了。另一个果果自己睡，我敬加加一起现在果果加加敬一起都挤我们三个更挤了。想起房子就想起我爹的那句 5w 你待还我。虽然他们也给钱但他们并没有让我觉得他们是我的靠背可以依靠的。我妈不在这住我想睡客厅等加加想睡客厅了在还给他。客厅的床本就是给加加准备的不是给老娘。\n假如那天真的又恶化了我该怎么办，让我妈过来。假如真的那一天就放弃治疗吧，手术的罪我是不想在受了，家庭也负担不起了。\n假如敬和我离婚了，财产孩子都归她了，我怎么办，肯定是恶化的原因了，不会有人再带我去医院了，是去上虞还是回阜阳，要 over 了。\n不去想那么多，朝着 30 年 50 年的目标迈进， 向往美好的生活。尽力而为，静待花开。\n心态不能在以前了，可环境没变人怎么能变呢。要钓鱼读读佛经吗。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3144, 'eYXv4Mb3dHcgjmKqisttP3', 1, '2025-02-14 15:46:14', '2025-02-14 15:46:14', 'NORMAL', '今天是 2025 年 2 月 6 日，\n给周长宝发给消息，本想说把床寄给他的，他说要来来就来吧，在饭店吃的铁锅鱼，聊会就回去了。\n敬都是去黄河路校区上班，突然想会不会老板想离家近接送娃容易摸鱼呀，就安排远点的校区了，随便看把到时真的那天关系不好了及时撤出来吧，避免影响感情，也不可能在一个地方打一辈子工吧，\n夜里刮起了妖风，这边的天气很奇怪，夜间多次刮大风了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3145, 'K39xhvPgN7Cn7UakP6wHyg', 1, '2025-02-14 15:46:23', '2025-02-14 15:46:23', 'NORMAL', '敬还是 2025 年 2 月 4 日，娃们从姥姥家回来，敬不上班，二亚也没去合肥带他们，视频通的也多了，觉得自己在娃们看来还是有地位有影响的，\n手机快没电了，加宝来了句手机饿成兔子了，一下子没反应过来，后想明白了，手机亏电到自动关机充电显示了米兔的图标，这么久远的事情他居然还记得。加加每次都分开心，吃饭摇来摇去还担心多动呢，后想是开心的表现。\n果果没那么开心话了不多了，别的初中生也是如此吧，可这不是我想看到的，希望她乐观积极健康，有事能和爸妈分享。\n我妈愿意干嘛就干嘛我也不管了，随便她，懒得操心管，反正也不会改，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3146, 'JA3SEdCptBcMvwvcLdzqVX', 1, '2025-02-14 15:46:38', '2025-02-14 15:46:38', 'NORMAL', '今天是 2025 年 2 月 3 日，今日立春\n敬带娃们看哪吒去了。\n我还在天津，太阳明亮，偶尔有风，出去走走，遇到狗对我叫，不知怎的感觉不好，想狗是不是能看到人类看不到的，又有些小担心了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3147, 'TQTpdDpMiopmXV8VbR7nzN', 1, '2025-02-14 15:46:47', '2025-02-14 15:46:47', 'NORMAL', '今天是 2025 年 2 月 2 日，敬今天回合肥，亚运带他们回去的 13:30 左右到家的，\n今天自己洗的头，很顺利，已经能够完全独立照顾自己，她非要帮忙大声说不用，\n我妈又买了很多夏威夷果，见我吃过一会就觉得爱吃没了就买，听同学了我妈照顾我知道我爱吃啥要是真的就好了，她根本就不知道我爱吃啥，主要是我自己都不知道爱吃啥。\n10 点左右吃苹果我用个大盆盛的，前些天看她和饺子馅的，想肉里面会有寄生虫什么的，就说生肉的分开，她说重新弄，说不要了说好些遍我声音就大了\n她流鼻涕咳嗽说喝感冒药，不流就不喝了，流了就再喝点，有个屁用呀，什么观念呀\n非要看我眼睛红，不让看我说你这么看感觉我要死了，非要人说难听的。\n和我妈住一起真的是住的够够的。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3148, 'N683qH4Ym7pCGGrcBjjyPV', 1, '2025-02-14 15:46:56', '2025-02-14 15:46:56', 'NORMAL', '今天 2025 年 1 月 30 日，我爸打视频过来，当然是打给我妈的\n爸提到这里离北京近，带我妈去北京玩玩，他们觉得出了院就彻底好了没事了，天气冷，体力还跟不上，说是近开车到那边也要 2 个多小时，在加上倒车的时间，来回 5 个小时半天过去了还玩个锤子呀，我体力还跟不上，带她去我就是操心的命，要想着别丢了。\n我姑我妈跟我说过你爸可怜多了你爸聊聊说说话话。和他们没什么共同的话题，一家人都不爱说话，怎么要求我也这样呢。别的父母子女会有那多话题天天聊吗，我不在他旁边刚毕业那会可曾对我做支持了，买电脑不给钱，去外地说了句你挣的钱去那了。总是想着终于解脱了不用管孩子了，不理解关心孩子。肯定是我爸和他们说了要不不会和我说的。\n我妈让我和我舅我爸说新年好，什么的，多大的人了还要教，不是我不和我舅说，你几个外甥过年平时有给你打过电话吗，你还带他们孩子几年呢，对你又有什么感情呢，想的是美满好的，现实社会就这样，个人过个人的，我性格本就不爱说话要求我。\n想我妈带舅家孩子一年给一袋面说小孩吃不多，我觉得应该他帮你解决了多大的问题。\n最近眼睛疼，前些天刷剧看手机太多了，这 2 天不看好些了，\n鼻子还是有问题清晰地的疼，洗脸擤鼻涕有血丝，希望是因为空气干燥的原因，回合肥会有所改善吧。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3149, 'ZCySHP6wZDfUzAUF8rBF7L', 1, '2025-02-14 15:47:06', '2025-02-14 15:47:06', 'NORMAL', '今天是 2025 年 1 月 28 日，今天除夕，这两天眼睛红有血丝，像应该是看手机看多了，我妈也发现，她在哪顶着看，给我看的很烦。\n嚷她说她这样让我死都不敢死，我想着我死了你怎么活，真有那一天不让我轻松走，不让我轻松她来了句不死一直活着，可我不这么想。算了想开些管她去呢，她对我好关心就当看不见心不烦\n生病时偶尔来句儿子听着不舒服，总算明白那里不舒服，我听着是我是她儿我不能死还待给她养老呢。\n没心没肺活着真好就想着自己，我也要转变不能像以前一样，大过年的真不该想这些。\n这里发烟花真的好猛。我和我妈都睡不着了，睡了醒醒了睡。对面楼好多窗户都是亮的，凌晨的真的睡不着了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3150, '3vUCKVbFJ4vTKKsbhAG4TL', 1, '2025-02-14 15:47:17', '2025-02-14 15:47:17', 'NORMAL', '今天是 2025 年 1 月 27 日，听着樊登讲书睡着了，醒了还在播放着心情愉悦，终于明白为何不愿意和我爸姐说话了，咋咋呼呼的，轻松愉悦的交流。\n记得小时候和我姐一起把奶奶院子里的地，把出好多蚯蚓一群小鸭子抢着吃，可开心了，玩了一上午，下午还想去，姐不愿意去了，我也不好意思去没去，嘿小时候……，其实他们可想让我去了，只是被父母带歪了，别的小孩去奶奶家像回家一样。而我却…，父母没带好。\n公司的年终奖发了 6k 多，可以了不错了，前 2 日还有些担心不发呢，想应该不会不发的。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3151, 'XfMs5bACMbqjnXyUebpyRs', 1, '2025-02-14 15:47:27', '2025-02-14 15:47:27', 'NORMAL', '今天是 2025 年 1 月 26 日，敬要回巨野的，等他弟去接他们 14 点才出发的，一路通过娃的手表看他们到那了，20：20 左右到了，安心了。\n二舅给我妈打电话，把钱还了，说我生病的事要来天津看，着急的不行感觉假。愿大家都好吧，健康美满\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3152, 'CWCQMiki49qeactUPy5VzT', 1, '2025-02-14 15:47:35', '2025-02-14 15:47:35', 'NORMAL', '今天是 2025 年 1 月 24 日，想明白一个道理，妈妈经常不见就会偶尔想，待的时间长了就烦了，她的坏毛病都传给我，懦弱，死不改。\n对我爸的几件事记得特清楚，\n买房给了钱说以后要还他，虽然一直没还，现也没打算让我还，当时图个嘴痛快能有多高兴。\n刚毕业那会去德清，给我几百，来了句你这一年挣的钱呢，钱甩给他我走了，也没让他送。\n在上虞那是敬也在上班来了句要买 2 电动车呀\n还在苏屯那会说供我上学，以后结婚我就不管了。\n\n对敬分开 2 个多月了很想她，从处对象后从没分开这么久的，和她的矛盾最多的就是对果果的教育上吧。看不惯她嚷人说笨什么的\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3153, 'JitsWhTSE9fJrmNgQzBkZB', 1, '2025-02-14 15:47:44', '2025-02-14 15:47:44', 'NORMAL', '今天是 2025 年 1 月 23 日，\n敬决定回巨野的家了，其实猜到了他们会回去，他妹子来了，北京也不来了，不让我回去回巨野不是很好的选择吗，在家带着过年也没意思，之前说好的来天津过年的怎么变了呢，时间淡了，刚生病那会还怕娃们想我不适应，现在觉得好冷落，他们很少问我管我，这也挺好的珍惜眼前关心眼前，远的也管不了。\n还是不能很好的直起来，伤口摩擦衣服还是会觉得不舒服。本以为绷带解开就好了呢，原来想简单了，之前管子没拔后来拔了管子还是不舒服，原来不舒服不是管子的事。嘿愿早日成为正常人跑步锻炼。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3154, 'bX8XsxA6mqmB27oCkttTyQ', 1, '2025-02-14 15:47:53', '2025-02-14 15:47:53', 'NORMAL', '今天是 2025 年 1 月 22 日，去医院拿了骨扫描的报告，没有肿瘤，感谢，会好起来的，很快就能见娃们了，可以上班了，小康的生活可以继续了，耶耶耶。\n听敬说有人家的孩子 1700 多人考了前 10，对比果果焦虑了，嘿\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3155, 'jy5AksFnrXFv32sXYbu7WW', 1, '2025-02-14 15:48:02', '2025-02-14 15:48:02', 'NORMAL', '今天是 2025 年 1 月 20 日，今天要去医院做骨扫描，本以为今天只能预约做的话要等到明天，幸好有个取消预约的，最后一个能做，明天 16 点后可以拿报告，愿平安健康没事。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3156, 'eEfRfGeFntw2hr8Eevmxo7', 1, '2025-02-14 15:48:10', '2025-02-14 15:48:10', 'NORMAL', '今天是 2015 年 1 月 19 日，不开心，昨天在住院期间去楼下挂号开骨扫描医生提了句住院开检查医保应该报销不了，我想没道理呀，怎么会有这种呢，就试一试收银说报 54，我还以为医保报了呢，发票打出来原来是医保余额里的钱，给泰康报销后发现少了些仔细看发现有医保未报销金额 424 元，别人的话还是要信的呀，当时也想了把出院办完了再去交费又担心出院时间长要等医生开单子楼下跑，昨天周六还只上午上班。怕时间来不及就缴费了，亏了 400 多呀，心疼。\n医保结算说退那笔最后一笔交费时减了 5 元，问退哪笔时我说随便，结果把最后一笔退了，本来可以省 5 元的，就自己嘴懒不好意思，还是改不了，真是的真要好好改改，不能让自己难过\n满血复活，感谢强大的祖国。感谢无私的捐献者，感谢高尚的医护人员，感谢不离不弃的家人。愿所有人健康平安\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3157, 'b5eSDWaRYwhDUQNDRL69Er', 1, '2025-02-14 15:48:18', '2025-02-14 15:48:18', 'NORMAL', '今天是 2025 年 1 月 18 日，15 号住院拔T 管，本以为直接拔了就可以了呢，原来还要插个吸管把造影剂导出来，避免感染发烧，猜测应该是担心造影剂流放肝脏里去吧，第二天医生就来拔了，办出院，幸好比较顺利没出现感染发烧。医生说移植的工作成功完成了。\n目前症状额头脖子有疙瘩，手指头脚指头有掉皮，医生也说了要去皮肤科看看。\n肩膀疼，后背疼医生也不知道啥原因了慢慢调养恢复下看看吧。自从做过手术后没几天就疼了，当时疼应是因为引流管堵了的问题，ct 检查没积液了，还会疼，愿恢复几个月能好吧。\n后背还是不能完全直起来，拔过管子也不用担心了，伤口疼克服下愿恢复。\n3 个月的奋斗终于胜利了，感谢敬陪了我最艰难的前一个月，刚做手术前几天贝贝照顾几天外都是老婆大人照顾了，白天晚上都休息不好，有她陪着我什么都不用操心跑腿的活也不用我管，躺着就好了。我妈陪的 2 个月去医院我都要想着只要她能做饭吃好就好。\n晚上学了会苹果香，发现短视频真的嚯嚯人，浪费时间视频乱剪的了解的知识是不完整的没体系的，学一学自己的值得，\n听了苹果香了解了歌词大意，突然想起内蒙古包头的肝源了，抱有感恩，感谢他们。给了我第二次生命\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3158, 'FQMurtr8fB5AUzHLMoPW9f', 1, '2025-02-14 15:48:27', '2025-02-14 15:48:27', 'NORMAL', '今天是 2025 年 1 月 4 日，周六对于敬来说是比较忙碌的，看敬 19 点电动车才充电，想以后周末还是要我做饭的，好好学做饭吧，加油争取娃们满意\n\n想到孩子想的都是开心的，他们淘气也会觉得开心，\n想到父母想到都是他们的笨，原生家庭我的性格太像我妈，我爸对我的期望却没有任何的辅导引路，说话不过大脑，只会批评说，却不告诉我该怎么做，\n\n说话不讨人听，上次和我说我的病别怕，我理解是说我怕死，我最怕的是孩子们受苦老婆受累。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3159, 'D9esgmTCP8szajCJcdBzVo', 1, '2025-02-14 15:48:35', '2025-02-14 15:48:35', 'NORMAL', '今天是 2025 年 1 月 2 日，去天津医院发现 12 月 31 日到 1 月 3 日，医保还不能用，年度结算真是的，报销麻烦了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3160, 'Kvd3Cjqot8Ym8P8b9grvBL', 1, '2025-02-14 15:48:46', '2025-02-14 15:48:46', 'NORMAL', '今天是 2024 年 12 月 27 日，包头肝移植的人保保险终于受理到账了 8866 还挺多，比较满意。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3161, 'gDUzfrbuJho7xakSRQWvCB', 1, '2025-02-14 15:48:55', '2025-02-14 15:48:55', 'NORMAL', '今天是 2024 年 12 月 25 日，最近休息不好，睡觉t 管附近疼，手术伤口处觉得压的，腰疼，口腔溃疡，头上睑上长疙瘩皮疹，难受呀，希望t 管拔了后都好些吧。\n和我妈在这待着并不开心，哭丧的脸，越疼我关心我，越烦觉得奴性。\n对整个家族悲哀，一代一代的都这样，都是社会的最底层，看不到希望。\n明显觉得自己瘦了，之前胸部还有好多肉，捏起来还肉肉的，现很轻松的就摸到骨头。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3162, 'PdYMDpwq83YeVFfCMWGfnp', 1, '2025-02-14 15:49:03', '2025-02-14 15:49:03', 'NORMAL', '今天是 2024 年 12 月 19 日，\n基本上是没怎么联系其他人了，也突然想明白，假如那天走了 2 个月也基本忘了，他们也回归正常生活了，生活工作忙起来很快就忘了，离开娃 2 个多月了，他们也没联系过我恐怕是把我忘了吧，都不记得他们还有爹。敬也很少主动发消息联系，时间长了也会适应了吧。\n天天在房间呆着外面很少有人联系感觉人这边的郁闷了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3163, 'UBr8TYLs5dP3di9BhUAhNA', 1, '2025-02-14 15:49:13', '2025-02-14 15:49:13', 'NORMAL', '今天是 20241207 和我妈在天津待得快一个月了，越来越讨厌我的原生家庭，很多地方太像我妈了，讨厌自己讨厌我妈。\n犟得很，说不听\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3164, 'cXJpcC5yhMAVMvbbqHDWHU', 1, '2025-02-14 15:49:22', '2025-02-14 15:49:22', 'NORMAL', '今天是 2024 年 11 月 17 日，出院 6 天了，好快，和我妈住在天津还好，她总是唠叨怕我冻到让我多穿衣服，我能做的她非要帮忙怕她劳累，\n\n想他们娘三打个视频也没叫爸爸的，也没问我什么时候回去，他们并没那么开心\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3165, 'Sc84sD682p2bcAdD6Ruasy', 1, '2025-02-14 15:49:31', '2025-02-14 15:49:31', 'NORMAL', '今天是 2024 年 11 月 8 日，从去包头离家一个月了，娃们可想爸爸妈妈。\n胃舒服多了，吃饭有力气了，肺炎痰的问题也好了，在这边最严重麻烦的是胰腺的问题，\n有天晚上左肩膀疼的难受一晚睡不好，白天好久没人管，敬去找医生把管向外拔一些，一会出了很多液体出来，原来胰腺管弯了，在包头时肯定就出事了，有天胆管不出他给弄下出了，说是打绷带时折到了，估计胰腺管硬没回来，没出他也没当回事，一直积液了。晚会陈医生就把我推到导管室换管了当时也没问那么多就信他了，也不等检测结果出来在决定，换了个管换的过程疼坏了。几天后测胰淀粉酶发现很高，就又推到导管室了换管子，这次插不进去了，换了好几个管子都不行，最后插了 2 个细的硬的管子换的时候不怎么疼，换好后推回来不能动疼死了，敬还不管了给娃讲作业不开心不关心眼前的事儿，后打止疼药还是疼没用，第二天才好些没那么疼，后几天不引流了说又要换管子，这次他们应是做了充分的准备方案很顺利一次就进去了，还可能这几天恢复了不少，换了管还是没什么液体出来，\n医生说观察几天可以准备出院了，给我妈买了 9 号的票，让亚运过来带 2 天娃，我妈和我姐说她说没时间真的没必要再和她联系了遇到这样的亲姐。她怎么还有脸给我打电话。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3166, 'cEv8ZtwGxLcYskvTQ6rXfF', 1, '2025-02-14 15:49:40', '2025-02-14 15:49:40', 'NORMAL', '今天 2024 年 10 月 23 日，在包头做完手术回天津了。\n11 号下午去做的手术，先去扎针了，胳膊脖子扎了几针，接着就吸气睡着了，等我醒了，在 icu 了，插着呼吸机说不了话，胳膊腿都被绑着了，在哪做的一件事就是调整呼吸睡觉，睡了醒醒了睡，呼吸机不知是不是不好用，口水吸不上了，吐也吐不出来，咽下去好疼，不知是不是到肺了而不是到胃，咽也好几次，疼死了，敲床也没人管，一天后检查什么把呼吸机拔了，拔也吸了口，手也放开了， 中间陈医生看过让我握他的手看我有没力气，还挺有力气的，敬在窗户外面叫过我，还请了护工，捏屁股擦腿，舒服多了，\n在 ICU 待了一天去病房了，看到小姑，贝，还有我姐，看见她不开心，她来也不开心心不甘情不愿的，第二天她就走了还把我姑给带走了，贝待了一周要回去了，说他媳妇有意见了，他帮我们跑腿买东西菜什么的，帮了不少忙。贝走过 3 天后我们回天津了。\n住院期间有痰咳不出来，肩膀疼，吊营养液，蛋白，能下来走走了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3167, 'RkFWXYM6PnceQUSTFxqqEa', 1, '2025-02-14 15:49:49', '2025-02-14 15:49:49', 'NORMAL', '今天是 2024 年 10 月 11 又是个吉利的日子，重阳节，愿今天手术成功，从此再次成为正常人\n16 点 40 多的时候被推到手术室，先给身上扎了好多针，左侧脖子扎了 4 个，从没放在这那里扎的，估计手术中的用药都是从这里进，的手一个扎 3 好像改个动漫，之后又被推到另外一个手术室天津的人在那个，洗个面罩也不知是啥，一会就睡着了，\n12 号 第二天具体几点我也不知道了，我发现我已经在 ICU 了，陈医生还问我认不认知我，握他的让我给最大的力，说手术很成功，一会有一个男的问的同样的问题，有他的手给力，我应该呆了 3 个半天左右，在哪不舒服是口水，我的嘴身子手都是被绑些的，嘴有呼吸机提供呼吸，想让时间过得快些就调整自己的呼吸啥都不想一会就了醒了睡睡了醒，把呼吸机拿出来还搞得很不舒服，应该是口水领到呼吸机里面了，之前还有进去的疼死了，全身的伤口都在疼。中间有人了换药，看我的伤口还拍照和他同事说要做成 ppt 给人看，加分项\n13 号早上 9 点多吧，推到普通病房了，看到敬了，我姑，贝贝，居然还有我姐，\n14 号，对 医生说的是血氧值低不高，同事吸了 2 个氧气， 对我比较难受是咳嗽有痰，一咳整个伤口都疼不是一般的疼，不知道是不是在 icu 的口水，下午咳出了一块痰全是有些有忍着咳的，口水的问题，老是吐口水，不让吃饭的，咽下去还难受，嘴干的很了，胃也出现问题，躺下去后明显能感受的酸冰感觉，说是胃反流了，做下去看吧， 这样没有明显的酸冰感了\n15 应该会吧小便的接口抽电，胃的不确定别又问题了，胃的位置应该动了，之前被挤压了\n\n发现手术很快，术后的事也不小。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3168, 'SUTBpGscjuHjrU67bcr7zx', 1, '2025-02-14 15:49:58', '2025-02-14 15:49:58', 'NORMAL', '今天是 2024 年 10 月 10 日，一个美丽吉祥的日子，8 点多通知我们去内蒙古了，要下午到后想明白是要在下班前到，做好相关的检查，明天能直接做手术了，\n听陈医生的建议先到呼和浩特内蒙古的省会，做飞机去的，在从呼和浩特做高铁到包头，一路很顺利，时间也都接的上，飞机抬头时有些晕中间转弯什么的有些不适其他还好，比过山车轻多了。\n又抽个很多血，b 超把身体检查了一遍，b 超医生刚看肝还说吃了好多东西，后和他说是肝，肝已经占了很多位置了，多处淋巴结肿大，应是吃药的原因。 签了很多字，就等明天的手术了，\n我反尔很放松无所谓的态度了，最后的机会最后的努力了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3169, '8uxwAup3pjrMFoN6orLgUj', 1, '2025-02-14 15:50:07', '2025-02-14 15:50:07', 'NORMAL', '今天是 2024 年10 月 9 日，紧张的日子，天津打电话说内蒙古包头有肝源，让我们有说准备不定能给我用上，包头那边电话联系把我的信息录入等待肝移植的系统，\n应该是天津那边会派人过去拿出来看吧，合适了就通知过去了。等着天真的快来了好紧张呀。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3170, 'KNLPdaAeaqp8xWV5Qk2yCr', 1, '2025-02-14 15:50:15', '2025-02-14 15:50:15', 'NORMAL', '今天是 2024 年 10 月 3 日，敬带果果检查视力，发现 380 多度了，和她的差不多了。听到这生气，之前和加宝一起查的才 200 左右，\n起她自己撵都撵不出去，写会作业不知道出去转转，敬说要去医院检查，我不近视认为小孩也不会，就没放当回事，好了，要带眼镜了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3171, 'iQhyRWSkA6sM5NAcs6LbvV', 1, '2025-02-14 15:50:24', '2025-02-14 15:50:24', 'NORMAL', '今天是 2024 年 10 月 4 日，敬要上班了，上班就带个娃去那边学习了，天天在家里晃来晃去，一天天的就过去了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3172, 'M6tidfFvsWVPY3vFQxocjy', 1, '2025-02-14 15:50:34', '2025-02-14 15:50:34', 'NORMAL', '今天是 2024 年 9 月 30 日，坐车回合肥了，因为明天是十一了，车票很难买，其实 2 天前就检查完了，这几天没啥事就吊水了，吃药效果一样的，在高德 12306 都在抢，加个抢票包，买到了一张加 20 元还挺贵的，娘的，之前还不小心买了从北京到合肥明天的卧铺，退了手续费 20% 好贵呀 50 多，来回折腾多用了 140 元，\n昨天和医生发消息说出差今天回来说，移植的手术是可以做的，就说些风险方案肝源的问题，方案吗就是我说希望的切一刀，肝源的问题吗\n1.亲属的切 2/3 给我，供方一周能出院，3 个月能长好，不用肝源的费用，可三代亲属又有说可提供呢，爸妈年龄大，我姐别想了，我姑家更不能连累他们了。\n2.完整的肝源当然最理想的了，\n3.平移的部分肝源，有切口的，部分给儿童部分成人。\n4.外地的肝源，手术在外地做，医生去，要付医生出诊的费用，\n等吧回来贿赂下院长，能提前加速些，早点做早受益，家人也不用一直担心着。\n好久没做过慢车了，可能因十一的原因吧，人还好多的，过道里站不少人，走动起来还人挤人的好久没做过这样的了。\n由俭入奢，由奢入俭，深有体会呀。能屈能伸是为大丈夫。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3173, 'ehPfsdxSeyxzCfZ5ikpA2f', 1, '2025-02-14 15:50:43', '2025-02-14 15:50:43', 'NORMAL', '今天是 2024 年 9 月 26 日，23 日去上海了，先做的检查，核磁 CT 抽血做了， 25 日看的门诊，说现在药物只能维持，不能改善变好，要做肝移植，本以为还要在上海呢，要去天津，先去做评测什么的，要个 3-5 天时间，\n这个方案应是最后的治愈方案了，努力一把吧，肝移植的人也不少。愿度过这一劫，还想带娃看雪看海呢。\n昨天肥东 19 点多 又震了 3.9 级，我和敬刚回合肥到家，果果还说奶奶的手机响了地震预警，我和敬手机没响也没感觉，千万不要有大震呀，保佑合肥。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3174, 'ERvquoar4M9DrLhTZM6cfA', 1, '2025-02-14 15:50:52', '2025-02-14 15:50:52', 'NORMAL', '今天是 2024 年 9 月 18 日，日本发动侵华战争的日子。\n最近腹部好像没那么疼了，还是浑身没力气，对自己没信心了，认为自己是多余的，活着对家人反而是累赘，还要我妈在这照顾我。\n下午喝盐水了，怕又是低纳\n晚上 20 点多，肥东地震了官方通报 4.7 级，第一次感受到地震，刚慌我还以为是隔壁关门声音很大了，手机响了，看是地震预警，敬也出来了，说跑了，我当时还穿着小内裤不管了，拿衣服就下楼了，提醒他们后面的带家里的钥匙，啥东西都不要拿了，果果还少穿了一只鞋，出了小门才穿衣服的，从小门出去还挺多人的，我们出去了不断的有人出，幸好我们是在 2 楼下楼快。在小门楼下万一楼倒了也不安全，去公园了，距楼足够远了，待个小时回家了，洗漱睡了，愿平安度过，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3175, 'bFvBL3TmtFiD46xEVoNjdv', 1, '2025-02-14 15:51:00', '2025-02-14 15:51:00', 'NORMAL', '今天是 2024 年 9 月 15 日，今天该吃提默䂳胺了。还担心会不会再吐了，中午吃饭还很担心呢，还好没吐一切很好，\n下午睡的很好，天不热，睡了还会会些汗，睡好后觉得人很精神，状态好，总是开心的事，说明还是要多休息的，不能像之前那样看手机，刷剧，不困看看书催眠吧，\n买去上海的车票和酒店了，原一切顺利，再活 30 年\n因为明后天有雨，晚饭后敬带娃们去看马戏团了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3176, 'FcU6nthizphxiR45hqsRcH', 1, '2025-02-14 15:51:08', '2025-02-14 15:51:08', 'NORMAL', '今天是 2024 年 9 月 13 日，本以为明天要吃替默唑胺呢，想上次少吃一天，这次补回来吧，早上还没吃欧贝片，11 点吃的，下午 13 点多觉得不舒服了，想吐，吐了 4 次，最后都吐苦水了，再吃个欧贝片终于不吐了，原来欧贝片这么厉害，那个药真的会导致吐，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3177, 'QWX6MvMbfqZuSeid5HoEJx', 1, '2025-02-14 15:51:17', '2025-02-14 15:51:17', 'NORMAL', '今天是什么 2024 年 9 月 10 日教师节，时间过得很快，\n这已经是是卡培他滨的第四天了，腹部还是很疼，发现问题，坐着好些，躺着站着就好疼，还硬。不知道前面几天症状好些的，但没这么久吧，记得之前的状态都挺好的，在床上疼时会不自觉的，那被子盖住疼的地方，这是什么原因心里呢，假如我不在了 2 个娃要吗敬全带，要吗带一个，等果果上高中住校了就少操心了。\n6 号的时候去了省肿瘤医院医院原来才知道那是省立医院的分院，问了那医生能都根治治好，说治不好，一下没希望了，难道就这么一直下去吗，耗着我妈在这里，\n敬上班也忙，昨天出差了，明天才能回来，早上能送果果上学，没时间在家做饭什么的，刚入行有压力正常的，加油\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3178, 'k3qu2vHViVrA5Fj69mCFEs', 1, '2025-02-14 15:51:26', '2025-02-14 15:51:26', 'NORMAL', '今天是 2024 年 9 月 5 日日子过得好快。从上海回来快 2 个月了，之前还想着下次去上海要很久呢，眼看也快了，\n我的状态是不怎么好，肝部位很硬，这 3 天 4 点左右就醒了，很难再睡了，脚麻也不想出门了，\n前些天听说王林因肺水肿住院了，昨天说是肺结核，听说还传染呢，唉能活好难呀，健康真重要，那天要失去了，就想珍惜了，\n这两天和加加一起睡。敬和果果在那边睡，睡得挺好，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3179, 'fCbwFPcjpfBGGA6j7kP4NN', 1, '2025-02-14 15:51:48', '2025-02-14 15:51:48', 'NORMAL', '今天是 2024 年 9 月 2 日，宝贝们都正常上学了。\n加宝最近很爱下围棋，在家的这几天好好的学学吧，争取能把他的棋技提升上来吧。\n我的状态还好，早上 6 点多就醒了，中午安静就在椅子上坐着了，也没开空调。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3180, 'eZoLrn8sy2EnnFvhurZz8z', 1, '2025-02-14 15:51:57', '2025-02-14 15:51:57', 'NORMAL', '今天是 2024 年 8 月 22 日，昨天张总说找我有事商量，下午过来的，在我家 1402 聊的，原来是他干的不爽，想出来干了，要单独出来做产品，受不了迪马，好大的魄力呀，一切从头来。还是之前的那些人，之前没有赵总了而已，那以后新公司每天是不是就没那么多会了。惬意，\n\n赶紧好起来吧，还有好多事，可挣的路子呢\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3181, 'LxCWXqR6Z424rnCwUcVdbb', 1, '2025-02-14 15:52:05', '2025-02-14 15:52:05', 'NORMAL', '今天是 2024 年 8 月 26 日，时间过得很快，我的状态还好，吃喝睡都挺好，唯一还有些疼，力气提不上来，\n\n敬今天去蘑菇屋上班去了，怎么样回来再说吧\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3182, 'iWcwEeACbpsNJgc5trgahb', 1, '2025-02-14 15:52:13', '2025-02-14 15:52:13', 'NORMAL', '今天是 2024 年 8 月 19 日，今天要搬家，他们的网还移走了。比较可以下，还是转移的把家里的网移到这边来，移两次 100 吧，搬个家可真麻烦，晚上 8 点左右来弄的，还以为回不来了呢。影响果果明天的网课。\n装柜子的事，还没定好日期呢，嘿真实的，\n上海复诊的事，早上看有个缴费的通知，妈的怎么搞得。真麻烦，要先付费，在选检查日期，这搞得商业险的报销都没法整了，折腾死了，\n晚上两娃一起睡的，还挺好的，反正我是坐会困了就睡着了，夜里醒了下，也不想起又睡着了，早上起来看他们睡的挺好，昨天怕空调冷，从家里把挡空调板拿过来了，为了娃跑趟也值得\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3183, 'LCUXTk5QdxWD4xnf2SByFt', 1, '2025-02-14 15:52:21', '2025-02-14 15:52:21', 'NORMAL', '今天是 2024 年 8 月 18 日，今天是中元节，俗称鬼节，晚上有人烧纸，\n昨天敬就说了，不要让娃们出去了，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3184, 'f3EdkHCGzNchZzz48Z7kdp', 1, '2025-02-14 15:52:29', '2025-02-14 15:52:29', 'NORMAL', '今天是 2024 年 8 月 17 日，这两天睡觉的时间明显多了，早上 8 点多才起来，下午能睡到快 16 点，疼痛感明显严重了，很担心呀，不安的想法 又浮现脑海，\n还有机会工作挣钱吗，我想高质量的活 30 年，不想成为家里的累赘负担，\n晚上敬回来伤心，不知怎么的了，怕我走了，她一个人孤单，还怪我不吃西兰花，不想着让自己的肝功能好些，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3185, 'bYybc5uHddTrPPZN6PG4gi', 1, '2025-02-14 15:52:38', '2025-02-14 15:52:38', 'NORMAL', '今天是 2024 年 8 月 16 日，计划去安医抽血检查的，舌苔白的事医生不知道，日间病房的事肿瘤科没有，住院也不能随便住感觉是医生太谨慎了没症状住院怕被罚，回来想想别的住院方式吧，要不商业险报不掉呀。纳的问题说最近不要补了，偏高了，先几天不喝盐水吧。过几天少喝些。真怕了低纳头晕。\n\n最近敬和我妈有些不愉快，前天加加躲在他搭的房子里看手机，被敬嚷了，跟着也说我妈了，怪不得那天等了半个小时还没下来。\n下午 12 点多睡的，迷迷糊糊不想起，睡到快 16 点，头有些晕不直是不是睡多了。还是怎的，\n\n晚上出来要给自行车打气，发生一件危险的事，之前鼓捣的吸尘器本想在家里能打气呢，结果家里都是交流电，吸尘器打气要用直流电，还要买别的适配器算了不折腾了，今天娃要打气，就拿到楼下了，结果用会烧了。因为我把它的接头转成 USB 口的了，线太细了，烧了，好担心呀，担心车有事，担心别人的车，车的间距太近了。拿完快递在这等着娃，顺便在这看着，怕万一。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3186, 'FuA8UueeC7swBMhrrfFrGA', 1, '2025-02-14 15:52:47', '2025-02-14 15:52:47', 'NORMAL', '今天是 2024 年 8 月 12 日，工资发了，上海报销的钱总算到账了，对我来说，最近总算是不缺钱了。一直等了好久。\n昨天和敬吵架，去万象汇周六跑一趟周日跑一趟，周六带果果去的，加加不愿意了，周日又带加加去的，这人是不是就想出去玩呀。\n12号加加该检测乙肝抗体了，下了班睡会，去庚玖检测了，说贵让我找社区医院的电话，去那给你找，不打气来了，这么简单的事都搞不好，还要跑几趟，不知道怎么想的不想在家待着吗，有那么多的事要干，把时间省下来不好吗，二建，做顿饭，休息，住宿费报销的问题问下怎么不好。带他们出去就要骑电动车，说让他们晒晒，这也不怕晒黑了，带头盔憋的慌了。\n在庚玖还发生一件事，说果果把玻璃门关上，加加一下撞上了，手欠关门干啥，怎么想的，一点安全问题不考虑，不考虑别人。\n在学校就看的出来并不是一个聪明的女人，如果当时没和她结婚我的人生会是怎样的。\n\n下午加加上围棋课最后一节课了，很开心每次上围棋课都兴奋，最后一节课比赛了，加宝第一名，拿回来好些小礼品，很开心，敬要继续给他报围棋课，240 元，12 节，相对来说便宜的很了。\n\n敬不忙的时候，和敬提了，车险的事，明天就过期了，今天要搞好，要不脱险了麻烦，上路面临处罚，保费可能开会长，想保费涨了是不是因为车主是女性的原因，不是因为过户第一年的问题，女司机\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3187, 'Z4Tdv9e96kznWpLPSj9aQv', 1, '2025-02-14 15:52:56', '2025-02-14 15:52:56', 'NORMAL', '今天是 2024 年 8 月 10 日，农历的七夕节，周六，敬今天上晚班，早上敬和果果起早去万象汇了，早上起来说要给我买个葫芦，寓意挺好的，不到 9 点就出发了，到那说 9 点半才开门，等了好一会，  11 点左右回来了，买了个 10g 的，7k 多，今天的金价查了很高，加工费近 1k，今天也是我们 14 年结婚领证 14 年的纪念日，2010 年我俩什么都没有一个月 2k 多块钱就结婚了，还租的房子，14 年过去了，一直是在走上坡路，有了今天，虽然没大富大贵，也算衣食无忧，房车儿女齐全了，\n晚上床让周姐拉走了，突然按预计的计算最近要买张床 1000k+，柜子的尾款 1000+，金葫芦 7000+，车保险 3700 左右，就敬一个人上班，平时这样怎么能够呢，不能再这样大手的花钱了。\n明年 2w 邮政，泰康寿险 2.6w，泰康理财 2w，这差不多就敬一年的工资了，明年这个时候怎么能攒下这么多钱，不能每年都贴老本吧，\n家和万事兴，我觉得家庭并不和谐，敬还是老是说我妈做饭不好吃，我也知道不好吃，你给我做呀，我也想吃你做的，也知道你累没要求你，你别说别人做的不好呀。我也知道我妈在这不开心想让她回去，敬倒好想让她一直待着当保姆用了，不付工资还要出一家人的伙食钱。\n我也不爽，心情也没那么放开。婆媳关系我夹在中间，娃要管操心辅导，心情怎么可能会好呢，一时是解决不了的。怎么能好的快呢，\n理解你的家难处，我爸妈那也是一个家呀，是不是家庭稳定了，我就多余了。\n一切都会好过来的，没我有我都会好的，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3188, 'LUpxZ4znWuZz5hxgKN5uB3', 1, '2025-02-14 15:53:04', '2025-02-14 15:53:04', 'NORMAL', '今天是 2024 年 8 月 9 日，日子过得很快，从上海回来 20 天了，治疗三个周期过去一个了，好快呀，\n我妈在这边待的也有些着急了，假如我能活 10 年不能让她在这待 10 年吧，应该不用，3 年后果果上高中了，加加大些，敬的工作也稳定了，就好些了。妈每天想着做饭，想着吃啥也挺烦心的，她的腿还没彻底的好呢，天天不知道怎么那么忙，我状态好能照顾着娃，你就别管些了，多休息好了，\n假如敬真的遇到个合适的伴，怎么办，会不管我了没，娃们怎么办\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3189, 'mX4YPYGBNx3MQNrPWv4LZj', 1, '2025-02-14 15:53:14', '2025-02-14 15:53:14', 'NORMAL', '今天是 2024 年 8 月 4 日，果果连续 2 天都要往外跑了，这人马上就跑野了，天那么热，老是跑出去，不知道玩啥，王她妈说她有早恋倾向很害怕会影响果果。\n我妈的腿从来时到现在还没有恢复，说让她多休息，天天不知道怎么那么多的家务需要她去做，天天忙的不行，出去买菜非要自己走着，看着就气，\n空调最近内机在滴水，感觉没之前凉快了，感觉要维修了，要加氟或者深度清洗下，又要花钱了，明年再说吧，过几天就要搬到别人家里了。这空调开不了几天了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3190, 'TAXXcxAhjgYvTUvjtHA2cw', 1, '2025-02-14 15:53:22', '2025-02-14 15:53:22', 'NORMAL', '今天是 2024 年 8 月 5 日，好快呀，还有 4 天就又要吃药了，希望到时症状能好些吧。\n昨天夜里醒了，很久才睡着，上腹部明显又疼起来了。\n昨天刷手机人民日报说北大的老师癌症去世了，还坚持给学生上课 3 年就挂了。假如我们活个 3-5 年甚至 10 年的我怎么活呢，天天躺着宅在家里，让我妈来做饭吗，伺候我吗。连累我妈。生活状态也不好，嚷娃对他们是好事吗，活的有意义吗。\n前些天看到一个 34 岁渐冻症的，看到渐冻症想起蔡的，竟然希望自己是癌症而不是渐冻症，想想自己现在是癌症是不是还挺幸运的，他们都在坚强的活着，他们活着的意思又是什么呢。他们肯定无法医治，至少我还有希望，还有可能，\n我希望的是能彻底恢复根治，能上班，2 年的时间如果过了恐怕我是没根治的可能了，那一天来了我也很害怕，我想的是怕死的痛苦。\n\n下午吃芒果我吃了一口，给加宝从另外一面吃，他来了句，爸你的病传不传染，我当然害怕传染给你们了，突然觉得小家伙也长大了。他其实一直知道老爸生病了的。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3191, 'cJuppnGnVzWpKGE39a25w2', 1, '2025-02-14 15:53:30', '2025-02-14 15:53:30', 'NORMAL', '今天是 2024 年 8 月 2 日，打开支付宝提示说是我的生日。又是一年呀，最近天气很热，很少出门，因化疗药先停了 2 周，感觉状态明显没吃药的时候好，我曾还天真的认为我要好了么，看样我是想多了，\n医生估计是怕一直吃药物，产生耐药性吧，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3192, 'hi8AeGcELVevzn2gUhfviy', 1, '2025-02-14 15:53:39', '2025-02-14 15:53:39', 'NORMAL', '今天是 2024 年 8 月 3 日，周六，敬中午的时候去猫头鹰那了，聊了下先干招生，ai 自习室招生，说一个自习室只要 10 个孩子就够本了，他说的本应该只是房租吧，最起码还要 2 个人看着吧。当然不确定兼职的可不可以。\n\n说在生鲜传奇上班上到 20 号就不干了，快开学了，要去学校跑招生了，招到了还能干什么呢，不清楚，如果这种模式好，是不是小班老师的就可以取消掉了，因为这种在制度上也是合法的。教育局说看视频的不管。\n很好的模式，愿能搞起来，生活好起来，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3193, '6SRJEpU5kLWHhNzZRCo47C', 1, '2025-02-14 15:53:49', '2025-02-14 15:53:49', 'NORMAL', '今天是 2024 年 7 月 27 日，我已经感受不到感冒的症状了，可今天有痰咳嗽，咳时就有痰，难受到底怎的了，真的 3 阳了吗，腹部的疼痛好多了，现在已感觉不到怎么疼了，晚上睡觉也好多了，夜里虽然会醒，可很快就能再次睡着。每天 9 点睡，5 点多醒，午睡睡会，早饭后困就睡不困就不睡。\n早上 5 点多起来，没有雨凉快出去走了走，2k 多步，不累，还算不错，\n柳祚龙太不靠谱了，让他办个租房备案到现在还没弄好，还没弄明白，真搞不懂，是搞不了，还是不想搞，不行联系下中介看看吧\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3194, '9Xqq7ZJxRpnQMfKv3qhoTU', 1, '2025-02-14 15:53:57', '2025-02-14 15:53:57', 'NORMAL', '今天是 2024 年 7 月 24 日，夜里起了 2 次都很容易的睡了，\n不好的事情发生了，矩亚，果果，敬，我妈都感冒了，我很担心，结果早上起来嗓子难受坏了，中招了，昨天中午还一直带口罩的，下午没怎么带就这样了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3195, 'YT37us5StPXaYTXtVWquwH', 1, '2025-02-14 15:54:05', '2025-02-14 15:54:05', 'NORMAL', '今天是 2024 年 7 月 23 日，昨天夜间醒来，居然很容易的就睡着了，之前很难睡着的，\n下午晚饭不知敬怎么了老是说孩子不吃饭什么的，逼着加加吃，果果不舒服肚子疼也不问题就说怎么不吃饭，嘀嘀咕咕说了好长时间，烦死了嚷了她句她们去老乡鸡怎么吃的带劲了，我看这菜饭我也吃不下去，不想吃，这几天热屁的了 37-38 度的，干米饭菜炒的干干的一点胃口也没有，怪我们了一家人 3 口不愿意吃自己不反醒。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3196, '9aht2PhVy7KuHcVL26t3Fq', 1, '2025-02-14 15:54:14', '2025-02-14 15:54:14', 'NORMAL', '今天是 2024 年 7 月 19 日，今天计划是居住证明的事，我妈合肥的和我上海的，\n合肥从皖事通上就能申请，按要求填下提交，居然下午就有电话过来了，幸好我没以为是骚扰电话挂了，说申请了和办证人反了，需要我妈的户口那页还有我的迁出证明那页，让我姐有时间拍了，再次上传周日又接到电话了解下情况说通过了，等 3 个工作日，就能办好了。一天就办好了，只是我没找到下载的地方，找到了，给我妈申请长期的异地就医，1 天也就通过了，效率还是可以的。\n上海的要租房信息，需要网签信息，周六想着柳休息和他说下吧，能办最好，就做个假租他家的房子，应该没问题。\n豆包真是强大这些都是他告诉我的\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3197, 'UgGoQHgLtuswQZDZSZxb2L', 1, '2025-02-14 15:54:23', '2025-02-14 15:54:23', 'NORMAL', '今天是 2024 年 7 月 20 日，今天是我要去化验的日子，去的是滨湖医院，原来那这是安徽医科大学附属第三医院在公众号叫合肥第一人民医院滨湖分院，之前的号都是挂好的来着，挂的肿瘤科，原来是个老太太，检查开的急诊的单子说结果出的能快些，结果确实如此，之前还在门诊等了好久等到我的号抽血的医生告诉我走错了的，去急诊那边没人排队结果出来的是快，医生看了居然还说不错，纳的指标也上来了，最近一天 3 杯浓盐水，控制这个量应该就可以了，最近状态很好，真不想再缺盐头晕了，总觉得自己马上就要死了。准备发给上海肿瘤医院的陈洁发现好大夫是要钱的 最便宜的 80 一次娘的上海的医生都这么没良心吗，不知道病人看病花很多钱在看病上了，还要在好大夫上搞创收，真没良心，你压力大没钱，谁活的容易了，\n这次去泰康还能报销些，下次就不可以了，发现公司交的保险报销的比例并不高，说是社保报销目录不能全报的，在报 90%，娃 50%，其他医保全报，和个人支付的部分不报，和我想的不一样呀，我以为是全部的 90%，或者医保不能全报的加个人支付的 90% 以为很快 5w 就能用完呢，结果这样。想 pet CT 7k 多，核磁 1.5k 公司的部分不能报了，这两项加一起就是上海的大头了，报不了，好烦呀，在合肥安医才报了 1.4k，娘的让他们吐点出来可难了，\n敬说我爸给钱就要要钱的这吧，我也想通了，这边只有敬上班，要养活我们 5 个人这个压力好大呀，后面的生活保障怎么办，只能不停的从老本里补贴了或者我爸了，他会想到每个月给钱了？\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3198, 'G2ymXCmP4wAB23warp3mxr', 1, '2025-02-14 15:54:32', '2025-02-14 15:54:32', 'NORMAL', '今天是 2024 年 7 月 22 日，敬昨天感冒了头晕还挺着去上班，\n果果请假了，周二下午16 点 补课，先这样定到时有变再说，\n我妈做饭\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3199, 'mvztyixXKUZk2wdNJ3kCXt', 1, '2025-02-14 15:54:49', '2025-02-14 15:54:49', 'NORMAL', '今天是 2024 年 7 月 21 日，周日，昨天说好的我两个姑今天会过来，今天她们不上班，过来看看我，其实并不想让她们过来的，没时间接她们，管她们，\n今天敬要上行政班，下午 14 点要去考试，考园林考过了能拿 1000 元，上次去过一次了挂科了，嘿这次补课不需要交费，要折腾一趟这是比较重要的事，在上海的时候就已经知道的，当时还担心在上海住院会耽误考试呢，结果没住上，只是在家吃药了，总算赶上了，还好，考的不错，题都搜到了，比较顺利。\n姑她们 4 点多到的，她们自己打车过来的，敬没时间接说最近太累了，明天还要上班，和她们说敬开车不行得了，她们来时我醒了，迷迷糊糊又睡会了，一人拿了 1k 还是 1.2k 呀，不知道了，丰收大伯也出了 ，我爸也带过来了 2k，我爸是不想收我姑她们的钱说她们还房贷压力大，她们现在也不挣钱，我小姑还了 5k，本想转给我妈 1w 的，银行限制转了 5k 说明天在转，我妈商量说明天再转就不要了，说用不到，要是小姑用不到，先还别人吧，15:30 分给她们叫车去合肥南站走了，确认她们到南站了就不管她们了，\n她们说那边的温度很高，鸡都热死了，兔子也有跑了，菜长的也不好，我爸在那也辛苦什么的，我爸 8 月份就能领取养老金了。我大姑能领到 2k 多，我爸也应该可以。正常我爸妈生活是够了，我这身体有变，加上我家一起就是杯水车薪了。\n果果发烧了，加加咳嗽，小姨头晕，敬带他们去医院了，去省儿童医院，给果果开了退烧药发热了吃，头孢，加加还是开了安尔宁，脖子后面的疙瘩也拍了 b 超看了医生说没啥事，从那回来了，带小姨去庚玖医院看了，说吃点 39 就好了，就回来了。敬从考试回来头晕，坏了，被传染了吗，本想下午上班还去的，去不了了，打个卡算上班了，和店长说了，这点还是比较好的，吃点药，睡了，明天还准备上班的，怎么回事呀，昨天矩亚带 3 个娃走着去来优品回来都中招了，敬应是被传染的，她们干啥了吃啥了呀，热的\n针对我妈做饭不好吃的问题，我从网上找了用茄子和豆腐的视频，明天中午让她们研究下做吧，不给她找好也不知道怎么做，希望明天能有个好的开始吧。\n我的状态还好，今天我成正常人了，给娃倒水，活药吃，幸好我状态比较好，加药了。说吃了会吐，给加了止吐的药，吃那个药也没有吐的感觉，希望娃们都好起来吧。\n算了下敬卡里的钱建设银行 工商银行 招商银行一起有小 70w 吧，邮政每年充 2w 的应该存 3 年了吧，存 5 年就不存了说留着给果果上大学用的6w， 我这有 12w，公积金还有 14w 今天是提不出来了。这是所有的了，这是这几年挣的钱了。\n我总觉得我治病还没开始呢，花钱的时候还没开始，好些地方是报不了的，比如上海肿瘤医院的陈洁要在好医生上回复看了下，这是要钱的一次 80 这医生肯定是知道的了，医生是想另外赚点吗？只能这么猜测了，\n下次去不住院就不好报了，方案 1 ，先去上海的门诊尝试和医生沟通住院吧，方案 2 回合肥住院，就担心这样会超过 7 天，合肥住院也不是随便住的，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3200, 'RSfsmPAkyhMKYMnxo8BW8M', 1, '2025-02-14 15:55:00', '2025-02-14 15:55:00', 'NORMAL', '今天是 2024 年 7 月 18 日把客厅的电给搞了下，之前搞过一次一会累的满头大汗的，今天把主卧的插口弄了下，之前一个开关控制两个插排现给改回来了，一个口都插电视了功控机了，这样看电视直接按一个按钮就可以了，天猫也不要了可看的内容太少了，要看就用电脑看吧，该装的都装好了，\n客厅的电视矩亚要下次亚运回家时让他带回去吧。电路的事算是暂时结束了就这样了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3201, 'n9eFYryWNT3b6sKFjJDzgD', 1, '2025-02-14 15:55:08', '2025-02-14 15:55:08', 'NORMAL', '今天是 2024 年 7 月 15 日，下午时和敬一起去了车管所，包河区的在哈尔滨路与天津路交口的地方，\n\n两件事要把车过户给敬原来只要变更联系人信息就可以了，还有我的驾驶证快到期了，8 月 1 号就到期了，跟担心我这身体能否过，还好居然过了，视力，听力，色弱检查就这些了，花了 60 块大洋，行驶证本 10 元，驾驶证本 10 元共 80 元，\n换驾驶证需要带照片可能会省着吧\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3202, 'aqH996hAcGKUA2zpmiYLji', 1, '2025-02-14 15:55:17', '2025-02-14 15:55:17', 'NORMAL', '今天是 2024 年 7 月 17 日去杭州银行把卡取消了，徽商银行把卡的网上银行转账的功能激活了，时间长没用，网上转账功能关闭了，天 1w 的额度，1 年 20w 感觉不够用呀，要更多需要去淮河路的徽商银行才可以，就这么用吧\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3203, 'BZbrCsf5YWuAhVDkBpt7r2', 1, '2025-02-14 15:55:25', '2025-02-14 15:55:25', 'NORMAL', '今天是 2024 年 7 月 12 日开始吃化疗的药物了，\n\n敬去安医做体检了，预约了 22 号的 肠镜\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3204, 'jKA27bRm23AheL7MUQhXk4', 1, '2025-02-14 15:55:33', '2025-02-14 15:55:33', 'NORMAL', '今天是 2024 年 7 月 11 日，早上还在上海，昨晚住在格林豪泰了，名宿到期了不给开专票，就没在住了，想 200 元能吃的很好了，找能开专票的地方吧，就又去了哪里了，结果还涨价了，问能不能开多些可以玩收 5% 的点，想可以就多开了 7 天，多付了 100 元也担心报不掉的，\n敬要去肿瘤医院浦东区盖章，医生开的诊断书盖章，昨天开的药也没拿因为社保一点也没报，想拿去合肥买药，我不想去了，想留些精力做车去火车站，就让敬一个人去了，她到那边还特意看了规格什么的手机上都能看的到，回来叫车加了个途径点来接我，一起去的火车站，敬座车还有些头晕，在路上买了车票，算了时间应可以到车站，还好赶上了，在车站也没等多久。\n和飞涛说让他把我的电脑带到火车站我去拿因为有组合任务的工作要我去做，其他人做不了，没办法呀，因为出口没有向上的电梯就下去了，又上去，飞涛他们等了一会，聊会，就因这个 200 元 1 分的罚单，嘿，\n他们走了我和敬要叫车了，我回家，敬去安医给我拿药我走不动了我不去了，在火车站的 2 楼叫车网约车还不上来，都在 p4 等着。我那知道 p4 在那呀，我们叫的都去了哪里，没法去吧，我把订单取消了，敬的不让取消，是觉得还挺远的，能抢到不容易吧，我快到时重新叫了，敬找到车上车了，我新叫的也找到了回家了，妈已经在大门口等着了，嘿回家洗澡，休息了\n敬去住院部折腾开不了，去挂了门诊，本就开一个疗程的后说别折腾了，一次开 3 个疗程的，拿回来了一大包，说还有没的，明天去庚玖医院开，还有防止低钠的不给开说完 3 天的检测单，有些天没抽血检查了。后就没拿，算了回来多喝些浓盐水吧，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3205, '8UbT2mjoiTcNWSqiDXZEjM', 1, '2025-02-14 15:55:42', '2025-02-14 15:55:42', 'NORMAL', '今天是 2024 年 7 月 10 日，今天注定要是个忙碌的日子，10 点有个核磁共振，还要在往浦东看门诊，6 点半就出门了，怕路上的时间长，差不多一个小时吧到地方了，这里比徐汇区那边安静好多了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3206, 'gCBUE4Ky7FFNbBf8ZMMERQ', 1, '2025-02-14 15:55:50', '2025-02-14 15:55:50', 'NORMAL', '今天是 2024 年 7 月 9 日，今天一天没什么要检查的，可我不舒服，腹部疼了一天，睡觉虽然是醒醒睡睡的，可能睡着，敬帮按摩下腿脚舒服多了，\n中午的时候敬出去买咯些吃的，\n下午出去拿报告了，把穿刺的样本也拿回来了，之前一直以为是在徐汇区不知怎想的，昨天去徐汇拿没有，检查下原来是在浦东，嘿一直没去哪，\n敬还在旁边的宾馆问了下，都开不了专用发票，下次住那边吧便宜些还近些，看那边吃的还多些，\n最近大便很费劲，要用好大的力气才可以，很干，以后用手术了，恐怕要用开塞露了，要不用大力气疼坏了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3207, 'SEXDz8FLPxUkKG7SmhJqFD', 1, '2025-02-14 15:55:59', '2025-02-14 15:55:59', 'NORMAL', '今天是 2024 年 7 月 8 日，今天有个检查在上海复旦大学肿瘤医院徐汇区，下午 14 点的，我们 12 点多就出发了，40 多分钟到的，做 pet \CT 一个人约 15 分钟吧，等了很久， 很慢，\n今天觉得很虚，走路也很慢，最近不知道是不是盐喝多了，晚上的时候老乱想，睡不着觉，一夜我就 4—6 个小时，质量还不高。\n中午的时候敬帮我按摩下腿睡了一小觉，怕下午去那没精神，\n18 点多 安全的回到住的地方了，坐车也不头晕，还在车上睡了一小会。\n\n我的身份证和社保卡号终于拿回来了，王学峰用跑腿送的，我们在徐汇区近些，还好都比较顺利，挂号什么的方便多了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3208, '5k8AJbC2jssGZ8iGCy4urj', 1, '2024-07-06 15:56:08', '2025-02-14 15:56:08', 'NORMAL', '今天是2024年7月6日，今天感觉很舒服，但是容易累到下午出去走一小圈就觉得头晕了，坐着不动不会头晕， 脚麻。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3209, '7Ancr4giLSLgJCq8iWnQC4', 1, '2024-07-05 15:56:17', '2025-02-14 15:56:17', 'NORMAL', '今天是 2024 年 7 月 5 日在上海，这是我们在上海的第 4 天了，\n今天我不能吃早饭要做个胸部的检查，敬做粥，煎的饼，有些糊了没办法，锅底黑了一圈一点涂层都没了，只能放很多的油才可以，下次没事，我精力看好了有力气，我来用刷子好好的刷下，明天来煎个鸡蛋试试，还是先来饼吧，敬吃些我们 9 点整准时过去了，一路好晒，路上没怎么出汗，到那了坐下歇息后，不停的冒汗，浑身抽没力气，还没空板凳，看有个位置有东西放着，先做了，不让做，说来了就走，脸皮也不管了，太虚了，\n今天要做个胸部的 ct 这个在合肥安医时就已经做过了，又做一遍，看样子是 ct 都重新来了遍呀，\n还好昨天打的静置针不用拔出来，否则今天去那边要要挨一针了，做完后有些不舒服，今天起来时本就不怎么舒服，一路走过来的，热屁的了，等了半天每小时不停的喝水，怕检查影响，真是的，检查的过程了那边一样，中间让不停的憋气呼吸，10 多分钟后结束了，头更晕了，已经吊了 3 天的水了，好像作用并不大。头还是有些晕晕的。\n打车去的那边，还好在车上什么不舒服了，来过几次了，这边的医院也都很熟悉了，我就在边上坐着了，让敬在那来回跑吧，我实在是不行了。很快就吊上了，在吊水的过程中睡了一会，靠着睡的很不舒服，休息了一会，就走了，想回去睡会，睡不着了。\n看电视了，转移下注意力，用力的和盐水，把盐水放到苦了，我不想因为这死了，我还想在活个 10 年 30 年的，像老婆说的，我即使不干活不工作，已经能照顾好自己也是挺好看的，看这孩子门成长。\n晚些了，特别的精神，不想睡觉，写下了这些，发现用手机写文字是个练习手和脑子情绪的很好方法，不行你试试，想想怎么能打得快，手，眼睛，脑都要用上，\n1. 眼用来看候选框里的字有没有你想要的，\n2. 手要盲打了，不能用看键盘，两只手要同时我同时用才会快起来，\n3. 脑子要想这拼音，特别是我这种拼音不好的。\n这是这两天打字的心吧\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3210, 'YzGwexw7ZBdXXzDLatnjJv', 1, '2024-07-04 15:56:26', '2025-02-14 15:56:26', 'NORMAL', '今天是 2024 年 7 月 4 日，一天应是没什么事的，早上到敬起来我才起来，在床上躺着，感觉很清醒，想今天要干的事想安医给出个转院的单子这样能在医保上添加个外地就医的外地申请想这样医保会不会报销的多些，\n打电话找不到人还说没弄过要等彭主任来了才可以，要下周一来了问他，我说话不清楚了吗？嗓子是有些不舒服，感觉整个人都在变差，感觉也不能在拖了，病情发展怕今年过不去了，\n中午 泰康 22w 的到账了，总算等到了一笔这下可解了燃眉之急了，不用想这来回转钱了，\n\n在家里躺了一个白天，晚些出去走走发现头晕不行喝了 2 支盐没效果，赶紧去吊吧，不能因省 22 元的挂号费，晕倒在路上了，回家敬煮面吃点，去了我却在整怎么能领到单车的劵怎么便宜结昨天一个用了 2.5 呀元觉的多了，敬说我尽想这省小钱。\n\n在门口看法青橙单车了，花 1 元买个啥的走了可以发好友发给敬了真是的尽想这小钱这毛病要改了，伤脑子，花时间，像我现在时间更宝贵切花在这上面，应想着留下些什么好好的陪着家人，\n骑车走了，感觉从回到我们刚去上虞那会了，也是骑车到出走出去找工作，那可是 16 年前的事了。也是差不多同样的季节，何曾的相像呀。还能回到那个时候吗一切都从新开始。那个时候一切都有可能现在我要先活下去，我要先活下去，\n\n骑了 20 多分钟到了，一路还算顺利，路上也不黑，车也很礼貌，没礼貌撞到我算他倒霉了，怕我真的也没希望了，身体本就弱在被撞伤怕是手术也不能做了，\n还进错门了应该走东门的，这边好难闻，车还多，开药拿水顺利排队人不多，这里吊水的地方也好多人，昨天外地看肿瘤的还在这住院，太难了，门口还有老太太在吊水留院观察，输液大厅还有很多年轻人快 23 点了还在吊水明天怎么上班呀，我们也好不到哪去还要吊水，结束了怎么回去。\n假如有天我能活到 60 以上生重病还穷的话，就买个车库下的储备室，放个柜子，吃些安眠药直接过去得了，别难过。孩子们没钱买墓地，放在楼下好了，愿意的话等等老婆，希望是等到一百年\n打车回来的到家又好晚了，一路上小哥开车真不容易。一夜就因为尿的问题被瘪醒了好大一泡尿，当然还是没大象的多了接着睡了。小鸟在外面吵一会又睡着了 7 点多才醒\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3211, 'hZTuVuoCmfSbeRbDmUFQwZ', 1, '2024-07-03 15:56:35', '2025-02-14 15:56:35', 'NORMAL', '2024 年 7 月 3 号，在上海，2 号的时候到的上海，做火车到上海站那是去预约的医院最近的车站了，之后做的出租车去的格林豪泰快捷酒店，30 多公里用了 130 块，好贵呀，合肥从我家到高新区的安医走高速20 多公里才用 40 元，30 公里 60 算吧，2 倍多呢，\n到住的地方特别憋屈，没有窗户，房子设计大圈套小圈，房间安排在了小圈里没有窗户，还有味道，算了好累了就着吧，还好能报销的发票什么的都能能出示，早饭准备先退房行李先放在着呢，免得去医院来回推麻烦，有人说早餐劵用不到了来不及了要走问有没要的，就要了早饭还行包子馒头粥炸的南瓜丸子。\n打车去的肿瘤医院浦东区，在宾馆的太憋屈了，真不想再去了，也可能那天有些头晕了吧缺盐了吧，5.4 公里开了 30 多分钟以后会很快便宜结过还搞了 20 多块，好贵呀，到那边挂号缴费从机器上交的吧用的是医院的卡号挂那的微信里找的，结算的时候还出问题外地的还报不了嘿，急坏了 8000 多呀都自费回合肥能报多少呢，嘿，\n找到泰康安排的陪诊了，也很辛苦和我们等很久，天天陪病人来回跑折腾死了，中间有医生要了检查的报告，等到 13 点左右才看到医生医生没说 2 句话，说卡龙不要打了没啥用，索凡替尼还可以吃，其他的就没说啥了，小 600 呀，就这些，还没给治疗方案，开了 3 个检查让自己预约做，三个检查三个分院不同的天，折腾死人了，\n\n在旁边找民宿吧真不想在住在那了娘的，从途家找了个民宿怕没了就先在平台付钱了，后才发现 30 分钟后退款还收手续费，联系房东后先去房哪里看了，从途家看到地址找到的，来了后，有个阿姨在打扫，聊了起来，说房子多，让找老板看看就在那，一会就来了，阿姨带我们看了这里的房矮，，在楼下阿姨得老板来了，在途家看到的那个老板也来了，说在装修吵推荐好些的，就是离医院远些，在小区里面应该事公寓改的一套公寓改两件也真是佩服他们，要 260 元，居然磨到了 200 元一天，老婆可真厉害佩服，交了 1400 一个礼拜得钱。\n算是再这边安顿下来了，中午检查的医生打电话过来说刚检查的钠含量太低了要去周浦镇医院吊盐水那边改没有真是的真怎么会没有呢，还要我们跑到别的医院区没得说了，想她可能不是很清楚，\n下午去亲自医院问下，药房输液大厅否不行，说输液大厅里还有化疗吊水的，天天呐在上海看个爱你这么麻烦，是因为外地人吗，外地来上海就医太太妈的难了。\n没法去周浦医院吧做出与车去的，以为很近还开了半天什么地呀这都是，太难了，就不怕外地人不是死在医院是死在医院外面。挂了水好些去拿行李了不想做出租车了，门口有个很多单车就骑了，骑到格林豪泰拿了行李还要手拖着箱子走发现根本不可能单车还一个我走这一会太慢了，单车都还了敬要在这买些啥准备明天的饭，旁边有个超市发现物价并没多贵，买了 2 袋子， 准备走了叫了出租车，路上就下雨了，好大，到了梧桐国际感觉不像，看我走时发给敬的定位是在路那边的小区，就去了，刚下车拿行李还好大现不下了，金那个小区还和门卫吵起来，到 2 号楼感觉也不像看房东发得写的是国际，打电话给房东，敬都快发脾气了，于是出来了出来了又和门卫吵娘的烦死了，说我们没去楼上没敲别人家的门妈的烦死了。老婆出来就发火了，真好不开心就说出来发泄哟并不生气，幸好现在没下雨，出来个敬说你先去找找小门吧，看在哪，找到了，上次我们就是从小门出来的旁边有个什么食堂真是，走的时候不熟悉没啥把周围摸清还没拍照，在车库停车还像怕个照呢，还有是没经验自己笨遇到事没想提前准备，就是司机停得那里她只是把车听到 3 号了导航没那么准已经很厉害了不能怀我们可也问我们是不是这个了，当时在下雨还尽把车往里停，有些人还是挺好的。\n到家我洗澡敬做饭这么晚了还做饭太辛苦难了，穷人太难了，吃过领洗还担心里面有摄像头，我关灯用手机看有个没红点没找到，想应不会偷拍的都是病人还这样太没啥良心了。大家也都知道在这来的都是因肿瘤的问题花钱都是无底洞，睡下 23 点了，早上被小鸟吵醒了，快 5 点了，从生病了睡得最好的一夜没醒，\n最近照镜子被自己吓到了，自己的脸明显变长了，脸瘦了，斑点多了，害怕会变得更坏隔了，我还再活 10 年呢那怕 2 年 3 年\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3212, 'SfLPTLEVfZxhjMxUKVYXB4', 1, '2024-06-24 15:56:44', '2025-02-14 15:56:44', 'NORMAL', '2024 年 6 月 24 日，出院了，一天很没精神，想应是缺盐了，睡觉前猛喝了好多水，那个保温杯吧不是热就是凉的，很没口感嘿，晚上睡觉肚子还疼，疼了一晚上好难受，希望下个月去检查能好很多。这个药要有用呀，我想再活 30 年呢\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3213, 'FLMGEUv99Y6SCcW4uhgM44', 1, '2024-06-19 15:56:52', '2025-02-14 15:56:52', 'NORMAL', '今天是 2024 年 6 月 19 日，昨天肝部病理的结果出来了，如医生期待的那样最好的结果，神经内分泌肿瘤，较温和的那种，也相对好治，只是相对比简单的单个肿瘤还是复杂的。谢上帝保佑🙏\n昨天说了要转到肿瘤科，两边的主任都已经说好了，过去简单的说下认知下明天过去安排床位，今天 7 点半就过去了，医生还没来，等会来了说是加 2 床在 2 号房，刚以为加 2 是在边上加个呢，结果还好在中间，也不挤，可能之前那房间是 2 病床改成 3 个的吧。\n愿能好起来，还能上班，家庭还能过上中等收入家庭。最近失业率很高 担忧呀，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3214, 'jZaqqBcx8rvdhsoutNBCEN', 1, '2024-06-18 15:56:59', '2025-02-14 15:56:59', 'NORMAL', '今天是 2024 年 6 月 18 日，多么吉利的日子，昨天有些焦躁，一直在等结果治疗方案，没出来。姐姐和妈妈过来了，姐做 16 号 下午的车过来的，到家 22 点了，10 点多过来的，13 点回去了，她还要上明天的班。和姐的话一直不多，真正关心的还是家人，虽然帮不上什么忙，感谢大家的关心。\n能看到第二天的太阳真好，能看到天亮好好。\n隔壁床要出院了，说花了好几万，他也只是做了个介入治疗，我这。有焦虑了，\n一直没让交钱以为还有钱呢，原来是一直欠着呢。\n\n癌细胞癌细胞变成好细胞，陪你你一辈子\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3215, '9HuTEMPmRTcv2e2KkhBDZo', 1, '2024-06-16 15:57:08', '2025-02-14 15:57:08', 'NORMAL', '今天是 6 月 16 日，父亲节多好的日子，正常应该爸爸叫你们起床送你们去辅导课的，爸爸妈妈还在医院，6 月 11 到到的医院已经 6天了，刚还是很焦虑，虽然在报告中看到了癌的字样，任然报些幻想想还是没确诊还有希望。随着一项项的检查结果也放下了，接受了。就这吧。爱怎么样怎么样。能活多久活多久，你们也会慢慢的适应，到时爸爸不在你们也没那么难过了。希望这一天不会那么早来，爸爸还是希望能有转机能根治的。\n妈妈也逐渐变的平静刚来时还想转到上海更好的医院，刚来时爸爸的身体不舒服头晕无力竟然是因为爸爸缺纳缺盐的问题，补了几天好了，有力气了，好开心。找了上海认知的人帮联系医生，拿报告给他们看 2 个都说不能做手术不能切。这边主任和他的学生说了不能切，差不多了不纠结了，这边说有方案就在这边吧，虽然离家有些远毕竟还是在合肥。熟悉的地方虽然对这一片不熟悉。\n爸爸的状态很好，吃饭带劲，棒棒的。\n爸爸前几天还查我们家算是那个经济水平的，算中等的还挺开心的，因病致贫的家庭太多了，希望我们不是，妈妈也不要那么用力保住房子能保住存款全部报了，感谢前些年买的商业险。如果房子没了你们去哪，姥姥奶奶家都不适合，妈妈也好累带两个孩子。一个送给小姨吧，她家只有一个男孩还好接受，一个丢给我妈我姐养着，我家人都想要儿子。会喜欢的。\n\n昨天大宝不开心的好玩的事情和妈妈说很开心，我们很想做你的老师，带着你们走向成长独立\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3216, 'GWE93bk6Q3kWsAtEKaunGq', 1, '2024-06-13 15:57:16', '2025-02-14 15:57:16', 'NORMAL', '今天是6月13日，昨天petct结果出来了，胰腺癌转肝癌，本以为最坏的结果是肝切了或换肝。现在看是不行了，那么巧能同时换。都切了估计也活不久，现在的症状还是上腹疼，影响了吃饭睡觉，真希望这一切都是梦，时间可以倒流。前些天还在算什么时候退休一个月能拿多少钱呢。\n之前经常说不想活了，真的到了不能活的时候真的舍不得，还想看着孩子们长大上大学，能独立生活自己能养活自己呢，\n孩子们爸爸一直希望你们能互帮互助，只希望你们能幸福快乐，\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3217, 'JWq8X6suGitH6UnvT2qPPq', 1, '2024-05-10 15:57:24', '2025-02-14 15:57:24', 'NORMAL', '       今天是2024年6六月十号端午节。爸爸前一阵子上腹部疼，这里有时候开会疼醒，医生让检查做胃镜检查，还开了肝胆胰的检查，因为爸爸没有做过胃镜怕不舒服，做胃镜的人比较多预约了第三天的才做上，做胃镜打了麻药之后都睡着了没有感觉，做好了之后医生把爸爸推出来了，是妈妈给爸爸叫醒的。结果还好只是有点炎症，然后又做了肝胆胰的检查，检查说有很多的结节大的有7厘米在爸爸的肝上面，拿给医生看了建议做进一步检查。爸爸也是比较担心，片子上面满满的白点，爸爸当时就想爸爸的肝可能保不住了。\n       回家爸爸妈妈决定去合肥最好的医院安徽医科大学附属医院绩溪路。医生给开了很多检查，还开了住院单。那天你跟弟弟两个人在家还去陈亦凡家吃饭，你还记得吗？那天奶奶也来我们家了。奶奶还是很疼爸爸的，奶奶六十多岁了还在想着爸爸，你的妈妈也同样很爱你😘，小姨过几天也会过来她是妈妈的妹妹都是姥姥的宝宝，就像你跟弟弟一样都是妈妈的宝宝。爸爸希望之后你和弟弟也能互帮互助疼爱妈妈。爸爸呢现在就是肚子疼吃不下去饭，恶心没有力气，经常睡觉没有精力和你跟弟弟玩，虽然医生没有确认结果，还是爸爸也想到了最好的结果就是把肝切除，坏一点的就是爸爸不能陪你们很久了，爸爸一样你们能保重自己的身体，爱惜自己。你和弟弟身上的每一块肉都是爸爸妈妈给的，没有爸爸妈妈的允许你们不能破坏。\n     爸爸不期望你们大富大贵，但期望你们能够衣食无忧。爸爸妈妈不能给你留下很多，只能靠你们自己了，学习虽然很枯燥，看不到成果在生活中用不到，学习是最简单的途径，但学习也不是唯一的途径，但很少有人不学习就可以成功的？爸爸希望你有自己的梦想并能够实现。工作是生活的一部分，生活不是不是为了工作，遇到不开心的工作，就毫不犹豫的换个，不委屈自己，所以希望你们能好好学习能有很多的选择，\n\n  爸爸再跟你说下关于交朋友的事情，在需要帮助你的时候肯帮你的才是真的朋友，不需要因为不必要的人生气伤心。以后选择对象的时候也是能从多个角度选择，内心强大，\n\n遇事不慌，处理问题有条理，总会有解决的办法\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3218, 'EfvxUtq4kJ2JqPB3N7LvbP', 1, '2025-02-14 18:29:48', '2025-02-14 21:17:09', 'NORMAL', '今天是 2025 年 2 月 14 日，阿今天是情人节哎。对不起宝宝了。娃们都要上学了，好快呀，一天天的。\n早上 5 点左右醒的，上个厕所不困了，\n敬送过娃后一起跑步去了，天不好阴阴的，我基本是走的，腿有些酸。\n娃们不在家在家弄电脑了，把日记的都导到 memos 里了，日记和文章放一起了，私有的放日记，鼓捣了 14 点吧，总算好了，主要是网慢。\n接下来的时间弄 Android x86 了，还没鼓捣好，下次有时间在弄吧，估计要下周 2 了。\n加加上书法课，果果音乐课回来，加加先回来等姐姐一起吃饭，真好想着姐姐妈妈。\n脑袋还是有疙瘩好担心呀，是因为体内一直有毒素拍不出来吗。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3219, 'G6qbCqqL9Vo5DiiefpELuu', 1, '2024-03-13 19:44:51', '2025-02-14 19:44:51', 'NORMAL', '今天是 2024 年 3 月 13 日 加加上学回来带回来好多鸡米花，说是吃不完让我吃好开心，没和他妈说和我说，前几天有学生拍了张吃的饭，颜色不对，整大发了，这几天饭较好\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3220, 'Ww5LFpfVqSCMTYGSrNXHR3', 1, '2024-07-06 19:46:20', '2025-02-14 19:46:20', 'NORMAL', '今天是 2024 年 7 月 6 日\n 宝贝晚安，\n爸爸妈妈最近几日没有回家，是因为爸爸最近要多了几个检查，检查不在同一天，爸妈大部分时间更没事情干，爸爸最近在手机打了很多字，打字的速度练习了出来，妈妈也在学习我们在要求我们早睡早起，爸爸 9 点就关灯躺下了，睡不着想给你大点什么。\n英语数学学到了一个知识点就能考好得高分，语文不同，要通过不停得积累才可以的，不停的阅读写作才可以，爸爸想到的和你分享，回家和你分享爸爸的打字方法，速度快起来了\n\n1 分钟可以干很多事的\n\n学好和玩好一点也不冲突，[微笑]\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3221, 'dm7QH79h8g2UgvY6YMvaZ5', 1, '2024-07-06 19:49:39', '2025-03-03 07:38:09', 'NORMAL', '安徽电信free 卡\n\n同时，你也可以通过编辑短信“NZYK”到10001进行新版流量包订购\n\n尊敬的用户您好，欢迎查询新ifree卡专属流量通话包，流量一年不清零，回复以下指令立即开通：\nNZYK10: 国内200M流量99分钟国内通话包_201704_9.9元\nNZYK50: 国内500M流量199分钟国内通话包_201704_19.9元\nNZYK60: 国内1G流量349分钟国内通话包_201704_34.9元\nNZYK70: 国内3G流量699分钟国内通话包_201704_69.9元\n新ifree卡流量通话包订购成功后立即生效，生效后不能变更与退订，可订购多个流量通话包、也可重复订购。\n热门推荐：回复“NZYK10”到10001立即开通9.9元全国200M流量99分钟通话，流量通话一年不清零，到期不自动续订。\n\n\n电信iFree卡套餐外流量计费情况如下：\n 无叠加流量包时：全国流量按0.11元/MB收费。\n\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3222, 'NaQweeoo6EWDUxQi5fjz65', 1, '2025-02-14 19:51:18', '2025-02-17 15:58:19', 'NORMAL', '为什么中国的老板都喜欢让员工无偿加理\n而不是高效完成工作呢？\n一个高赞回答是这样说的，那是因为中国大多数老板根本算不上资本家，本质上还是于属封建奴隶主思维。\n资本家只关心你给他赚了多少钱，如果你能力高，赚钱多，迟到早退压根不是问题，就算你整天不来，他对你也是笑呵呵的\n而封建奴隶主认为，买了你的一段时间，那你所有的时间都要听他的，你得随叫随到，看到你闲了，他不会认为你是效率高，反是而觉得给你安排的活少了，让你整点下班，简直比他赔钱了还难受。他们觉得多加了班才是赚到了\n\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3226, '2wPSmHFqWNguMFMLEZ6RR2', 1, '2025-02-15 06:15:25', '2025-02-16 06:15:25', 'NORMAL', '今天是 2025 年 2 月 15 日，\n中午果果上英语课，敬带过去带回来的，加加在楼下玩会打会球。\n下午敬待娃们去公园航站楼玩了，15 点左右回来，又上班去了，娃们在家写会作业，觉得有些冷，敬没啊出去了，在那磨洋工。\n吃过晚饭带娃们出去了会，敬说要 20 点才能回来的，出去玩时蔡训儒，齐鹏飞来了，还以为他们出来了呢，楼下有放烟花的，娃们要看会在楼下座了会，一会上去了，也没聊啥，送他们出小区，回来敬在吃着了，说我们刚下楼敬上来了错过了错过就错过吧，也许就如此。\n洗脚时我爸打视频说我妈回去的事，他让敬接电话被敬怼了，没事跟她聊个啥，敬说我现在活着不需要照顾就是最好的状态了，我爸想着我能接娃做饭什么的，我觉得我可以的，只是敬不让我来弄，其实她是最怕我走的，我走她会最难过，要带 2 娃，娃大怎么办，半路夫妻有几个恩爱的。我爸来了句那给他治干啥呢，被我拿来当反面教材教育果果说说话不过脑子，从家庭角度来看如果真是治好了没啥用没价值不如放弃，不能成为累赘，自然进化本就如此，很理解家庭的脆弱，家里每个人都不能少，少一个都转不下去。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3227, '35ow44VWjTJzb7LP4NGoD8', 1, '2025-02-16 22:26:48', '2025-02-16 22:27:50', 'NORMAL', '今天是 2025 年 2 月 16 日， 下午睡到 15:30 左右给果果讲讲不会的作业，去中央公园玩了，带他们还是很累的，走走停停被什么吸引就走不动了。下次就不要安排目的，按那个方向逛就好了，到家 18:40 了。敬打电话说要吃药，才赶快走的要不回来的就更晚了。\n晚上睡觉烦躁，明天要去医院了有些小担心，第一次去难免会有些紧张，不知这边的会不会耐心的听给建议什么的，果果左右非要到晚上才写晚，敬和我妈吵架拌嘴的事我是不放在心上还他们呢，知道敬是不会受气的。我比较担心的是敬会不会嫌弃我，从回带合肥我一直是一个人睡得。虽说有果果的原因，家里睡不下，很在意敬的看法怕她对我放弃了。\n额头上又长了好些疙瘩，想应该是最近没好好洗脸的原因，本就是油性的天冷不洗更容易出\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3228, 'mY9hkBTHHYGNRrAwDkYW6c', 1, '2025-02-17 15:57:10', '2025-02-18 04:44:37', 'NORMAL', '今天是 2025 年 2 月 17 日，一早去省立医院检查拿药了，挂个号的医生不是肝移植的，我看介绍说神经内分泌瘤的，下次去了挂了专门的移植的吧，目前就西罗浓度测不了，依维莫司还没有 2.5mg 的，真麻烦，让敬去安医问，我自己在省立做检查拿药，敬去哪问压根就没依维莫司的药却可以测西罗浓度，搞不明白，检查先去安医检查吧，省立就拿依维莫司吧。省立的小程序做的挺好的，都从小程序上交费先自费之后可以在网上医保结算。安医的可以交费没看到医保结算的，线上开个发票还是完全自费的，头疼呀，报不了怎么办，西罗的浓度明天去测吧不能拖一个月不测吧，时间天长了，依维莫司就一粒分 4 半吃吧，就这样吧，吃一个月看看，下次 3 月份的 检查早些。\n敬先从安医走的，在包河苑等我，说加宝吐了，嘿昨天上篮球课还想着加宝最近好久没流鼻血了，又出这事，真的不能想，那也是一刹那不知怎么就从脑子里出现了。回到家 12:40 了，加宝睡了，我们吃饭，吃过饭拾掇下整理下做被窝了。\n敬 15 点多去包河区服务中心办护照了，她公司说 4 月份去香港，先办护照，真厉害第一个出远门的人，那边的手机卡怕还要从新办说大陆的卡到那边收漫游还挺贵，说的的流量套餐只是大陆。\n晚上敬看了我的报告说有个指标高是因为最近没休息好的原因，不想让我去上班了，我还想多挣点呢，看了我两的时间正上班了，怕是聚少离多，兼职干公司会同意吗，张博士就不要了，我又有何德何能。\n\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3229, 'Lcp9ffdwNuqne6BNY8Y57H', 1, '2025-02-18 04:39:43', '2025-02-18 22:27:05', 'NORMAL', '今天是 2025 年 2 月 18 日，日子过得很快，最近不知怎么的。很难一夜到天亮，4 点 5 点多就醒了，还做梦\n去安医找到抽血的地方报道排队抽血等了好一会才等到，抽的比较顺利，医保结算要去窗口才可以办理比较顺利昨天我在小程序开过发票的也一起给报了，发票也从新开了比较给力，问敬确认钱退了我就回去了。\n去到包河苑去徽商银行准备注销徽商银行卡的等了好久还办不了必须去开户银行才可以，不管了算了就这样吧，反正也不扣钱。\n敬中午带加加去庚玖医院了，昨天吐了今天早上吃饭又吐了，去拿了些药血也没抽，下午睡了会醒了说头晕，抱抱又睡了，从昨天就没怎么好好吃饭了，睡到 15 点多敬上班了醒了，状态很好，陪他说说聊聊很爱讲，开心，晚饭吃了一点状态一直很好真棒，敬说在回来的路上看到喜鹊说我好事是说加宝好了吧。\n从天津回来寄快递的事总算差不多了，快递公司说赔偿 2 盒的药钱了 1900 多，挺好的了毕竟这些泰康赔过了的，找快递被子，棉衣找到了，鞋子就算了一直沟通麻烦的很。\n这两天的泰康也提交申请了，心情好多了，下午还花了好些时间怎么导出图片呢，发票和明细在一起的想导出时也一起，费了不少劲最后用 wps 免费版水印的给她了原来她就要分开的，手机直接截屏就好了还花哪些功夫，浪费了哪些时间。。\n联通王卡的事平台反馈了，不知道电话打没打插号的手机好久没开机了，算了 5g 也就 5 元，也不能这么算日租宝的流量一天用不完明天再用又要扣一元了，到时没收到反馈换卡了再问吧。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3230, '5twiAeFDnVmbMUKAC6cAub', 1, '2025-02-19 06:40:18', '2025-02-19 18:06:38', 'NORMAL', '今天是 2025 年 2 月 19 日，\n夜间做梦梦到在医院昨天的单子陈池义看了说需要吊点水，还在黑板上写需吊的哪些药给合肥的医生看，要人说我在天津住院是在天津蹲监狱，梦里的我怎么这么有才居然能想到蹲监狱，现实中我可从没这么想过呀。\n今天搞了好久的电脑，准备安装 Android x86 谷歌官方的可以运行只是网打不开，鼓捣 bliss os 安装上找不到指导无法启动系统，明天在鼓捣下再试下最后一次机会再也不玩了，搞不搞拉倒，反正以后会不会用到还不知道呢，平时在家也没看过电视鼓捣他干啥，纯净无广告版的吗嘿无聊。还给自己搞得好累困，去他大爷的拉倒吧。把家里的网线都给搞好了，至少是主卧的两个都是好的了通的，\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3235, 'k667XEgQ4GMtNuQuu5Ea2H', 1, '2025-02-23 17:43:32', '2025-02-23 17:43:32', 'NORMAL', '今天是 2025 年 2 月 23 日，昨天和加加一起睡的主卧，睡得很好一夜没醒，今天早上果果起来有数学课要上，想到了昨天中午果果上英语课她去数学课的地方接果果了，回来和我们说这有啥好说的自己笨还好意思说。她们走后又聊到我妈回不回去的问题。\n敬不想让他回去是想她能干些活，我想让她回去是看着烦奴性，啥事做不好还不想说她，说了也不会改，还让她不开心说个啥，我妈不想走想做些家务疼我吧，我是想情愿身体上累不想心累\n今天接加加电动车没电，天气也不好，就开车去接加加了，开车还挺紧张的，嘿很宽的地方还没停直，真是的。到学校了说下次课要在西安路上了，这边的场地在被收了，他们也不容易之前好大的场地被政府收了，这又要走了，去西安路学校了。没背景真的是不好混呀。\n晚上敬带娃们去图书馆，借的书明天就到期了。明天图书馆不上班，图书馆 21 点关门，只能如此了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3237, 'QjiNCwmH58j3hUH9R5VKSq', 2, '2010-04-12 18:00:00', '2010-04-12 18:00:00', 'NORMAL', '今天是2010-04-12 。 会计从业证\n 昨天去考会计从业证了。早上7点起来天气挺冷的，我和寝室的两个人同坐一辆小电平车出发这叫一个挤。一直坐到了大润发，因为不知道地方就打了个的去的。刚到学校就看到好多人，晕倒。。。进了大门才知道来早了还有一个小时才让进考场呢，我们就在外面等啊，这时天又下起了雨这叫一个惨啊，出门不顺。\n   终于可以可以进考场了，本来想去厕所的找不到地方就算了，哎你说就这样能考好吗，没坐几分钟老师进来了啰哩八嗦念了一堆考试纪律，看来只要是在中国考试都是这个模式。考试开始了，试卷发下来了看了一眼就开始答了，二十分钟搞定比想象中的难，很认真人检查了一遍，还是发现不了问题，交卷走人。估计最多60。。。。。。\n考完了没什么事就去吃饭了，学校的食堂还真是黑，就吃我们中午的工作餐还要十五块，给的到是挺多的，饭吃好了没地方去就在食堂小睡了一会，人太多了也睡不太好，接着就是看题了，下午考会计基础还平如早上呢，一个小时才把题做完。 是谁说的大多数是课后题的，也就40%，这下完了，估计最多60。看来什么东西都不能投机取巧的。\n   考试结束，下午回到寝室整个人都不想动了，好累啊，考个试比干了一天的活还难受。本来想去洗个澡放松下下的结果秋裤又找不到了，害我又发了个小脾气。哎老是这样爱发脾气心情怎么会好呢？\n可能是因为没考好，晚上老公打电话给我，我对他发脾气了说了好多伤他自尊的话，我好后悔，自己一点能力也没有还要求别人做这做那的。自己没什么优点还对别人要求那么高。我一点主见都没有太容易受别人的影响，别人说这个好我就想让我老公去做，明天说那个好我又让他去做，还老是教训他可是看看我自己吧，我又做了什么呢。总是在这里幻想一些不现实的东西。因为我的好强老公离开了佳华（2009年6月30），在外面奔波了近三个月才找到工作，那个时候我还老是说他，没能力这个那个的，一点都不为他着想。在加上他爹妈给他的压力又花光了所有的钱没办法，去了德清这样一个远离家人的地方。一个人在那个小黑屋里一呆就是近一年，想想看多么的无聊，那时无知的我还以为他找了份很好的工作（因为有个同事说木塑很有发展我就相信了，还在那沾沾自喜），只有老公自己知道在外面有多么的不容易。吃饭要钱，租房要钱一个月也就一千五百块还能剩下些什么，我还嫌他小气不舍得买衣服，网线也不装，手机也不买好的，想想看当时的我是这么的不讲理。即便这样他还是会给我买零食、衣服只要我喜欢的，想想看我是多么的自私。\n  他从不主动对我发脾气都是我没事找事，每次都是他跟我道歉，我太好强了从来都不承认自己做错了，即使是我的错。我还老是在他面前说他爹妈的不好，其实他们对我也挺好的是我要求太多了，老是想要买房子，想想看现在的房价那是我们说买就能买的起的，我老是拿自己的老公去跟我同学的比，我只是看到了她们好的一面她们的艰苦只有她们自己知道，我太不知足了有个这么好的老公还天天在这里抱怨，这自己有什么好的长的又不出众，个子又矮，真不知道自己在得意些什么。所以从今天开始我要好好的对老公，不要老是去让他一个人承受这么大的压力。要不然我真的就不是人了。\n开心和痛苦都要一起。\n老公我爱你，请原谅我的无知。\n（7：00左右）刚才又因为老公给我的天天日记没弄好，我又跟老公急了，怎么这么没记性啊说了要对老公好的，又发脾气，我到底怎么才能改啊。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3238, 'ZFwmPxuuuLSvkACPAFdTe4', 2, '2010-04-13 18:00:00', '2010-04-13 18:00:00', 'NORMAL', '今天是2010-04-13 。 幸福\n  昨天写了一篇日记把自己的心里话都说了，今天觉得好轻松，感觉好多事情都想通了，不那么受别人的影响了，自己也有了更多的想法，心态也平衡多了。一直都没有过这种感觉。\n超好的感觉哈哈哈好开心。\n 以后坚持，王矩敬加油你现在很幸福，很多人都羡慕你呢。让她们羡慕去吧嘻嘻嘻嘻。。。。。\n今天下午去做了一件意义的事，把存折里的钱半存到我的卡里，一半存到老公的卡(3000)里这样以后我们花钱就方便了，有钱一起花这种感觉真好。呵呵呵呵 \n晚上老公又给我了一个新的天天日记，这次的好用了以后可以天天写日记了。很开心\n  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3239, 'hFvC77ez7WEASwr83AXeQJ', 2, '2010-04-14 18:00:00', '2010-04-14 18:00:00', 'NORMAL', '今天是2010-04-14 。 自己动手，丰衣足食\n今天做了一件很有意义的事。\n前段时间在寝室总是上不了网，一直以为是电脑的或是路由器的问题，就让公司里的人帮忙问问网管，问了以后也还是不清楚是怎么回事，然后就说等他来公司的时候顺便帮我看看，这一看就是好几个月也没见有人来给我看，算了人家不说我也不好老是问。偶尔有一次上去了，没几天不知道是谁动了路由器，我这电脑又闹脾气了。一个生气我好几个月没在寝室上网。\n今天问了一下公司的同事，（其实以前也问过别人，但她们老是说我的电脑问题，一听我就来气，也就没有下文了）他说让我试试重装无线网卡。结果就好了。好开心。\n晚上我把事情告诉老公了，他还夸我聪明呢。嘻嘻继续保持。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3240, 'gt4zTzsm36YR6mJchoRjqM', 2, '2010-04-15 18:00:00', '2010-04-15 18:00:00', 'NORMAL', '今天是2010-04-15 。 过去、现在、将来\n在佳华公司呆了一年半了，想想也没有什么值得留恋的。\n还记得我跟老虎一起来的时候，当时我俩都不太爱讲话，每天都只有我两个人在一起，下午下了班一起吃饭，晚上一起打乒乓球、看电视。冬天不爱出去就在寝室一块听广播、锈十字锈。几乎每个周天老公都会陪我逛街，即便他不爱逛，偶尔也会去他爸妈那里吃个饭。那时的我真的很幸福！\n2009年7月30日老公离开了佳华，去了一个叫做德清的小县城，哪离我这要做3小时火车的路程，刚开始为了省钱我一个月才去他那一次或者是他回来。后来因为太想念我就会要求一两个礼拜见一次。刚开始觉得老虎的房间太小又黑，现在慢慢的喜欢上那里了，因为那里有一个真正爱我、又疼我的人。记得有一次我无意中从网上看到癌症的病症，感觉自己很符合我就以为自己得了，然后哭着给他打电话说我病了，他就从德清赶来安慰我陪我做检查。（其实什么病都没有，是我多心了）现在还能想起他当时紧张的样子。自从老公去了那里我俩就在也没有好好的去吃过一次饭了，以前还会去吃火锅、烧烤，买很多很多的零食，现在都不怎么去做这些事情了。其实这些我都可以理解，我俩过年就要结婚了现在还没有落脚的地方，老虎他也心急。其实我想在这里跟老公说：老公别急，慢慢来你到哪里我就跟你到哪里。\n现在我很迷茫，不知道做什么更不知道去哪里？前几天考了会计不知道能不能过呢，就是过了证书也不能现在就拿，所以会计暂时做不了。化学方面的又不想做了，一个是对身体好，还有就是我对化学不感兴趣。今天一起工作的同事还跟我让我好好做，跟他一起分担别做啥事都不想，做好了就算了。我知道他的意思是让我多帮帮他。其实他说的也对，毕竟我现在还在佳华做呢，是应该把自己的工作做好。说实在的我一点都不想在这儿呆了工作我不喜欢，下班了没人聊天，天天一个躺在床上一两个小时都睡不着觉，好想能跟老公一起看书、聊天、听音乐等等。但现在走也不知道去哪里，因为老虎那边也不想做了，我如果现在去他哪里也不行。一方面我如果不工作钱又是问题，另一方面就是工作的话我两晚饭也是个问题，不能老是在外面吃不卫生又贵。还有一个就是也不能找到合适的，我现在一个月最少也能拿1800，吃饭还不花钱相当于2000了，在德清干什么活才能给这些啊。我正在是想能挣一点是一点，到时候不至于为钱烦恼。找工作得花平少钱呢。\n我到底该怎么做呢？先做到四月底吧，就这么定了。\n我相信，我和老虎以后一定会幸福的，这么多年的辛苦都过来了，在坚持一美好生活会属于我们的。\n加油，矩敬！加油，老虎！\n今天又写了好多东西啊，发现自己还挺能写的，今天是边写边哭啊。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3241, 'cGBbzaWCtApo3PTpYYpFgu', 2, '2010-04-16 18:00:00', '2010-04-16 18:00:00', 'NORMAL', '今天是2010-04-16 。 自制手提包和意外收获\n公司为了参加雅思会展，特意以环保为主题自己动手做的手提包，每个人都在上面画了自己的作品。下午为包包穿带子，穿了两个小时，弄的我手都疼死了，不过还是有点成就感的。\n下了班去晨辉那过买东西吃，刚好看到有卖牛肉的就买，刚好12块，我给了她50的她就找零钱给我，我打开一看嘻嘻48。多了10块我没话就走了。自己觉得很好玩明天可以吃牛肉了而且是白给的。哈哈哈哈  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3242, 'Y38P4Q6xwFrBfA6ba5KMKm', 2, '2010-04-18 18:00:00', '2010-04-18 18:00:00', 'NORMAL', '今天是2010-04-18 。 开心的一天\n今天是周天，天气很好。约了同事一起去逛街。今天去了步行街的顺江买衣服，这里我以前都不会去的，可能以为要砍价而我自己又不擅长这个。开始相中了一件短袖，因为价格不合适就没买，当时心里老是惦记着。后来去别的店铺又看到了，很开心就去试试，试完了以后又觉得也没那麽好看吧幸好当时没买。最后选了一件满身红嘴唇的。希望它能给我带来好运气。看来以后买东西不要冲动想好了再决定。\n晚上老公给我打电话，听老公的声音感觉得到他今天很开心。我就问他怎么这么开心啊，他说了句话让我很自责，他说因为我没提工作的事情，我以前一直认为我跟他提工作是对他的关心。可能是我没能站在他的角度考虑。我老是提工作的话反而会给他压力的。以后都不提工作的事情除非他跟我提。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3243, 'CLQ5CL6YfvYmi2mg7K2cnf', 2, '2010-04-19 18:00:00', '2010-04-19 18:00:00', 'NORMAL', '今天是2010-04-19 。 下雨天\n今天的天闷热，下着小雨。我坐在电脑旁不知道做什么，想找工作又不知道找什么，去哪里找？真的好烦啊。\n在佳华也呆烦了某人总是啰哩八嗦，好讨厌。又不好跟老公说，我该怎么办啊。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3244, 'KhzMGGpJDqSrVQGHM5LwRr', 2, '2010-04-20 18:00:00', '2010-04-20 18:00:00', 'NORMAL', '今天是2010-04-20 。 决定\n今天老虎去合肥面试销售，很成功。但他老是问我有没有决定要去，我也没什么主意的我觉得在那里都一样，他跟我说别人都往浙江跑我俩却回去了，我是不是又在忽悠他。可能他对我不是太放心了，被我忽悠到德清快一年了我也没去。怕了估计他。其实我现在问自己的话我也不确定要去哪里。我真的需要一个能做决定的人。在浙江呆了也快两年了不也这个样才一千多块钱，哪里不能给你这么多啊。\n决定了去合肥  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3245, 'efvcae2uEEgRyB9KkpwyED', 2, '2010-04-23 18:00:00', '2010-04-23 18:00:00', 'NORMAL', '今天是2010-04-23 。 原来衣服也可以这么洗\n把昨天洗的衣服捡回来，自己都吓了一跳衣服好白。以前都是随便洗一下就好了，也不知道干不干净。这次洗衣服时刚好有人聊天就洗的久了点。所以看起来脏的衣服还是可以洗干净的。以后要慢慢洗不要心急。\n\n\n体检\n今天中午去体检了，主要检查了血压、肝功、乙肝五项。其它的都好的只有最后一个还不知道结果。结果应该是完美的。等待中。。。。。。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3246, 'HaoY8tH38urTLKbiq8VWKH', 2, '2010-04-27 18:00:00', '2010-04-27 18:00:00', 'NORMAL', '今天是2010-04-27 。 听话\n五一要放两天假，本来想好了要跟老公去绍兴，在这里这么久了都没去过。本来以为是个好主意，下午跟老公讲了想法结果他不同意，刚开始有点不高兴，可是后来想想老公说的也对现在是用钱的时候，不能乱花。\n等以后有钱了再去，要老公好好补偿我，嘻嘻。我今天真听话。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3247, 'ZdpvKzaTvfTdtaHvKXKMUt', 2, '2010-05-01 18:00:00', '2010-05-01 18:00:00', 'NORMAL', '今天是2010-05-01 。 很开心收到了老公的礼物，魔法项链。五一第一天下午去逛街了，街上人人多的不得了，本来想买双鞋子的也没有合脚的，谁让我脚丫子太小了。本来逛街时间挺好的事情，可因为衣服的事跟老虎吵了一架。不过一会就好了。嘻嘻写的有点语无伦次。我也就这水平了。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3248, 'brVEEnsVXN3WdsukJiQq5p', 2, '2010-05-02 18:00:00', '2010-05-02 18:00:00', 'NORMAL', '今天是2010-05-02 。 今天是五一假期的第二天，早上七点就被老虎吵醒了。天气太热了在寝室呆了一中午，下午去爬龙山30度的天气，热死人了就在山上的凉亭呆了二小时。晚上在家里吃的晚饭，老虎妈做的菜不是一般的难吃，我没次都只吃几口。晚上他妈说让我在那里住我听了都好笑，你们睡过的床就算让我住也要换个床单吧，每次都说让我住我都说不住，怎么都不想想原因呢。提起这些事情我就来气！  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3249, 'ZWjxXdAKu52vxHBKUZRsVR', 2, '2010-05-03 18:00:00', '2010-05-03 18:00:00', 'NORMAL', '今天是2010-05-03 。 今天我上班，老公晚上九点的火车。下了班老公来接我去江边玩了会就去万和城吃烤肉了，记得上交吃好像是去年老虎过生日。8点我回来后老公又急忙回家了。看着老公的背影我很难过感觉像是永远分开了似的，这们的日子什么时候才能结束。\n到了合肥又得开始我们租房子的日子，我最不想的就是租房子，可能是因为小时候老是跑来跑去的吧。我也不知道老虎爹妈是怎么想的，从来都没提过买房子的事情。都不为我们的以后着想吗？\n伤心。。。。。。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3250, 'H2G3SiDhtbDXkj8swcWWSV', 2, '2010-05-04 18:00:00', '2010-05-04 18:00:00', 'NORMAL', '今天是2010-05-04 。 老公到合肥了，听他说挺顺利的，电话卡办了房子也找好了不过挺小的还没有在德清的好。不知道老公中午饭吃了没，只是说晚饭在训儒学校食堂吃的，我个月就过去了希望老公这一个月吃好、喝好、身体健康、工作顺利。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3251, 'AbdNW4NVKaq6hUYBiNqDRE', 2, '2010-05-05 18:00:00', '2010-05-05 18:00:00', 'NORMAL', '今天是2010-05-05 。 他妈的真是气死我了，又是给老娘断网，老是搞这一套你们就没有点新花样了。断了也就断了你好歹跟我说一下好让我死的明白，要不我还以为又是亲爱的电脑有问题呢。真不知道你们这帮弱智是怎么想的，难道我的断了你们的网速就能快了吗，他妈的，蠢货看你们能牛多久。都去死吧奶奶的  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3252, 'hTtrZk4eq9QFNBoBVZ49qA', 2, '2010-05-06 18:00:00', '2010-05-06 18:00:00', 'NORMAL', '今天是2010-05-06 。 打了三个电话，一个是跟单的说招到人了，让我做品检，一个月1300－1600要工作12小时，妈的老娘才不做呢。第二个是文员，靠！说什么要会CAD，早忘了。慢慢去找会CAD的吧。第三个没人接就算了。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3253, 'ir8e5bhsncrEQowXDUwYfC', 2, '2010-05-07 18:00:00', '2010-05-07 18:00:00', 'NORMAL', '今天是2010-05-07 。 坐了一天没啥事，小查走了老汤也不在我就没人管了。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3254, 'EjvRtjsFBF7ToMnE2xmkHU', 2, '2010-05-08 18:00:00', '2010-05-08 18:00:00', 'NORMAL', '今天是2010-05-08 。 又是散伙饭，这已经是我来佳华的第五次了。看着他们一个个的离去我没有当初的难过和不舍，反尔觉得高兴呢，俗话说人往高处走。\n我也要走了，辞职报告觉定下个周二交，虽然工作还没有着落。刚好借这个机会放松一下，好好想想以后到底做什么，人生真的是要规划的！还好我有个爱我的老公，他答应我说养我呢，很开心终于可以睡个好觉了。自从来了佳华我就没睡过一个好觉！  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3255, 'k63sooVzf6ydyqXzpMQmTE', 2, '2010-05-09 18:00:00', '2010-05-09 18:00:00', 'NORMAL', '今天是2010-05-09 。 早上睡到11点，然后吃饭，吃定完饭洗衣服。下午给老公转钱因为这个还被他说了一顿。今天是母亲节本来想晚上给我妈打电话的，可又不知道说什么好就算了。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3256, 'Xbxk8WvUVRoYKShJEvZgoX', 2, '2010-05-10 18:00:00', '2010-05-10 18:00:00', 'NORMAL', '今天是2010-05-10 。 中午上班没啥事，办公室也没人就给妈打了个电话，问了问家里的情况，我妈都说好没啥事，我妈说我妹给他们买衣服了，还说钱是我妹拣的听起来我妈很开心因为妹妹拣到钱，我就没把实情告诉她。聊了10分钟就挂了。其实我一直都起说爹妈我爱你们，但我不好意思说出口，毕竟农村不兴这个。\n下午交了辞职报告，本以为老汤会问我很多东西，结果就说了句“先放这儿吧”，无语。我刚回办公室老汤就打电话过来找杨工，还问他谢东丽的电话，真是太好笑了在的人不好好珍惜，走了的人。。。。哎。。。\n下班和小池，小顾一起去逛街顺便请她俩吃了个饭。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3257, 'HjFnL5pQR6soHfZgHGNQa3', 2, '2010-05-11 18:00:00', '2010-05-11 18:00:00', 'NORMAL', '今天是2010-05-11 。 嗷嗷郁闷！今天想戴耳环，结果右边的堵住了，这可是我痛了一个多月才好的。就这么堵住了。\n  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3258, 'WJJbZjupbq4eyUcWQvYZ5y', 2, '2010-05-12 18:00:00', '2010-05-12 18:00:00', 'NORMAL', '今天是2010-05-12 。 晚上去上虞图书管了，桂花办了张卡，然后借了三本书，我没办因为要走了。时间还早就去步行街逛逛。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3259, 'VdfmQoY8oz5cjen58zDcQt', 2, '2010-05-13 18:00:00', '2010-05-13 18:00:00', 'NORMAL', '今天是2010-05-13 。 下午老公汤找我谈话了，怎么都不让我走，最后说了2个小时才说做到这个月底，让我看完世博在自私走，我也同意了。下午把事情跟老虎说了他也说好的。\n晚上打电话给老虎，也是说关于去世博会的事情，他说要去我也挺开心的，然后我就说让他去修相机要么去买一部，结果他说我怎么这么自私让他买自己不去买。我听了就挺伤心的还哭了，我不知道他听出来没，反正是没安慰我，其实我真的想他能安慰我一下的。我觉得是我俩分开太久了彼此变得好陌生了，他不知道我在想什么我也不知道他在想什么。我哭了他也不说一句安慰我的话。\n他还说现在租的房子很吵挺烦的，那我说你可以在找个好一点的，这位心情会好一点的。他又不爱去找说等我去了在说，可能 他是好意但我就会觉得男人就要做事情干脆点，做顶梁柱，因为我本身也是那种没什么主见的我需要有人给我拿主意，需要有人保护我给我安全。我这人是从小就没有安全感的，睡觉从来都不会很沉的，睡觉时也是缩成一团。所以我一直也吃不胖的，自从高中时就耳鸣到现在也没好。\n今天对他说了好多气话，只是我一个人在那里说，他那边也没什么回应，他越是不说我就越来气，感觉他没在听我说。他说我每次打电话都是训他从来不好好跟他说话，可我觉得我没有在训他我只是说让他多学习。也不是很正常的吗，那个女人不想自己的老公多学知识有出息啊。他既然不理解我那也算了我干麻说那么多让他讨厌我呢。\n我决定半个月不理他，我俩都好好想想是谁的问题。\n\n我现在好想听到老虎说，我爱你，我会一直保护你的。在我哭泣的时候说宝宝别哭，你哭我会心疼的，宝宝最乖了。在我不知所措时跟我说别着急老公帮你出主意。\n  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3260, '33CMuzcpKSwWD9Y5VEzn9H', 2, '2010-05-14 18:00:00', '2010-05-14 18:00:00', 'NORMAL', '今天是2010-05-14 。 把电饭锅、风扇给老公寄过去了，老公不用吃馒头了。嘻嘻 ！  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3261, 'mewo46RWxAF7pURy75fKk8', 2, '2010-05-15 18:00:00', '2010-05-15 18:00:00', 'NORMAL', '今天是2010-05-15 。  可能是昨天睡的太晚了早上不起床，闹铃响了两次才起的床，洗漱了一下就下楼了看到了同事就顺便问了句早餐吃的什么，他说鸡蛋，嗯不错。结果到了食堂就看到了三根油条，我晕，没吃就走了。做完早操就在座位上呆着没事，这时老汤打电话来了，问昨天的东西怎么样，语起气也不好，我说90度不行，他说那然后怎么弄了，我就说然后下班了我就走了，他说噢就挂电话了。真是个神经病自己都不知道在做什么还老是说别人。对这人我真的是无语了。\n中午就这么座着不知道的就到了吃饭时间了。中午的菜还不错一人两个鸡腿，回去就是要睡午觉了，不知道怎么了好像是这个月开始的，午觉一直都睡不着也不知道在想些什么。\n3点多的时候杨工让我帮他压片，我就帮了。压好片座了一会就下班了，晚饭还是吃的中午的所以没什么味口。然后休息了一会把泡了两天的白大褂洗了，烫了个脚就在上网了。刚才老公打电话过来了说东西到了，还问了我怎么防暑我不知道。随便聊了下就挂了。\n\n  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3262, 'hAAT9WDEqHdqeNqFHDAvxo', 2, '2010-05-16 18:00:00', '2010-05-16 18:00:00', 'NORMAL', '今天是2010-05-16 。  早上七点闹钟把我吵醒了，关了闹钟刚好看到有一条短信，我以为是老公给我发的一看是小顾发的说她肚子疼不能一起逛街了，其实我也不记得什么时候说的一起逛街，可能是寒暄的时候吧。然后就接着睡了反正半睡半醒的到了10点半，想上厕所了就起来了上了个厕所也不觉得困了，就刷牙洗脸了，然后把寝室打扫了一边，就去洗了个澡。看外面天气不错就想晒被子，感觉订单也该洗了顺便就洗了。都收拾好了可以吃午饭了，一包方便面一个鸡蛋再加点小青菜，吃的我饱饱的。接着就回来上网了。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3263, 'LjAdjwELmwdEvjvKavx2Ni', 2, '2010-05-20 18:00:00', '2010-05-20 18:00:00', 'NORMAL', '今天是2010-05-20 。 现在上班对我来说就是一种煎熬，一上班就想着赶紧下班。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3264, 'YstWF8kKHgfdTMwjEjL34F', 2, '2010-05-21 18:00:00', '2010-05-21 18:00:00', 'NORMAL', '今天是2010-05-21 。 今天一进办公室就看到杨工在桌子上爬着呢，问他怎么了他说可能是吃坏肚子了，我就很懂一样的给他分析怎么回事，最后结论是胃不好，我就给他吃了吗叮啉，结果到了下午还是没好看来是不对症。下午没下班呢就早点回去了。第二天说看了医生说是中暑了。我晕还真的是我给吃错药了。我这个人就是这样的不懂还装懂，幸好没吃出什么问题。以后不要再这样了。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3265, 'cuz8RcsVT75rn3ow5XFNyr', 2, '2010-05-22 18:00:00', '2010-05-22 18:00:00', 'NORMAL', '今天是2010-05-22 。 昨天听小池说了她的苦恼，一直想要孩子就是怀不上，我也看的出来她很有压力，我也试着劝她不要有压力，可能是时机没到。可是有一点我很气愤为什么不能生孩子就是女人的问题呢，老公是不是也要反醒一下呢，即使是老婆的问题是不是应该一起来承担呢，最起码要一起去看病吧。做为女人谁不想要孩子呢。\n还有昨天老虎问我说宝宝怎么都不怀孕呢，我晕你都不知道我两总共才做过几次吗？而且每次都有防备不是吗？男人到底是什么心里，不好了就想是女人的问题就算 是那有怎么了，应该一起努力不是吗？  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3266, '2mzbo6xiVtGz8PArPQkUDy', 2, '2010-05-23 18:00:00', '2010-05-23 18:00:00', 'NORMAL', '今天是2010-05-23 。 因为肚子疼，5点多上了趟厕所。不过躺床上一会就睡着了，再醒就是9点多了，刚刚洗漱好老公就来电话了问我几句因为手机要没电了就挂了，很开心一大早就能接到老公的电话。之后就吃了点饼干就当是早餐了。吃好了也没啥事干了就把鞋子给刷了，在浴室碰到了桂花就问她今天要不要出去，本来是想说跟她一起出去的，把电瓶车骑过来。她说要去接某女，所以就算了不去了。有时候想想人与人之间的相处真的很奇妙，两个人相处一定要有一个人付出的更多，否则就没办法相处。\n今天不出去了就呆在寝室上网了。\n晚上在看电影忽然间断网了，就我一个性子急到处问怎么了。真是个性子急以后可不能这样了。  #日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3267, 'nXbZqPSse6aCSecQjziZ6N', 1, '2025-02-24 17:14:09', '2025-02-24 17:59:40', 'NORMAL', '今天是 2025 年 2 月 24 日，周一，加加上学一起出门的，我和敬去公园跑步了，说是跑我是小步的跑，我妈送加加去上学了。\n回来把我妈的票给退了，28 号的回上虞的不回去就不回吧，反正啥事我也不操心就这样了。\n上周的报告陈医生说有个霉高，要再去测测，约的周三的，给我整紧张了，没事不在玩电脑了，就这样了看电视就用工控机，树莓派回来留着做服务器用吧，省电呀。\n今天终于把ip6 的问题整明白了，家里的电脑分配ip6 地址是可以外网访问的，真好，这下就不用服务器了，有个域名就好了，还是有问题因为ip6 不是固定的，想办法获取ip6 地址不一样了，改域名解析吧。\n把敬的日记给迁移到 memos 过过了，看了下，刚毕业那几年真的不容易。穷快乐成长未来可期\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3268, 'FB3EYW23NR8dPW5UZwQEcr', 1, '2025-02-26 12:18:16', '2025-02-26 12:18:16', 'NORMAL', '今天是 2025 年 2 月 26 日，上周去省立医院测的转氨酶偏高，今天又去测了下，结果降低了一些。\n检查发现个高级的抽血，现在也有用机器抽了，看效率也快不多少，会进步的，只能是这是趋势了，哈以后就不用护士互相扎针练习了。\n加加的课后美术课报了，创意美术，学着吧。果果学了几年画的还可以，加油\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3269, 'TpyEZFNU8ApXANKwos9ept', 1, '2025-02-27 11:59:08', '2025-02-27 11:59:08', 'NORMAL', '今天是 2025 年 2 月 27 日，果果过生日说要要鸟，玄凤鹦鹉从网上查了下还挺贵的，今天和敬一起去裕丰花市看看，买了 2 只加个笼子 450 元，还买个乌龟 20 元，大点的好养，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3271, 'FQnNMtmQtyL7rTfCD4X95A', 1, '2025-02-28 16:46:42', '2025-02-28 17:43:19', 'NORMAL', '今天是2025年2月28日，早上和敬出去跑了，我只在公园大脚丫那待了会，脚疼一周了， 也不知啥原因。\n中午敬上班我在家座小沙发上睡了会。\n午饭敬回来吃过饭就斗鸟玩，之前说的是周一去办证的，想今天周五了想把资料收拾下，到时周一去快些，给工作人员检查时能快些，我要给敬看下，谁知道那天我能不能去呢，给他看看她知道些到时不着急吗，工作人员让他看这个那个的找不到，现场发脾气，又骂工作人员的。我给她还缺哪些东西先打印着回头直接带过去，看她在斗鸟，看心情是不太好，跟我发脾气，说到时候再搞急个啥周二才去呢，周一收拾不行吗，我以为周一去呢，她不急就好，说我给自己找气受了，她工作也有压力要辅导孩子学习，她英语读的不好，纠结呢，嘿，像她说的，之前不好好学习总是要还的。\n手机里的相册太多了，就想把相册整理下，好多是看病的，想把这些想放到网盘里去好了，放到阿里阿盘了，随便把Alist给搞了下还挺简单的，没有想想的那么好用，还是官网的客户端好用\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3272, 'FanYEKjeEmcvtiAxXU8tMu', 1, '2025-03-02 14:24:59', '2025-03-02 14:27:36', 'NORMAL', '今天是 2025 年 3 月 2 日，日子过得好快呀，前些天搞 alist 网盘组合的事，又想着把之前存的照片整理下存到那个盘里，找了下之前有个阿里的盘，有 1.8 个t 的空间，里面存的东西不多就他了，可是这上传速度没法说呀太慢了娘亲呀，受不了。昨天用手机es文件管理器传图手机的电不够用的，还有广告受不了，今天用电脑传看样子一天也传不完了，快是 2m/s，按理说这速度应该可以呀，稍微算了下 256g 下来要 36 个小时妈的，怎么加速，这网速还是不行呀。\n申请赔偿的事怕是没希望了，娘的这人都太没人品了。\n\n\n#日记 \n\n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3273, 'Es6DXjYduV5S68rEHSeqHh', 1, '2025-03-03 19:53:22', '2025-03-03 19:56:34', 'NORMAL', '今天是 2025 年 3 月 3 日，今天是果果的生日。昨天敬去盒马买了蛋糕，还把金葫芦的绳子从新换了下，算是生日昨天就过了。\n中午敬与我妈吵了说我妈不听，犟驴我就当没听见管他们呢。还说要买车票回上虞今天就要给她买，让她走，\n中午去要素大市场去弄公积金的事和拿护照的事，手机还给拉在车里了，还下着小雨，我在公积金嘛等着，她去拿护照，等半天不来，原来找医保报销的地方了，可能我之前没给她说吧不是在这，在塘西河附近，来公积金出时还在打针电话，嘿，因为肝源没发票的问题业务员在不停问人什么的搞了好久，敬来就发脾气了怎么还没好，那边还有社保卡的电子版在手机里，还想着她上来时一起带过来呢，原来她手机里存了真精，说今天晚上明天早上能到账，回去的路上还说呢。自己的钱都这么麻烦。\n幸好敬打了电话问社保局的原来每月 1 号到 5 号结算，结算不了，等到 6 号再去吧，电话也没白打。\n下午回来接到申通的电话，墨迹了好久，赔了 800 元，就这吧，自己也有责任，药一起裹在被子里就是我脑子有问题，再说泰康也报过了，这算赚的，2 月 8 号寄的件 3 月 3 号才解决，还是寄件的驿站赔的，说是包装不合理。啥原因都有，看来驿站也不好干呀。\n终于把相册都放在云盘了放在阿里的云盘了 256g 传了 2 天，服了，放在相册里看效果还是挺好的，只是相册没传完，备份是完成了，是分两个入口传的还是不太高级呀。备份阿里云盘的账号是 18656094577，联通宽带的手机号\n\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3276, '2AkVmJY2vbk3ftpSKu6mBu', 1, '2025-03-04 12:51:15', '2025-03-04 12:51:15', 'NORMAL', '今天是 2025 年 3 月 4 日，昨天取公积金的钱到账了，转给敬了，她存银行定期了，管她怎么存呢。突然有种感觉能退的钱能要的钱要完了感觉自己也空了没底了，虽然早就要把公积金的钱弄出来。\n\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3279, 'cpLUZBXK2yzeooJgy6M9wD', 1, '2025-03-06 12:09:22', '2025-03-06 12:18:33', 'NORMAL', '今天是 2025 年 3 月 6 日(周四)，今天去滨湖服务中心把医保没报的给报了，第一次去上海没报掉的还是报不掉，说如果拿药的话可以按病提交报，当时太贵了药没拿算了，反正也只是试试的态度去的，今年说政策改了说慢性病不用办长期异地备案了，只是报销比例低些就这办，应该能报个 1k 左右嘿也不多呀，就这一点点。还要 30 到账，这龟速。\n车上敬有提到科大幼儿园，还是公务员好呀，想有个娃能考上就好了，哪怕是个小职员也可以呀，工资是一方面隐形收入，福利办事都有利，加油吧，孩子们，爸爸真的就这样了，我对自己是不抱希望了，活着好好的，能挣一点点就好了。\n今天刷视频刷到个哥们原来网站上的视频他们存到网盘里的，用的 webdav 挂号网上的，只是他们开了网上的会员，在网盘之间相互复制传，我说呢他们不能存在那的，看有个哥们空间有 1pb\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3280, 'WezbPEvYmq2ABcSsceFadt', 1, '2025-03-05 10:30:00', '2025-03-06 12:14:18', 'NORMAL', '今天是 2028 年 3 月 5 日，预约的退个税的，申请了下可以退 2k 多一点还有好几百，想等回来医保结算完在退税吧，多个一分也可以呀，反正不急，才知道大病高于 1.5w 的才能退，最高 8w，而且不是所有自己花费的，只有乙类的才算进去能抵个税。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3283, 'MrBYgS5idsQr5dKKXCa2uA', 1, '2025-03-07 10:45:34', '2025-03-11 07:59:41', 'NORMAL', '今天是 2025 年 3 月 10 日周一，早上和敬一起去公园跑步了我只走过桥就在那里坐着了，\n生鲜传奇店铺承包的问题说有家店 80w，还在谈，我觉得王先峰和敬说问题应该不大，他说借 30w，赚钱算入股，赔了算借，敬之前说借 30 入股 20 给我感觉你家挺有钱呀，希望顺利吧，一个月能有一万的话要 2.5 年才能收回成本呀，能卖那么多吗。\n\n#日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3284, 'nhsEwyny57z9qk8URMQCgF', 1, '2025-03-08 16:29:20', '2025-03-09 06:19:50', 'NORMAL', '今天是 2025 年 3 月 8 日，时间过得好快呀，今天也是周六好些天没出门了今天接果果英语课放学接果果了想顺道把快递拿回来快递员昨天放小区门口了去的时候还没找到，到果果英语课的地方打给快递员了，一会说找到放在红色的柜子上了，\n加加 9 点才起来的，写套数学试卷还错了 3 个嘿，吃过饭要出去玩我不想出去了，腿好些了，现觉得左腿膝盖有些疼，右腿好些了，快好起来吧，加加想出去滑轮滑敬说奶奶弄不好，就没不开心了，\n娃们把鸟放出来在阳台，鸟们挺开心，只是果果不主动写作业学习有些担忧，我上初中了就好开学了成绩就不错了，我是没人玩学的好的，果果这边一直有人玩呀，还是杨文浩聪明搬家了没人玩了。\n接果果了的路上看到阿姨收手机摆的有老年机就问她要不要 5 快开心一下就成交了，买那个手机真的没怎么用纯为了感情纪念的结果还没信号不能用 GSM 网络关闭了\n夸夸宝宝。今天接果果看西安路搞的好干净，广告牌大大的明显清晰，学员也不少等果果 10 分钟就 4 个学生进去了，宝宝真厉害[强][强][强]\n果果要去学校到羽毛球，以为是在体育馆里面的，原来不让进，只让去操场上打，去那人挺多的，还是学生居多，打球的跑步的，和果果打了会，她同学就来了，果果打得挺好，厉害，平时上课没白练。\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3285, '7mHwmRqDNb4qJcaZUzFUDf', 1, '2025-03-09 20:49:52', '2025-03-09 20:49:52', 'NORMAL', '今天是 2025 年 3 月 9 日，这两天牙疼，拉肚子、腿疼、头上长疙瘩、鼻子疼偶尔有血丝的问题还没解决，拉肚子回合肥出现的，腿疼应是前些日子走的多，突然觉得活的好痛苦，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3286, 'iSTWQ35hapLYBU5KVuycoG', 1, '2025-03-11 08:03:24', '2025-03-12 04:56:25', 'NORMAL', '今天 2025 年 3 月 11 日，好久没拉过长长的大便了，开心，擦屁股也没粘稠的了希望好的开始吧，昨天按鼻子好像也没那么疼了，腿也能走些了比之前好多了，感谢，目标 30 年\n敬下班回来就拿着手机看回消息，不管孩子，我说工作生活分开，她就发脾气说怎么可能分开说她工作特殊，家长正决定要不要报名呢。\n周一接次加加和加加说她要带果果去香港玩，不带加加，加加就哭伤心，说不让姐姐去，把火车飞机炸了，不应该笑而是想到他真的很伤心难过，今天写作业又提到，带果果费用 3.5k 左右差不多吧和心理预期的差不多，说有点消费性质的，应不会过分强制消费吧，\n感觉体力还是不行 20 点多流鼻子，我就烦我妈说些大实话，冷多穿点，就没点别的，她觉得都是对的，她说啥我就抵触啥，坐在床上一会感觉好些，怎么办这一辈子就这样了，不能跑不起来了吗，\n为何我不觉得有钱呢，感觉敬觉得有钱，我想着果果整牙，买空调，加加切包皮，差不多要 2w 吧，泰康的医疗 2w，还有泰康的理财2w，这就 6w 了，敬一年的收入了，我不上班怎么办。\n看企业微信工作群里公司的事还挺多烦的，有人脾气还大的很，就在群里怼，一起跟着创业的元老没有一个进高层的，赵子建感觉也很少发言了，他不会也慢慢的被排挤走吧，不知高层来的这些是不是迪马的人，对公司陌生起来了，可能最近在给韩国的交付吧事多，过段时间再会好些。\n我妈回去应该没问题的，若我上班就累成狗了，不上班还是可以的。接接娃做个到啥的。敬是想让她一直待着，她是啥事不用干，我看我妈那愁样烦怎么办，对她没好心情。敬还说对她好些果果也会对她温柔好些。反正 2 个女人都有各自的算盘，都不简单，我怀疑我妈回去了我爸也不会让她来了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3287, 'dycCsXaxr3A7yMqSbUtxdn', 1, '2025-03-12 04:53:59', '2025-03-12 17:57:15', 'NORMAL', '今天是 2025 年 3 月 12 日周三植树节，早上 4 点醒了睡不着了，居然想鹦鹉有没有盖棉被的事，后看加加竟然后背都漏出来了，\n果果几天前就说学校要组织植树后说没地方种，每个班抽 15 个人捡垃圾，果果没抽中还不开心了，说捡垃圾有什么好的，没抽中正好，周末和你一起去捡去，当然人多心情是不一样的。\n11 点吃饭的敬在家吃的，吃过就上班去了，13 点了还没回来原来是去买绿植去了，带回来一盆君子兰，听说很贵，她说 30 元，把家简单收拾下。\n因为今天下午我开车去接的娃，开车还可以，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3288, 'gJ6t84qxrhcZUzTW2DyS6W', 1, '2025-03-13 17:10:21', '2025-03-13 17:11:00', 'NORMAL', '今天是 2025 年 3 月 13 日(周四)，把多肉移到大点的盆里了，原来多肉长的高长是因为水太多了，\n和我妈待这么长时间所悟，两个人相处，越想得到越容易失去，\n连续的阴雨天真的让人很难开心起来\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3289, 'EiqrJYcNfMA2mrcu666oKs', 1, '2025-03-14 18:01:01', '2025-03-14 18:01:01', 'NORMAL', '今天是 2025 年 3 月 14 日(周五)，这两天天气不好，人昏昏沉沉的，躺床上一会就睡着了，睡眠可好了，看书看书就睡着了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3290, 'UAuUGvCvvnhbSu2eHgT3g6', 1, '2025-03-16 12:00:00', '2025-03-23 14:59:56', 'NORMAL', '今天是2025年3月16日周日，中午敬带娃们去公园玩，捡回来好多树棍，下午加加写作业，用树棍做了个鸟笼，果果上课回来后又不断的完善感觉良好 ，鸟儿们不太喜欢。\n![IMG_20250317_144116.jpg](http://yps.aotbot.com:5244/d/images/blog/picgo2025/IMG_20250317_144116.jpg)\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3291, 'gR5TUj3TtgsJodLQoyzZrW', 1, '2025-03-17 15:07:35', '2025-03-17 21:48:40', 'NORMAL', '今天是 2025 年 3 月 17 日(周一)，因为前几天七牛扣了一分钱的问题， 想换个平台，memos 上的文件存储服务，嘿折腾了 2 个国外的都不很顺利算了不折腾了，为了 1 分钱闹心，反正平时也不怎么使用文件这种功能。\n昨天弄个鸟笼现在日记中加图片，markdown 是可以可是上传不方便就在手机上找找类似 picgo 的，结果还真有好用，配置方法都一样的，牛逼，\n看了个开源项目 talebook 说能把电子书上传管理，结果笨的很根本没法阅读，也可能服务器配置太低了吧，反正是阅读书的时候一直转圈圈😁\n今天老师发消息说加加方向的错了很多，是试卷我给他讲错了吗，还是他又考试练习了。很担心是我给他讲错了，那笑话就大了😂\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3292, 'Drpcg7wnki6zRWFmqgf8JU', 1, '2025-03-18 13:30:00', '2025-03-18 15:17:23', 'NORMAL', '今天是 2025 年 2 月 18 日(周二)，敬公司说今天中午去滨湖银泰吃自助餐\n本以为吃过很快就能回来了，2 个多小时还没回来，脑袋里突然跳出会不会给她介绍对象啥的，觉得一下就要失去她了，还担心她开车安全，不让人放心不会主动发个消息吗，假如她要离开我，我也没什么好怪她的，跟我妈闹的不开心。我还有脸去上虞看他们吗，看我姐，看就心烦。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3294, '7cnPGwMjZZBw4rEydHX3tc', 1, '2025-03-15 13:30:00', '2025-03-17 15:33:24', 'NORMAL', '今天是 2025 年 3 月 15 日(周六)，今天送加加上篮球课，因为转到西安路学校上课了，今天和果果一起混进学校了，加加在上篮球课，我和果果打羽毛球，打的胳膊都有些疼了，\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3295, 'VrtQkVn3PqSx5STAXnr6ap', 1, '2025-03-17 19:05:02', '2025-03-17 19:05:39', 'NORMAL', '听书记录\n\n能者上、\n优者奖、\n庸者下、\n劣者汰\n\n一把手说一不二，\n二把手说二不一，\n三把手说三道四，\n四把手……五、六、七八、九把手\n是光做笔记不张口\n\n\n女大三，抱金砖。\n女大三十，送江山。\n女大三百，送仙丹。\n女大三千，位列仙班。\n女大三万，王母喂饭。\n女大三十万，佛祖门前站。\n女大三百万，仙界你说了算。\n女大三千万，六界任你转。\n女大三个亿，盘古是你弟\n\n\n有生无养，断指可报。\n有生有养，断头可报。\n无生有养，无以为报。\n不生而养，百世难报。\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3296, 'NPCWuVzbZBPSvdFkj9GPK5', 1, '2025-03-19 10:54:08', '2025-03-19 22:03:43', 'NORMAL', '今天是 2025 年 3 月 19 日(周三)，加加之前要报的西安路举行的围棋比赛终于要开始了，期待宝宝的表现，成绩无所谓，开心就好，可是加加这么好的兴趣还喜欢怎么继续培养呢，敬说自己玩，我觉得不对，还是应该报班系统的学，先掌握前辈的方法在想着创新，不是在想着总结，自己造轮子，篮球课结束后再想着报班学吧，\n放学回来到家不开心，问了才知道原来连比赛都没参加，问他会不会围说不会，老师就让他回去了，伤心坏了，说下次运动会报铅球报老师副校长砸死，看的出来是很生气😡，这下可记住了要说会，真是希望越大失望越大，好厉害上画画还能正常心的上完，没在学校哭😭生气。\n晚上陪加宝写作业，准备洗漱突然有些头晕。\n现在看我妈像陌生人不想搭理她也不想她搭理我，像小时候不愿意和小盆友玩不说话一样，母子关系怎会这样，看她什么都烦。饭提前一小时做好，包子问加加说不吃一会又问，天天脑子想什么的，家里平时就我两她也很少出去就在家里磨来磨去太影响心情烦了，觉得陪着孩子孩子就开心，其实早就嫌弃你烦你了。对呀这是若有第三人说就好了，可惜没有就在这耗着，没文化真可怕，气人还不知道是他气的，怎么气的。\n果果今天把一包纸巾扔过来，说啥味呀，我知道那包是从天津带回来的，漏油的，可突然细想这不是一个证明吗，证明油是可以通过塑料的，天呢只是时间有些久而已，40 天了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3297, 'DKuuBvrQzUBakfYjsgTZjB', 1, '2025-03-20 00:24:38', '2025-03-21 07:42:56', 'NORMAL', '今天是 2025 年 3 月 20 日周四，凌晨三点郁闷的一晚，睡不着了，10 点多刚有点想睡，果果洗漱，还总提到声音我以为是敬和果果说话，原来不知哪家的，后又迷迷糊糊的还做了个梦梦见和多个人做电梯，电梯到了楼层不停一直往上，后跑到太空去了，果果那个换的手表响了，声音很微小，理解敬说的吵了真的奇怪昨天怎么没响，\n本以为今天会用钱，敬要和同事开生鲜店，对方一直没有消息，钱都准备出来好几天了，这收益没了呀。\n午饭后午睡一下睡到 16 店多，怎么这么能睡，反正睡得也是迷迷糊糊，半睡半醒的。\n加宝先写作业，吃饭，在写作业，妈妈下班在一起出去玩，新的规划的一天挺好的。天暖和了天黑可以出来玩。不冷\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3298, '2BdM7krABLK3LMwNCxM4WX', 1, '2025-03-21 12:50:32', '2025-03-21 18:47:45', 'NORMAL', '今天是 2025 年 3 月 21 日(周五)，娃们上学棉衣脱掉了，\n早上去公园药水带了手机忘记了嘿，早上公园打扫浇水坐会就走了，在路口等敬的也不知道时间怕她走过去了就回去了，过红绿灯路口遇到了，我在他的前面，\n回家把线捋下用固定下好看多了，\n门滴些润滑油，开关门有声音，咯妞咯妞的，滴些好些\n我妈看有个未接电话昨天我爸打的说要回家，我说你和敬商量，之前让你回去不回，现我也做不了主。\n居然想到公司用的那种物联网卡用在手机上。嘿斤斤计较想这些。\n敬中午回来我妈说要回家的事，吵了一架就知道会这样，说话不注意场合时机就知道会这样。\n敬说中午看到王先峰了说了承包生鲜传奇的事，觉得合伙的可能性不大，有好的项目为何要和你一起呀，一个人干不好吗。\n等敬去香港回来心情好些，再说让我妈回去吧，要等等我就上班去吧，总不能一直在家呆着吧，敬的工资也不够花的，再说我不挣钱花钱也不自在，上班了没时间做饭就去外面吃了，也能剩下不少。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3299, 'WVU3mWR5bnLurAFdj7DbCA', 1, '2025-03-22 22:08:26', '2025-03-23 06:43:29', 'NORMAL', '今天是 2025 年 3 月 22 日周六，前些天知道今天是骆岗公园的风筝节，想着娃要放风筝，岸上草原有些远，在门口就想着带他们去，果果早上上课了，中午 11 点多敬带回来，说去公园玩我和加加在楼下玩呢。说带风筝说不让放，先探探路看看，好多放的没人管，\n14 点半带果果去检查视力到哪\'16:31 排到，扩瞳还做不了了，滴眼药水 5 分钟滴一次，要 20 分钟，说到时间就下班了，下周六早点来吧，顺便去新华书店看看，把药拿了，看有门诊报销就试试，不能报有最低标准不到标准不能报，医保卡里点钱把里面的用掉了，\n在医院和果果聊了些说妈妈大声说话嚷你，你可以说出你的感受，妈妈你嚷我我不开心，我希望什么什么的，就怕孩子不搭理父母很危险，像我现在对待我妈一样。\n回来快 6 点了，我妈带加加出去玩了，我吵了菜赶紧吃敬说 6 点多，回来带他们放风筝，到家快 19 点了， 天都黑了，没去成。\n天热起来了，路上很少有人穿毛衣的了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3300, 'jUheRkbA7hjHS4i8PGiLWW', 1, '2025-03-23 06:31:45', '2025-03-23 21:29:09', 'NORMAL', '今天是 2025 年 3 月 23 日(周日)，夜里做梦带着小葫芦去上班，不知怎是学校，是学校的桌子，有人要看就给他看了，后又有人要看，他又传给别人了，那人把玉的金铂皮给扣掉了，我就说有不好的寓意这事没完，要找老师家长赔偿。\n七牛又扣了我一分钱真是的，决定不用了，没天理了，把公用的给删了，域名也解绑了，以后就用 115 网盘的吧，只保留私有的作为资料备份的用吧。\n加加第一次去棋社围棋了，果果还在上英语课呢，先先先接加加，加加水杯忘记了，掉头又把加加和他奶奶放在棋社门口了，我去接果果了，她已经出来一会了，下次应该先接果果回来路上带着加加，这样即使骑电动车也方便些。\n到家后吃些东西就去放风筝了，在草地上放的人还挺多，加宝飞不起来，不太开心，后来有飞，线都放完了到底了开心，果果说放风筝也没意思，这是玩够了呀。敬拿来了汉堡和我妈做的饭，在路边板凳上吃的，\n敬和果果一起去上班上课，我带加加回来了，写会作业，下去踢球。\n问天津陈池义半年做ct，是做腹部增强还是 petct ，说最好做 petct 明天去约吧，反正能报。\n晚上说加加把围棋课 1k 多的，敬的工资花完了，开始为钱焦虑了，这还没一个月就花完了，，敬的工资明显是不够一家人花的，一个月敬回来上班去吧，看着我妈烧水浪费就不开心了，虽然水费燃气费不多，从回来敬给我转了 4k 我回给他 1k，可我也没怎么花钱呀，怎么就没了呢🙁\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3301, 'TcpNsNyARg4T9xZk7ZViFX', 1, '2025-03-24 17:48:24', '2025-03-24 19:00:42', 'NORMAL', '今天是 2025 年 3 月 24 日(周一)，今天去医院了，安医做检查预约了下个月的检查约了 petct，去省立医院开了依维莫司。敬去大钟楼的联通改套餐，说改不了联想套餐的事不想了算了就这样了，去省图书馆把之前果果办的图书卡给退了，100 元押金 6 年了，好像也没怎么借过书。\n回来后我妈就要做饭吃饭，我听着就生气，只是把我养大没育，天天就知道吃，\n和公司说了下说要去上班的事，敬说应先和公司说下，觉得对是要和公司打声招呼免得直接去太突然，说了说部门商量下，估计是和领导商量吧，毕竟谁都不愿意要个雷，如果我是老板我会想办法把他打发了。\n最近 2 天心情不好，想和钱有关，焦虑了吧，娃也写作业磨不开心，就这吧，心情好些。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3302, '9zmKLc5mFCvfiR2aGNKETD', 1, '2025-03-25 08:30:00', '2025-03-26 10:25:54', 'NORMAL', '今天是 2025 年 3 月 25 日，19 点多澳汀人事打电话过来说了一通，意思是等领导回复，领导要问问领导，嘿怎么这么复杂呀，我随口说了句，应该是我把这事想简单了，对方听了还以为是她不会办事搞复杂了。\n下午敬上班前 15 点多就发好了面，等芝士屑，面都快 2 次发酸了，我给放到冰箱里了，18 点左右才送到，赶紧做，娃们吃的很开心😊\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3303, 'ZzWjCMikNo6V6dJSZMzSkM', 1, '2025-03-26 10:23:04', '2025-03-27 11:14:39', 'NORMAL', '今天是 2025 年 3 月 26 日(周三)，昨天就做披萨了，今天早上又给娃们做，吃的很带劲开心😆，还是果妈厉害知道宝宝爱吃什么。会拾掇。\n早上和敬出去跑了会，最近脚是不疼了，可是伤口不舒服，大喷嚏都会有些疼勒得慌，真是每天的感受不一样呀。上班复工的事也不急了，慢慢等吧，也不焦虑钱的事了。花老本就老本吧，急也没用。\n泰康的报销提交了，人保要等到下个月 10 号才能提交，广电的卡现在注销需要 50 元违约金，5 月 1 号后就没了，再用一个多月吧，\n下午 16 点醒来后有些头晕，以为是睡得时间长的原因，没在意，18 点多 吃饭时觉得有些热，量体温 37.6 ，19 点多 38.3 了，有些担心，怕是排异反应，陈医生说去医院抽个血看看，去庚玖说是感冒了，就开了退烧药，不敢开消炎药\n敬回来说亚运老婆生了女孩，挺好的， 2.8kg，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3304, 'm8vJjpeQcSYtG2kFG7S7D2', 1, '2025-03-27 11:17:57', '2025-03-27 16:38:04', 'NORMAL', '今天是 2025 年 3 月 27 日(周四)，感冒还没好，有些头晕，多睡休息，愿早点好起来吧，中午量还 37.7，嘿，活的好难呀，\n今天张伟打电话，说帮个小忙，看他企业的注册资金 20w，挺好的做起来了，软件都是用别人的毛驴机器人。不管怎样能做起来就很厉害了。给他搞好了没任何表示算了以后不给钱不给弄了，我现在很缺钱\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3305, '5CWzM7oUnv8SG6C5gU7mea', 1, '2025-03-29 19:30:00', '2025-04-01 20:58:20', 'NORMAL', '今天是 2025 年 3 月 29 日(周六)，\n中午去庚玖医院内科看了，做个咽拭子拿了口服的消炎药回去了，11 点多敬回到吃点 敬一会上班去了，\n下午 39 度找开的布洛芬没找到喝了儿童了 10ml，2 个小时冷感觉没啥反应又去喝了 12ml，敬 6 点多回来了，20 点多吧 又吃了，敬看我手掌有些红，担心又会是肝不好，焦虑\n夜里觉得冷发抖，39.9 敬被吓醒了，给 120 打电话，去的省立医院，挂了发热门诊，后又挂了内科门诊，抽血，掉了退烧的，消炎的烧总算退下去了，人也舒服多了，敬还租了个床我躺着睡着了，挂的号不给看住院。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3306, 'LS55rP7mBjdBMCxcVCPLhQ', 1, '2025-03-30 19:30:00', '2025-04-01 21:15:35', 'NORMAL', '今天 2025 年 3 月 30 日(周日)，我在床上了睡着了，敬去挂肝传染科的号看大夫了，插对说半天给办个传染病的院还是在传染病医院我一看是我之前上班路上的那个，有些担心怕我会被传染别的就更麻烦了，当也没更好的办法就说先去了，\n打车到传染医院，到那第一次进去看，路破，建筑外的杂草长的很高，里面也没几个人，进去看住院的人还是不了的只是都在里面不出来，办住院手续，遇到这边的医生敬和她说说哭哭一通，给安排到南区的肝移植病房了，不管怎么好厉害，打车去南区了还是曲线住院\n南区办住院手续本以为住院之前办了，原来是急诊开的单子，要从急诊开的办，等的一会 11 点多了 宝宝 12 个小时没怎么好好休息了，还去错了本以为只有一个住院楼呢，原来是 2 个，中间只有 3 楼是连着的，要吗有马路过红绿灯。\n到那边办住院，下午医生上班后就吊水了，烧也退了些，搞的好焦虑一直还以为是流感，细菌感染，我也迷糊到底啥原因呀，敬抽时间回趟家给果果收拾行李了，香港敬怕是去不成了让果果自己去吧，老师大多认识也没啥，果果也乐呵\n一起睡的病床敬睡的很好，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3307, 'YCWXBGL8Fnfj83ud935Jn2', 1, '2025-04-01 21:16:05', '2025-04-01 21:40:03', 'NORMAL', '今天是 2025 年 3 月 31 日(周一)，早上抽了血，13+管子，吓我一跳，咽拭子 15 项还是没省掉，大便小便痰都测了，这是要大排查呀，\n下午还做了ct 头腹部胸部做个，没有癌细胞，说胸部有积液，陈医生说是肺炎，依维莫司生病期间就不吃了，可能是想恢复的快些吧，\n\n敬 10 点多回去趟这边医生想看看我手术后组织的病理，医生好像是没给，问陈医生他那还真有，回去那其他的，和果果又交代些又回来了 3 点多到的，刚好差不多轮到我做 CT ，增强还必须要家属陪着的\n\n发烧的问题是好些了，正常体温了，拉肚子咳痰了感觉又严重了，2 天出不了院了\n\n果果 夜里 11 点珠海了一路平安，12 洗澡 1 点才睡😴，该累坏了吧，看还挺兴奋的😁\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3308, 'msWRxomuADZhgeS3mWcYdA', 1, '2025-04-01 21:38:54', '2025-04-01 21:52:07', 'NORMAL', '今天是 2025 年 4 月 1 日(周二)，早上医生叫敬过去好担心呀，原来是去我的 CT 说有白肺，一个肺的 1/3 白了，普通肺炎怎么这么严重，感觉情况好复杂呀，一路又问家里是不是养鹦鹉，咯噔一下，原来检测到它的病毒，鹦鹉热支原体感染，就想着外面的没想到家里的动物，赶紧想着送人了，\n鹦鹉热会导致白肺，还要说还要做检查，已经在吃治疗的药了，要吃 14 天，依维莫司这么长时间不吃有些担心，吊了 2 次消炎的和雾化\n拉稀的问题好了，今天就拉一次虽有些稀比以前好多了，后面也没了，之后我是与任何宠物无缘了家禽什么的也不接近了\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3309, '5y955w6DuUUDHymrFcA3dR', 1, '2025-04-02 13:36:55', '2025-04-03 19:02:49', 'NORMAL', '生孩子是育，养孩子是德，托举才是恩，\n榜上无名，又不是脚下无路。\n天赋过人就上交国家，\n资质平庸就承欢膝下，\n没有人会因为考试羸的所有，\n也没有人会因为考试输掉一生～\n世界不过是一张纸，未来才是一幅画。\n\n\n\n孩子放学四问，三不问！\n首先三不问！\n1️⃣ 别问"作业写完了吗？"就像你下班被问"今天赚多少钱"，谁听谁烦！\n2️⃣ 别问"老师批评你没？"越问孩子越敏感，没事都能想出毛病\n3️⃣ 别问"有人欺负你吗？"总这么问，孩子真会觉得自己好欺负\n4个必须问！\n1️⃣ "今天有啥开心事？"——引导发现生活乐趣\n2️⃣ "今天哪里做得棒？"——帮孩子建立自信心\n3️⃣ "需要爸妈帮忙吗？"——让孩子知道有后盾\n4️⃣ "接下来怎么安排？"——培养时间管理能力\n坚持一个月试试！孩子学习更主动，亲子关系更轻松～', 'PUBLIC', 0, '{"property": {}}'),
(3310, 'SB7q6J6L5cbhFt9GSpKWqv', 1, '2025-04-02 13:40:03', '2025-04-02 13:40:03', 'NORMAL', '今天是 2025 年 4 月 2 日(周三)，幸好这几天敬公司出去旅游了，敬没去成才有时间陪我在医院，今天状态很好，说还是要查个肺🫁，还没通知啥时候，后天加宝就放假了，要查快呀，快快好吧受罪\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3311, 'LQ8DePZPiokBh4ysChVC5h', 1, '2025-04-03 19:09:16', '2025-04-03 19:09:16', 'NORMAL', '今天是 2025 年 4 月 3 日(周四)，\n今天做了呼吸镜，先往鼻子里滴麻药，去屋里后往鼻子插管子，又滴麻药，搞得好抢，吞咽了几口麻药其他过程还好不难受了，出来后咳了一会，2 小时后不让吃喝，看单子说光滑没事，说清洗下痰说没有，不知道是不是没找到位置，娘的，充洗后的水拿去化验了今天还出不来结果。愿快点好起来吧，还是虚走会就会累困。\n果果今天在澳门玩了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3312, '9zSLbozo6MQwRBVf9veLt7', 1, '2025-04-04 18:55:35', '2025-04-04 18:55:35', 'NORMAL', '今天是 2025 年 4 月 4 日(周五)，今天就吊水了没有检查，敬中午回去了，怕加宝在家待的着急带他出去玩了，\n白天学 flutter 了，之前有些基础看起来还是挺简单的，只是后期还是要系统学习的，看遍官方的文档。\n果果今天应是在珠海玩\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3313, 'GVEjC6p4hEHF7bmLAzLxEg', 1, '2025-04-06 21:09:19', '2025-04-06 21:09:19', 'NORMAL', '今天是 2025 年 4 月 6 日(周日)，我还在省立医院南区医院，因为鹦鹉热支原体感染的事，敬回家了，果果昨天回来了，要写作业，加加也要出去玩陪着，我还好吃的送到跟前，洗漱睡觉就好，这几天三瓶消炎的。\n上次扎在胳膊上今天肿了我都没感觉还是拔针的护士发现的，晚上又要挨针了。\n我妈上班了没时间说在车库打扫卫生，\n个人所得税退税办理了，不等了医保报销的估计是没戏了，同时办理的 2 笔只有一笔下来了就这样吧，总比没有好。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3314, 'jHjpeJtipyhBMdbAXyfVJA', 1, '2025-04-07 18:14:19', '2025-04-07 18:14:19', 'NORMAL', '今天是 2025 年 4 月 7(周一)，早上做了 CT 结果还是有些阴影，问医生可以出院了，再吃一周的药隔 2 周再测下。 办出院回来了，回来打车有些头晕，\n吃饭时拿筷子明显感觉手抖，希望他克莫司停了后能改善吧\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3315, '4jEkSyYuQSfKQuKDBJEk68', 1, '2025-04-07 19:07:54', '2025-04-22 16:19:24', 'NORMAL', '亲爱的宝贝:\n自己把衣服洗了，叫独立；\n课堂上老师提问，你经常第一个举手，叫勇气；\n不到10分钟就洗完脸刷好牙，收捡好房间，叫效率；\n说好了玩20分钟手机就不玩，叫守信；\n回到家就写作业，叫自律；\n睡前自己又看了一会儿书，学了一些知识，这叫富有。\n宝贝，加油呀！好习惯是慢慢养成的呀！\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3317, 'W9PRmxQtkeFuFtsj6XkSeZ', 1, '2025-04-07 19:14:20', '2025-04-07 19:14:20', 'NORMAL', '“子丑寅卯辰巳午未申酉戌亥”的读音如下：\n \n子：zǐ\n丑：chǒu\n寅：yín\n卯：mǎo\n\n辰：chén\n巳：sì \n午：wǔ\n未：wèi\n \n申：shēn\n酉：yǒu\n戌：xū\n亥：hài', 'PUBLIC', 0, '{"property": {}}'),
(3318, 'U4zfmwL8HRZMbuLmMMvFyS', 1, '2025-04-08 17:14:34', '2025-04-08 17:14:34', 'NORMAL', '今天是 2025 年 4 月 8 日，昨天提交的泰康报销了，住院因为是发热的原因，有报销门槛 1w，也不知道怎么算的共花费 1.4w 自费 6k 报了 4k 多，算了也算不明白，这么多就这么多吧。\n早上和敬一起出去跑，下午出去了 2 小时还好不累，状态挺好看的，身体好了又想着搞钱的事了，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3319, 'bz2NgCFaGzywpRtHAEmxsh', 1, '2025-04-10 05:00:00', '2025-04-11 06:11:46', 'NORMAL', '今天是 2025 年 4 月 10 日(周四)，早上起来敬说摸加加的胸口有块骨头很明显，她和果果的不明显，去省立儿童医院检查，之前挂的骨科要去胸外科看，拍了片子说第四根肋骨粗分叉了，说不疼不用管，如果要动手术把骨头给磨了，观察再说吧反正也没啥影响，说不定长长就好了，\n敬这几天去黄河路小学了，也是老是在一个学校门口宣传脸都熟了，只是娃放学在学校门口看不到妈妈了，多少会没些安全感。\n敬借出钱开生鲜传奇的店今天开业了，希望能开起来，股份算进去吧，即使顺利的话也要 2 年才能回本。\n关于我复工的事人事回复在等领导通知，等等的就没戏了，好担心，看奇瑞在招人工作地在芜湖，嘿万一有个不舒服的在跑到合肥来麻烦事，去不得呀，工作的事慢慢等吧，心态放好，月底还要检查鹦鹉热呢。\n辅导果果写作业，感觉还是有价值的，22点多我躺下睡了，不知道果果作业写完了没以后她关灯去睡了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3320, 'VkCrCEtrpaCMsP37fL7Ae7', 1, '2025-04-11 06:08:35', '2025-04-12 12:08:18', 'NORMAL', '今天是 2025 年 4 月 11 日(周五)，时间过得好快呀，夜里睡觉妈的不知那家一个男的大声说话吵醒我好几次，还好早上起来还算精神\n中午回来我妈说我大伯住院了，生病了具体什么我也不清楚，也没精力来问，昨天我大姑打电话过来说的，我二姑去照顾他了，在阜阳住院。\n澳汀人事打电话过来关于复工的事，说是公司要解除劳动合同，n+1 的赔偿，9.6w，当时和他说希望能再交几年的社保，后想想不能一直不工作吧。以后还是要找个班上的，工资少点轻松点，能交社保拿点工资就好。问问能不能找着私活干，嘿干私活就跟顺风车一样不挣钱。\n觉得公司做的过分当时就想想了能一个月 6k 在家办公就很满意了，财务的打电话过来意思就是让我接受，公司的情况不好，人事也很尽力了。\n对敬来说压力比较大了，突然觉得回到 12 年前在包河苑租房子那会了，房东要涨价 50 还是 100 呀 觉得生活一下变难了，现在比那时好多了，至少手上还有存款，敬工资还能维持生活开支\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3321, 'bAFifrrhHQ8UCdLUknycZY', 1, '2025-04-13 16:06:23', '2025-04-13 16:06:23', 'NORMAL', '今天是 2025 年 4 月 13 日(周日)，昨天没睡好觉，果果讲数学讲到 23 点多，不知道还是楼上楼下的说话，一会声音大一点，就吵醒了，好容易睡着了，凌晨 2 点多醒了，好费劲睡着了，应是 5 点多吧，听到敬说话说我妈给她吵醒了，我又睡了，吃药也是迷迷糊糊吃的，7 点多了，果果要起床了我才起给加加叫起来，加加 8 点半的围棋课，果果 7 点 45 的数学课，敬先送果果在回来送加加的辛苦了，\n想打印\n楼上的兄弟你好，凌晨 1～3 点实在太晚了， 不知你是在打游戏还是搞直播，多次惊醒邻居，请你声音平稳些小。劝你早点休息，避免爆肝。\n敬说没用，没用就没用吧，算了，夜里还想呢诅咒他得肝癌。\n和物业也反映了，他应有每户的微信，希望能提醒到位吧，娘的，敬说是楼下的，楼下的房子是出租的估计换人了，\n我躺着也没在睡着，快 10 点想给他们做点什么吃的，看到还有盒意大利面就给他们煮了吃了，看吃的很带劲开心。\n我妈回来一会我做床上睡着了，13 点多才醒，一会敬回来了一起吃了点。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3322, 'Lo7UQNJPFcAsQHr7Cy6v4y', 1, '2025-04-14 02:55:47', '2025-04-14 22:18:38', 'NORMAL', '今天是 2025 年 4 月 14 日(周一)，凌晨 1 点多被吵醒，去窗户外看看好像 1302，1502 卫生间的灯都亮着呢，把敬叫起来了，说听到吵了，她穿衣服，果果也跟着醒了，我先去楼下看看确定就是 1302 的人，到他家门口听的声音特别清楚，一会敬下来，我来录音确定，我妈也跟着醒了跑到楼下，说我怎么了，我就是讨厌她这样关心我，一惊一乍的，她下来了果果醒了不害怕吗，我给物业打电话 20 分钟还没来，敬说敲他家的门，敲好几次都没开，应是打游戏带耳机呢，打电话报警了。\n20 分钟左右民警就来了，1302 家的灯也关了， 敲他家门开了，态度不太好，说要睡觉什么的，说是打游戏，民警说 10 点以后就不要吵人扰民了，还这样就要物业联系房东，把他赶走，不组给他了，希望这次他能改正吧，问他职业说是蔚来的。好厉害我之前期望的公司。\n不知为什么住院不舒服的时候，困的嗷嗷叫，现在却很难入睡，不困\n下午感觉有点恶心，胸闷查了下盐酸多西环素会有这副作用，明天最后一次吃药，希望停下后过几天能好吧。很担心是之前白肺没好清，严重了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3323, 'hoceNEgbLJkfozo6jnCSvX', 1, '2025-04-15 15:30:00', '2025-04-15 18:39:06', 'NORMAL', '今天是 2025 年 4 月 15 日(周二)，昨天说恶心的事，睡一觉舒服多了，体力还是跟不上呀。容易累，应该多休息。\n前 2 天因为楼下吵的问题，昨天凌晨报警今天没在听到了，和敬换房间睡了。我和加加在大房间睡，果果和敬在小房间睡。敬说睡不好，腰疼加加睡觉不老实，踢被子。22 点说睡的醒了感觉是被敬训果果吵醒的，23 点多又睡了， 一夜没醒真好，5 点多起来吃药很精神。\n关于果果辅导作业的事很担心呀，担心果果的性格会变，其实在数学上花费的时间很多，敬会发脾气大声，果果学习方法还没找到，不会总结，不会的题下次还是不会答案写上去交作业有啥用，时间就想着写作业完成任务，应多谢时间复习，思考总结归纳。\n有些焦虑投了几个简历都没消息，就一个要简历了后面还没在说什么，估计没戏，嘿找工作真难吗，年龄大，身体还不好\n看了澳汀买的补充保险去年还报销了 1.4w 多呢，2025 年至今报了 4k 多还有 2 笔待报销的，报下来估计也有个 4～5k， 离职的话这个钱也没了，虽然之后应不会去医院花费这么多了。但总觉得是个保障，即使去别的公司怕也未必能买了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3325, 'GB2obCQARjzdf9pM7DpnkE', 1, '2025-04-18 18:39:17', '2025-04-18 20:15:54', 'NORMAL', '今天是 2025 年 4 月 18 日(周五)，\n吃过早饭我和敬一起去包河图书馆，敬把书还了又借了几本，我在那边等着洗车，洗车发现天窗的管道漏水了，怪不得前几天下午副驾有水，之前只以为是伞上的水没想到是这原因，这样的话水好多天了，洗车的地方说换不值钱忘记问价格了，因为要晒的原因就没在那修，因为去开麻烦。\n洗车的时候给物业打电话说关于楼下吵的问题，说沟通态度不好，22 点给他断网断电的，说会和业主沟通，希望能解决吧，再不行就只能找他公司行政部门了，公司给他施压。让他滚蛋。\n之后去了澳汀昨天说好了，也想开了，赔偿 9.6w 就这样吧，说好了今天去签，没想到人事的和敬聊了那么久整到 11 点半才走，说是 5 月 10 号钱到账，社保交到 5 月份，想这几天多拿些药多报些，\n上次换刹车传感器京东的贵一点，想这次直接去途虎吧，没想到要 1400 多问 4s 店才要 1300，给京东的打电话没接，给亚运打说要 700～800，算了去别的地方问问吧，回去京东说要 860，就这吧，以后有麻烦安全隐患再导致传感器问题麻烦。晒 2 天。周日应能开回来吧。\n好纠结呀，要不要买台笔记本电脑，等有活了再说吧，要不买了也没用。今天国家补贴能省不少。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3326, 'oSGp44e2vg4FUjmZLaxX7o', 1, '2025-04-19 07:10:11', '2025-04-20 07:11:37', 'NORMAL', '今天是 2025 年 4 月 19 日，早上起来一夜到闹钟响，真好，从来没这么了，😃能量满满的一天。\n中午快睡好 15 点，还是被加加鼓捣醒的，果果还要去学校打羽毛球，刚起来迷糊不想去，还有计划的面包要烤呢，看面已经开了。就让他奶奶去送了，和果果在家弄面搞形状，结果烤的温度太高糊了，也没任何形状了，塌了膨胀了些，又和了一盆 21 点烤 180 度还是糊了，敬说 150 度就可以了。嘿好失败呀，想起之前买面包机做面包我妈还拿给雨涵吃我弄的啥面包硬的很，不知道父母怎么想的不好的东西送人显摆。觉得欠别人什么，想着让我还自己不会买些东西以我的名义送吗，\n晚上出去玩和敬说感觉堵的慌，具体哪里我也说不出来，她急逼问我那知道呀，几天了，担心是不是白肺引起的。\n晚上睡不着觉，也没听到楼下吵，上厕所，以为热把上身脱了才睡着，一夜到亮。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3327, 'ZV7wUebAX3GQpt3UaWUugx', 1, '2025-04-21 12:00:00', '2025-04-22 12:33:18', 'NORMAL', '今天是 2025 年 4 月 21 日(周一)，昨天夜里加加上要厕所，开灯光着脚丫就去了，拉了好多，出来想吐，家人都起来了。夜里的时候他的脚踢到我，我又睡着了没起来给他盖被子觉得好自责，怕是冻到了，一会不想吐了吃了点益生菌，盆放旁边敬给他搜搜肚子睡了。\n早上起来加加没什么事，又吃了粒益生菌，吃点小米粥上学去了，中午接回来吃的，下午送过去了。\n下午把车装好开走了，敬要五一开车去南京参加他弟小孩的满月酒，要开 2 个小时的高速有些担心。\n车子周五洗车时说天窗漏水，开回来在旁边的京东养车修的，还好了就这吧。\n果果回来敬问果果语文考的怎么样说作文不会写，阅读看不懂就焦虑了，孩子该怎么辅导呀，我小时候不会的就自己看答案看不明白在说问人，现在渠道多了，父母累了孩子还是考不好，方法不对，不主动学习呀\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3328, '7bdTmWtV7MhCvnVQkJikd4', 1, '2025-04-22 12:37:29', '2025-04-22 12:39:38', 'NORMAL', '今天是 2025 年 4 月 22 日(周二)，最近心态好像发生变化了，不怎么想着挣钱工作了，也不怎么用心学了，睡得好白天睡 2 觉，还睡不醒，天天像猪一样，这人生。\n可能家里没电脑了吧，两个电脑都好老了，09 年的 17 年的开发是不行的，只能看看手机视频资料了，没法上手。就想着有份活挣钱买个电脑。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3331, 'Q9KcBbbvis7YpaYYTCCuPq', 1, '2025-04-24 16:04:48', '2025-04-24 16:04:48', 'NORMAL', '今天 2025 年 4 月 24 日(周四)，找看工作有段时间了，连个面试的机会都没有，真的觉得找工作难了，是看到年龄大了就不要了吗，我招人时就是看年龄大的就 pass 了，这种事轮到自己身上了😮‍💨，还和程序走缘不。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3332, 'CuzS6nJSxNiTyeR5BVYaCC', 1, '2025-04-26 09:33:57', '2025-04-26 09:33:57', 'NORMAL', '今天是 2025 年 4 月 26 日(周六)，晚上做梦还梦到嚷我妈，嘿怎么回事呀，怎么对她这么多意见呀，天天慌慌张张匆匆忙忙的。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3333, 'KB4R5iKNKUktxkn8D8sYHV', 1, '2025-04-28 11:45:45', '2025-04-28 11:45:45', 'NORMAL', '今天是 2025 年 4 月 28 日(周一)，\n昨天今天都和敬吵架了，昨天说要弄短视频那个不会了问我没告诉她了，想到跟她讲过说了 2 遍不做笔记，下午我自己跑公园转转去了。\n今天去公园的路上说起果果的学习问题，我说我不想听了，你自己去前面跑吧，我在后面慢慢走，说了 2 遍还在说不想听了，教育孩子那这么多计划，你给她的计划好使吗，你自己的计划完成了没。\n最近压力也大吧，她愁着招生不会和家长聊谈，教育孩子焦虑，我也烦找不到工作连个面试的机会都没，工作真的这么难吗，还是因为看我年龄直接就过了，我招人是这样的，毕竟不想招个年龄大的下属觉得别扭。\n虽说现在还有钱花，可没有进的钱不舍得花，花一个就少一个。\n在公园照镜子发现额头一块一块的黑斑像老头子的，担心了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3334, '9edTThdoK8n2hGXD2ivcQf', 1, '2025-04-29 17:04:37', '2025-04-29 20:42:59', 'NORMAL', '今天是 2025 年 4 月 29 日(周二)，约的今天是去医院复查的上次鹦鹉热的问题，本想和每月一次的复查一起解决的，说病历不写发热，写神经内分泌瘤g1,g2 的敬较真，开检查，开药医生开不明白，提示说什么的怕扣钱不感开，她成就不熟开的慢，慢特选不了的问题着急了，说检查完再来吧。后抽血检查后又挂了个普外的开的，还好看普外很快就好了，再抽血的时候敬把我手机拿走了，用她的手机点开票了结果没有医保结算点了还要排队去窗口搞，耽误了很多时间。回到家 12 点多了，累坏了。\n到家就听我妈说她磕到钉子了摔倒了，跟我们说这些干嘛，即使要说不能在等等吗，刚回来我都累的手抖，自己慌慌张张地，总觉得干不完的活，不知道干啥，之前接接孩子做做饭忙的跟狗，现在还是，受伤是迟早的，我不愿听她说话她自己肯定想的是敬在后面忽悠蛊惑，太了解她了。\n肝功能的结果出来了，有几项高了，发给陈医生，说过几天再复查下，高了就去天津，想肯定是因为最近心情不好，前 2 天还和敬吵架呢，好个屁呀，看我妈那样就烦。\n记得有次洗漱池子下水不流畅，她给下水道管子拔出来，说里面多脏多脏的，跟我们说干啥没话题就不说，我弄过多少次了，我啥也没跟小孩敬说。\n对她为什么没有好的记忆呢，小时候只记得给我们讲谜语好玩，其他真没好的记忆了。小时候皮肤痒，她不给挠说自己困，天生的劳碌命，不想着改变。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3335, 'DaiLrJRtwWdK5mW989GkWZ', 1, '2025-05-01 06:00:00', '2025-05-02 06:39:29', 'NORMAL', '今天是 2025 年 5 月 1 日(周四)，日子过得很快，把电话卡改取消的取消了，广电的卡取消还挺快的，在app 上操作后很快就没信号了，联通的副卡取消还要人审核打电话，当天就通知了说要下个月 20 号前再正式注销管他呢在联通app 上看不到副卡的信息了，就这吧事情搞完了，我妈的手机流量不够就办个 2g 的套餐，看她昨天一天用了 159m，看样子是避免不了的了。\n周姐开了家奶茶店，转让费只要了 2w 元，说是等着急转，太幸运了，我还以为之前 10w+呢，说昨天到 18 点 销售了 5k 多，到 22 点估计更多了，那这估计是大赚的了，可能今天五一的原因人多些吧。\n楼下和娃踢球，球踢到书上了。回家拿跳绳看一个小磨牙在踢，加宝给要过来了，说球是我的。厉害👍\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3336, 'MXbK5oYdCECWynhS3SgXmH', 1, '2025-05-02 06:40:39', '2025-05-02 19:46:29', 'NORMAL', '今天是 2025 年 5 月 2 日(周五)，亚运娃办满月酒，敬开车去那边的，一路平安。真厉害👍\n\n对小区越来越不喜欢了，老年人明显增多了，感觉成了平民窟了，知道我生病的会不会也觉得我影响了小区的形象了。在小区里除了娃们没有什么特别值得我想念的，因为没有想念所以也没那喜欢吧。对于我妈也许不和我爸挤一个床就舒服想念吧。真觉得自己文化水平低脑子里没字，真的之前没听过孩子幼儿时期词汇量的教育也不觉得，知道了反而……\n为什么我说不想听她说话怎么还要不停的说呢，憋的难受，还是压根没听到脑子里去，我觉得是两者都有吧，毕竟我是这样的。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3337, 'ZLiLxZEHyABEnGtj23VrZt', 1, '2025-05-03 22:07:16', '2025-05-03 22:07:16', 'NORMAL', '今天是 2025 年 5 月 3 日(周六)，不知道干什么，听有声书说家庭读书的氛围，想读书只是随便看看，没认真的读过一本书，不如按顺序认真的读，先不给自己明确的计划，累了困了就休息。\n天热了身上不时会被虫子咬到，痒，讨厌的季节。\n看地图看到之前收藏的老家地点，哗啦哗啦看到初中的学校，看大门还是以前的模样，多了几个教学楼，本以为学生应不多的，搜了下 1200，是不是有些夸张了🤔\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3338, 'bEcRAHopSeXRPh2KfKwMPH', 1, '2025-05-05 06:45:57', '2025-05-05 06:47:12', 'NORMAL', '今天是 2025 年 5 月 4 日(周日)，中午去安医检查了，结果很好，肝功能指标高些，比上次在省立测的好多了，心情，吃药都有些原因，\n最近夜里睡觉会醒，好久才能睡着，嘿好讨厌呀。\n敬下午回来了，带着娃从南京开车回来，厉害了我的宝宝。\n又和我妈吵，说没孩子办满月酒，没仪式感，在院子里请吃饭不算，说没钱收入什么的，觉得我妈不会办事每个月给个 2k 不就结束了吗，敬想的应是怕给我姐了，父母想着以后还要指望她呢，闹僵了不行。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3339, '3GzMFsnCLhSENyAJqVMAtS', 1, '2025-05-06 10:12:38', '2025-05-06 10:12:38', 'NORMAL', '急躁是因为经验不够！\n心烦是因为思路不清！\n压力是因为期望太高！\n\n人生就是一场修行！\n苦乐全在心境！\n\n欲成大事先修心！\n欲成大业先立人品！\n\n不代怒气出门 ，\n不带急性做事，\n不带烦恼睡觉，\n\n以清净之心看世界！\n以欢喜之心度生活！\n\n度人先度己，\n度己先度心！\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3340, 'BtAs4C2wYYyKSVsW3q3mv4', 1, '2025-05-08 16:12:01', '2025-05-08 16:12:01', 'NORMAL', '人生感悟\n选妻就是  改命\n攒钱就是  改运\n早睡就是  续命\n读书就是  开悟\n自律就是  破局\n认知就是  出路\n行善就是  积德\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3341, 'JZeZRSd9xdceX6CfvUCw2r', 1, '2025-05-08 16:44:23', '2025-05-08 16:44:40', 'NORMAL', '今天是 2025 年 5 月 8 日(周四)，一中午的时间把图片给整了整，阿里的备份从文件移动到相册了，这样看着方便些，能按日期人物分类，把重复的图片质量不高的删除了。以为图片很多原来才 21k 多张。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3342, '8j7hWVMfo2qxKxnntFDwJg', 1, '2025-05-08 19:44:02', '2025-05-08 19:44:02', 'NORMAL', '以积货财之心积学问，\n以求功名之心求道德，\n以爱妻子之心爱父母，\n以保爵位之心保国家。\n\n—格言联壁\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3343, 'AbBvQ6Uf82oEyzwLjFTToj', 1, '2025-05-09 06:00:00', '2025-05-11 06:31:16', 'NORMAL', '今天是 2025 年 5 月 9 日(周五)， 又开始鼓捣域名的事了，看到有免费的二级域名，还支持 HTTPS 重定向，就想鼓捣下，没弄好，卡在 GitHub 登录上了，需要 verycode ，免费的真的是最贵的呀。\n澳汀的赔偿到了，和澳汀没关系了，就等失业金领取的事了，顺利的话和澳汀一点关系也没了，钱转给敬了，顺便她存吧，她心安。\n果果放学回来，在赵汝飞那换东西。开心说了好多。加加考试关于塞翁失马焉知非福，班级就它一个写对了，开心，忍到妈妈回来才说的，😁\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3344, 'C3zeZN7oxfCZUggshnS5kk', 1, '2025-05-11 06:44:39', '2025-05-11 06:44:39', 'NORMAL', '今天是 2025 年 5 月 10 日(周六)，早上敬送果果去英语课，加加在家吃饭，一会牙疼一颗牙要掉了，嘿说碰下拔下不愿意，不吃就不吃吧，外面刮着风就没出去让他在家下会围棋上个厕所中午就过去了。\n下午去打篮球比赛了，果果要打羽毛球，想去吧结果人很多，想打的话会影响他们就没打看他们比赛了，加加排在最后，刚打一会，看篮球学校的老师和家长急忙出去了，想会不会交警在贴罚单，赶紧也出去看看，他们说有交警巡逻了，挪车也没地方挪呀，想在车里待会有交警来了，车在开走，手机还留着给果果了，让他看着加加，还真有交警来了，开车拐弯停在另一个路边了到下课的时间去接他们了，原来提前 18 分钟放学了，嘿感到自责，晚上敬回家看到她手机有交警的信息提示提示挪车了，嘿执法还是挺温暖的。\n篮球课回来后做披萨比较成功，放南瓜不好了，水份多稀了，分层了。\n晚上他们出去玩 21 点多回来的。\n明天是母亲节还是把我妈当成空气人。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3345, 'dum6Vfd6mscZ6ZLUkp8yhq', 1, '2025-05-12 08:14:01', '2025-05-12 08:14:01', 'NORMAL', '家庭的第一原理是经济而不是感情\n职场的第一原理是功劳而不是苦劳\n人脉的第一原理是资源互换而不是卑微讨好\n爱情的第一原理是筛选而不是培养\n健康的第一原理是自我管理而不是医疗\n养老的第一原理是金钱而不是依赖子女\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3346, 'VUHQPBQQyrzMtqAQ2GE9Jk', 1, '2025-05-12 21:53:48', '2025-05-12 21:53:48', 'NORMAL', '今天是 2025 年 5 月 12 日(周一)，失业金的审核过了从 6 月份开始 有 22 个月，应该是 2027 年的 4 月份了，还不错，有 1800 块的收入，比前几个月还多些😂\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3347, 'EJsjdgi3pjWBnakNhdV4Jz', 1, '2025-05-16 17:59:13', '2025-05-16 18:02:42', 'NORMAL', '今天是 2025 年 5 月 16 日(周五)，前几天整网页了，学了 coderedcms 觉得挺好的，只是之前不会用，真的是在在后台就把网页弄好了，当然也要改开发了要写 css ，之前没找到门路，没怎么休息。\n618 快到了，之前想买个电脑的后决定不买了用 vscode 开发挺好的，再不行用cnb.cool 在线开发也不错的，不开发 android 就用不着电脑，web java 就用 vscode ，要买个空调把果果房间的给换了，净水器双 11 再说吧，看有没必要换。\n今天本想把果果房间的网络给搞下的，加个路由器发现不好用，连上后提示无法连接互联网也是搞郁闷了，路由器放到大房间就可以，是因为网站太远了吗，嘿真是的瞎折腾，也没弄好，回来再说吧。那天忍不了再说吧。\n我妈接加加烧饭火没关，我以为她在炖什么，我也没管，她回来送胡了，确实我也闻到糊味了，说她忘关了，也没说我怎么不看着，嘿母子的关系怎么这样呢，太关注反而会失去。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3348, 'i3chnCNiAY2akyuopycpre', 1, '2025-05-17 21:43:55', '2025-05-17 21:43:55', 'NORMAL', '大学生为什么\n进不了央国企\n因为他们连发布央国企\n招聘信息的平台都不知道\n1.国聘网\n2.中国公共招聘网\n3.24356就业服务平台\n4.国资小新\n5.央国企官方网站\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3349, 'GAR2pUcMSKjgVubxprQmU6', 1, '2025-05-17 21:52:58', '2025-05-18 15:01:58', 'NORMAL', '今天是 2025 年 5 月 17 日(周六)，过得好快呀，马上就 6 月份了，失业一年了，嘿真是去年 6 月份生病，今年 6 月份拿失业金，\n中午去接果果英语课去安粮小区打乒乓球，跳绳玩到 快 12 点回去了，和加加一起打乒乓球好厉害最高记录能来回打到 18 个🤩。\n吃过饭，中午打乒乓球觉得好热回来把风扇给装好了，困了睡了果果也睡了，加加用平板下围棋了，睡了一个小时。\n敬今天要好晚才能回来，试听 21 点 40 才能回来到家 22 点多了吧。\n今天一天左肩胛后背酸疼，头上的疙瘩也多了，最近大便是不太好了，干还不多，之前有次能拉个 2 斤的，心里想着事买空调，还有做公司官网网页的事，嘿怎么能通便，要学习了，这两天水喝的多了，没事出来逛流出来喝点，前 2 天在电脑旁做好久不喝点，看样我这心态还是不能上班，太心急了，太负责了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3350, 'R7bZjRFf97L58WuGMJX8kP', 1, '2025-05-18 15:01:17', '2025-05-18 20:54:25', 'NORMAL', '今天是 2025 年 5 月 18 日(周日)，晚上睡的很好，夜里也没醒，醒了也很快就睡着了，脑袋上疙瘩，想和大便有关系一早起来就上厕所拉了，想这个点拉挺好的，不至于和他们抢。\n中午把加加桌子擦擦，我妈就知道擦门不想着把缝隙桌子擦擦，\n说有个快递她买菜让她去拿，要接孩子了，回来时带着孩子门去拿，真会想自己去拿不行吗，打卡什么时候拿不就可以了吗，浪费娃们的时间，他们那那么多时间浪费呀。还没拿到他们没找到，找快递员快递员在筐子里找到了，就这出事了，应该让快递员送到家的，这样就不内耗自己人。\n把信息发给敬想让她下班回来拿的，买了自己午饭吃的粉丝不拿，我是想着在筐子里时间长了又找不到了麻烦心烦，想让她上班从哪里走时拿带着，说不顺路，不拿。我不开心她就在那叽歪，不想见她非跟着要问个明白，我很生气其实很生气的是她的态度，说不想见她，就说要离婚，说出了我最害怕的，就像这话不能从她最嘴里说出来，就想要离婚不能从我姐嘴里说出来一样，这是对我放弃的节奏呀。\n想明白了，这次也是个引子吧，至少知道她能顺口说出离婚的话，口从心出，她肯定也有这么想过，气话才是心里话，看事情清楚着呢。一个簸箕坏的值得。\n之前我好好的，她都不愿意拿快递都是我在拿，这时更给她找不愉快了。\n之前吵架生气都她跑，现在是离婚你走吧，真没有她了我怎么办，钱都给她了，我住那，靠父母吗，她留着心眼存钱，这个阳谋怎么办，娃们怎么办。为这湿润了眼睛👀\n想到了成语 老有所依，我这年龄轻轻的就没了依靠，靠不住，首先一家人和和气气就难了，再说和她还能是一家人吗？\n脾气变的好大，烦躁。之前很少发脾气，以后孩子会变成什么样成为什么样的人，不要焦虑，可她焦虑。\n我上班我带娃，不上班还是我带娃，周末见不到人影，平时下班回来也晚没人影，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3351, 'SacDiRUFDjEg6nZG7BQVKc', 1, '2025-05-20 11:51:56', '2025-05-20 11:51:56', 'NORMAL', '今天是 2025 年 5 月 20 日(周二)，昨天敬去医院拿药了把一年的依维莫司拿了，赶到澳汀的补充医疗保险还能报买了。骑电动车去的 1 点多才回来，说有 9 个人等了 2 个小时。\n前 2 天左肩膀疼，今天发现不疼了😏，开心，今天走了走发现是左腿膝盖的地方疼，愿早点好起来吧。额头的疙瘩也快点好起来消失吧，大便正常起来，最近好干还不多。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3352, 'QDoXn9L3bWMQq6WE2ubpRi', 1, '2025-05-20 18:44:02', '2025-05-20 18:44:02', 'NORMAL', '1可怜之人必有可恨之处？可恨之人必有可悲之等。\n2天地不仁以物为空豹圣人不仁以百姓刍狗\n3.未经他人苦莫动他人善，你若经我苦未必有我善?\n4书到用时方恨少，事非经过不知难\n5.以德报怨何以报德，以直报怨功德报德！\n6.酒肉穿肠过佛祖心中留，世人若学我如同进魔道\n7. 百善孝为先论心不论远轮迹寒门无孝子\n8.万恶淫为首论迹不论心，论心世上无完人\n9.不尝世间醋与墨怎知人间酸与苦\n\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3353, 'noMASTJbon7WS36nkXhAMk', 1, '2025-05-26 10:27:15', '2025-05-26 10:27:15', 'NORMAL', '今天是 2025 年 5 月 26 日(周一)，因为性生活的事吵架了，生气时说的真心话看个丑样子黑的，这是嫌弃了，和她还能生活多久，永远不会想自己的问题，经过这个注定一生不会再有性生活了，经历上次不会再网购了，觉得好绝望呀，我的生活还能更好吗，还不到 40，\n其实之前都想明白的，大家都没有改变，再生病会是必然吗。\n真的若不是和她生活我的生活应该不一样，\n想在德清看别人骑电动车都觉得羡慕，也不觉得怎样。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3355, 'bodAUzZ2rxmfuspmrZZxNw', 3, '2021-06-02 11:13:15', '2025-05-26 11:13:15', 'NORMAL', '今天是2021年6月2日周三，发烧了，昨天我和妈妈云医院了， 小汽车都不想带我们去了，妈妈去了，好几个医院，妈妈好累走走我就说想吃面包了，走着妈妈的电瓶车就没电了\n\n#日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3356, 'NSwT46kAozKzVeHND6MSkN', 1, '2025-05-27 10:53:51', '2025-05-27 10:53:51', 'NORMAL', '今天是 2025 年 5 月 27 日(周二)，想明白一件事为什左腿膝盖疼了，打麻药打在左腿上了，估计和这个有关系吧。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3357, 'Zvk5pHd3AwakmAVbroesEm', 1, '2025-05-29 17:49:10', '2025-05-29 17:49:10', 'NORMAL', '本人程老虎，现神志清醒，身体状况尚可，为防止身后因财产继承问题产生纠纷，特立此遗嘱：\n本人名下房产存款等财产归 2 子女程明月，程旭阳所有。\n程老虎 20250529\n致父母，感谢你们含辛茹苦的把我养大，供我读书买房，花钱给我看病，我还是决定把仅剩的遗产留给我的孩子，从毕业 2008 到 2024 年，16 年的时间里 2013 年之前工资只 2000 左右勉强生活，之后生活好转也就 10 年的时间存款也不多，养娃房贷车子看病不小的花销。为了孩子未来都让王矩敬他妈来带吧，她若给娃改姓就改吧，我大姑也是这么过来的。原谅我不能给你们养老，只能靠姐姐了，辛辛苦苦一辈子希望你们能多疼爱自己些。\n\n致妻子，不能陪你白头了，再嫁孩子改姓没意见，只希望你能抚养他们长大。嫁给我是你的不幸，对不起。\n\n致子女，对不起没经过你们的允许把你们带到世间，爸爸陪你们的时间稍微短了些，希望你们能健康快乐衣食无忧，愿祖国繁荣昌盛百姓安居乐业，你们以后也会有自己的家庭，希望你们能和睦相处，家庭幸福。做人的智慧我也不会，所以也没什么好教的，不过一点是对的要有自立的资本，假如那天觉得另一半和不来果断些，有生存的能力。爸爸还想着以后能给你们带娃分担些呢…真希望能看到那个时候，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3358, 'R4DV3diH2HQ34ESY6bpPCe', 1, '2025-06-01 18:10:42', '2025-06-03 11:40:52', 'NORMAL', '今天是 2025 年 6 月 1 日六一儿童节，一早我妈就座车回上虞了。走时还想着我不要担心什么的，知道是关心我不想让她太关心，也稍微关心下自己，俗话说老了还想要个娘呢，是真疼。\n昨天端午节今天儿童节一直的下雨嘿，好好的假期就这样耽误了 2 天，\n17 点左右敬带 2 个娃去万象汇玩了，吃的龙虾，烧鸡挺开心的😍\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3359, 'LthdxwEkM3NXphno9ES5NP', 1, '2025-06-02 10:30:00', '2025-06-03 11:37:14', 'NORMAL', '今天是 2025 年 6 月 2 日(周一)，一早去安医检查了，上个月开的b 超单子开错了，做b 的不给做，去医生那开了 2 个b 超单，今天做一个下个月再做一个，开错的单子也退了，折腾了一圈，11 点左右到家了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3360, 'Am46c2TKbbKouE8K6o8LFb', 1, '2025-06-03 20:57:34', '2025-06-03 20:57:34', 'NORMAL', '今天是 2025 年 6 月 3 日(周二)，我妈回去 2 天了，给她打电话说腰疼，嘿是在家干 2 天活干的吗，一年没干过弯腰的活了\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3361, 'hv9PANdu7HVuKcitEJ3Las', 1, '2025-06-04 15:46:10', '2025-06-04 15:46:10', 'NORMAL', '今天是 2025 年 6 月 4 日(周三)，计划预约回收电脑，空调的，空调收走了，笔记本回收不要😏，嘿那天看到旧手机的给他们吧，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3362, 'KyM4DHmuXrbw2zivjeoRPr', 1, '2025-06-05 11:30:00', '2025-06-06 12:59:54', 'NORMAL', '今天是 2025 年 6 月 5 日(周四)，要去学校参加家长半天活动看孩子们上课，果果不想让我去，我也不是很想去，敬直接给我报名了，怎么想的呢不考虑我们，最近腿有些疼不想打羽毛球，还是要我去，她是关心我吗，学校吃午饭时回来了，吃点面休息了，觉得她让我吃面是正常的。\n下午接加加回来带他去理发了，洗澡吃饭，\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3363, 'kKPusEwLZCivUZSiPn8R7T', 1, '2025-06-06 11:30:00', '2025-06-07 12:49:44', 'NORMAL', '今天是 2025 年 6 月 6 日(周五)，中午把电动车修了下支撑太重了，怕时间长扭脚了，前几天就说修的到哪就喷点润滑油是轻一些了，没收钱。\n在楼下看到一大爷收废品，问他收不收电脑说完，说收，说一会拿下来，他去楼上收了，去楼下等会没等到把电脑放在他车子上了，拜拜了看着闹心，\n接加加时去楼下看京东的车子来了，问问有我家的，和他一起上去了，送到家来了，送加加去写字课，到家没多久装空调的打电话说一会过去装，说一套快，就等了因此接果果还晚了会。收了室外作业费，铜管加长费共 150 元，把前几天洗空调拆的烟也给他们了，才便宜这些的，\n做凉皮做了好多给我累坏了，很成功，就是叠在一起会粘。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3364, 'L6VRL5rt3hBwHd7enn5nAn', 1, '2025-06-09 19:21:05', '2025-06-09 19:21:05', 'NORMAL', '今天是 2025 年 6 月 9 日(周一)，敬今天休息本是可以开心的一天，娃们上学时下着小雨送去后没出去打羽毛球，敬在家收拾屋子果果的房间收拾一上午。下午带加加去医院看加加走路踮脚尖的问题，晚饭说炒面的也没吵。\n\n接果果回来，到家就生气的哭了，给她屋子收拾的笔找不到了，敬回来知道凭她的脾气不会好好道歉说的会把人顶回去，这不是帮收拾的问题是帮做决定自作主张不尊重的问题。我妈希望家里能说说笑笑的，她实现不了，我也这么希望发现也实现不了，家和万事兴太难了。\n\n他们回来也只能吃饼喝豆浆炒面也没人炒了，弄个啥呀，天天家里没啥菜吃，过得啥日子，天天上班上的啥班，从 19 年左右上班周末就不能在家好好过。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3365, 'AVR2oU85evUHP8KoKY5Aeh', 1, '2025-06-17 21:13:05', '2025-06-17 21:13:05', 'NORMAL', '今天是 2025 年 6 月 17 日(周二)，很热的一天，34°C\n送完娃们后去公园打羽毛球，昨天因为有很多蚊子咬的原因穿了长裤，结果胳膊手被咬了 2 个包，蚊子实在太讨厌了。\n敬回来收拾带个粽子就去上班了说今天有事要早点去，\n10 点多睡着了，现在睡觉一会就醒了，虽然也是 2 觉没以前睡得时间长，以前能睡近 2 个小时起床迷迷糊糊懒洋洋的状态感觉很舒适。\n下午把记日记的标签给弄好了，感觉编程能力退出了很多。可能以后再也不会从事开发的工作了，闲了那么久慢慢都不想工作了。\n果果今天英语课，敬说今天下班早，她去接的，回来说头晕感觉要中暑了。\n快暑假了想着暑假带不带娃们出去玩，看车票即使他们 3 来回路费都不少呀。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3366, 'BGpacqpHbUaA3BDoiLdLqx', 1, '2025-06-13 20:00:00', '2025-06-17 21:16:00', 'NORMAL', '今天是 2025 年 6 月 13 日(周五)，最近在听斗罗大陆的音频，有时间就听迷上了，一周下来也听够了，虽然还有很多集没听呢，没那么急躁要很快的听完了，睡觉也会定时关闭听完一集，不至于睡着了给吵醒\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3367, '4QdjFHhFeDC6DseJ3DtZRD', 1, '2025-06-15 21:00:00', '2025-06-17 21:40:44', 'NORMAL', '今天是 2025 年 6 月 15 日(周日)父亲节，真的没啥感觉，加加书法课老师搞了个抽签，最帅的人抽，签的内容有，\n一家之主，\n宇宙第一，\n爱永不止，\n一生相伴，\n应是老师让他们写的，我家娃应想不到这些成语，美好的愿望。\n伊朗和以色列打起来了，嘿之前怂了那么久还是被削了，愿世界和平。中国和平。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3368, 'aXVtdcJSAZRiPmLzdbM22A', 1, '2025-06-18 21:17:38', '2025-06-18 21:34:47', 'NORMAL', '今天是 2025 年 6 月 18 日(周三)，又是大热天，敬那边确认了 7 月份啊放假，要 8 月份才会，\n下午吵的菜放辣椒，辣了娃们没怎么吃，我也没怎么吃。难过\n晚上我妈转 2000 不收了，算了，他们留着吧。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3369, 'R3tRo37PrHBp4v5HiEuidd', 1, '2025-06-19 09:17:40', '2025-06-19 09:17:40', 'NORMAL', '为什么越是一些低端的家庭就越穷\n简单呀\n因为低端的家庭个个都是倔种\n家人之间不能好好说话\n一说话就抬杠\n一闭嘴就说你的不是\n生活中的任何小事\n都能出发敏感的神经\n沟通成本极大\n解决问题的能力又很低\n动不动就甩脸子\n一点小事就大发雷霆\n每天在家里持续的窝里斗\n就指望着孩子有出息\n殊不知\n当人家上下三代都在齐心协力\n为了共同的目标一起努力\n而你们家却无休止的内耗\n你怎么拼得过别人\n你的孩子怎么会有出息\n父母是这样\n孩子也是这样\n根本不可理喻\n如果意识不到这一点\n一边摧残着家人\n一边还指望着家人\n最后只会把家里弄的乌烟瘴气\n\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3370, 'T9diWEkUV63ydMK4tepJ4F', 1, '2025-06-19 09:18:28', '2025-06-19 09:18:28', 'NORMAL', '1可怜之人必有可恨之处？可恨之人必有可悲之等。\n2天地不仁以物为空豹圣人不仁以百姓刍狗\n3.未经他人苦莫动他人善，你若经我苦未必有我善?\n4书到用时方恨少，事非经过不知难\n5.以德报怨何以报德，以直报怨功德报德！\n6.酒肉穿肠过佛祖心中留，世人若学我如同进魔道\n7. 百善孝为先论心不论远轮迹寒门无孝子\n8.万恶淫为首论迹不论心，论心世上无完人\n9.不尝世间醋与墨怎知人间酸与苦\n10.久病家中无孝子，久贫家中无贤妻\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3371, 'GJmYbesN938sCXxhvWWxhW', 1, '2025-06-19 09:19:46', '2025-06-19 09:19:46', 'NORMAL', '为什么我很怕麻烦别人，\n哪怕是我的爱人，\n哪怕是很合理的要求,我也会很不好意思。\n心理咨询师一句话破解\n因为从小你的合理需求\n就没得到应有的尊重和接纳\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3372, 'UhTk3AsURTSmBwTezji8FJ', 1, '2025-06-20 06:00:00', '2025-06-21 07:15:32', 'NORMAL', '今天是 2025 年 6 月 20 日(周五)，加加今天考完试就放假了。\n送果果上学，送娃上学觉得自己价值更高了，敬送的加加之后，去公园了。刚去时还没下雨，走到那边准备回来就下雨了，一会大一会小的，跑一会到一个地方休息下，陆陆续续到家了。\n回来冲个澡，敬送中午不去了，给我们烧好了饭，下午烤好溜肥肠， 15 点就去准备接加加了。到那边车已经拍成排了，这是这么多人没上班吗，16 点 15 裹 2 根肠去学校接加加了，昨天让进学校接的今天也应该是，去到他教室还没放学呢，到赵汝飞哪里把烤肠吃了，我去车里等了。把车往前挪点走时能近些，接到果果在车里吃些，他要去接加加说去换东西，结果有新的奖品积分不够了，嘿。\n到家烧汤，蒸米饭，走时淘好了忘记蒸了，还没蒸好敬就回来了，我先吃，果果在上数学的网课。\n明天要抽车位，用楼下一家的房产证物业费快到期了让交不交不给报名，说和物业沟通吵。她来我家，敬和她去外面说话，原来她老公去年就走了，肝癌\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3373, 'f83kMJYWssSx3ZCxtoWTu5', 1, '2025-06-21 05:30:00', '2025-06-22 06:40:41', 'NORMAL', '今天是 2025 年 6 月 21 日(周六)，抽车位我说去敬说人多她要去，没抽到，经过人介绍给了个，\n最近口腔溃疡好疼，夜里能疼醒，上次也是疼了一周，怎么才能缓解呀，\n下午果果说要出去和她同学一起，没精打彩的就同意了，在生鲜传奇被她妈敬看到了，嚷一顿回来了，觉的不能老和王玩，玩野了，说是和她一起会不会中间见别的人，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3374, 'QoSSrgre3M6TL2eJ6L5nPK', 1, '2025-06-23 18:05:23', '2025-06-23 18:05:23', 'NORMAL', '今天是 2025 年 6 月 23 日(周一)，果果开始期末考试了，只中午连续考 3 天，加加好棒，我去接果果他说在家里也不怕了，上次他在家有人敲门他害怕，经历过一次反而胆大了，不是会留下阴影。\n下午加加英语自然拼读也开课了，\n我口腔溃疡还没好，痛苦呀，睡觉都能疼醒，昨天还有口水，把垃圾桶拿到床旁边醒了就吐下，早上实在不想起，敬 6 点半 起来做的饭。左边的额头附近偶尔会觉得疼下想针扎一下似的，好担心呀，之前周末带娃时也偶尔觉得这样，前 2 天觉得腿酸软，带他们去公园不到桥那里走不动了，还是要多休息呀，上周听小说白天虽然睡睡一会就醒了，凡事不能急，听到最后他说录这个音频前后花了 2 年的时间，是呀 1100 多集，一集 10 多分钟不是简单的事呀。最近一直在想活的好痛苦，不是活的好累。\n加加咳嗽 2 天了，最近天气不好，转凉了，夜里睡觉冻到了或者淋雨了，早点好起来吧。\n失业金到账了，开心，1854 元 不管怎么样有些收入了，最基本的吃饭够了。\n我妈今天打视频过来，在地里干活，脸垂直方向基本平行了，脸上没肉，还说自己胖，没说啥看我好好的就挂了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3375, 'dXRgMq3uPPNh3UwjDfv67c', 1, '2025-06-25 10:08:48', '2025-06-25 10:08:48', 'NORMAL', '世界上著名的五大学习法\n1.费曼学习：把你学的东西，讲给\n别人听，如果能讲清楚，就是学会了。\n\n2.西蒙学习法：确定学习目标，拆分\n学习目标，6个月就能精通任意领域。\n\n3.SO3R阅读法：浏览、提问、阅读、回\n忆、复习。\n\n4.香茄学习法：规划学习和休息时间\n，二十五分钟为一段，定闹钟。\n\n5.康奈尔笔记法：记与学，思考与运\n用相结合的方法。步骤包括记录、简\n化、背诵、思考和复习五步。\n\n\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3376, 'AFp6vPpmKkZ27ML72Li3kT', 1, '2025-06-26 09:25:05', '2025-06-28 12:01:11', 'NORMAL', '今天是 2025 年 6 月 26 日(周四)，口腔溃疡还在疼，嘴里的一个还没好，在上嘴唇又长了一个，痛苦呀，这次一定再问问医生怎么能缓解些疼痛。头有时也是会阵痛，真的很怕会复发呀到底怎么回事呀，脸上的疙瘩还没好没有特别大的也没那么疼，浑身没力气没精神。\n\n下午李鹏飞过来了，送了些鱼就走了，敬回来商量下把鱼扔掉了不知道在那钓的，有没污染，他老婆也来了，不知是不是不放心她才跟来的。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3377, 'W3NUKRWmtRhydYKYNj97Ge', 1, '2025-06-28 11:58:49', '2025-06-28 11:58:49', 'NORMAL', '今天是 2025 年 6 月 28 日(周六)，头晕阵痛的症状好些了，左边的口腔溃疡好了些，右边感觉要长了一个，吃饭不怎么受影响了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3378, 'Aa7cwfZGp2J59X4h5WjoAC', 1, '2025-07-03 21:46:34', '2025-07-03 21:48:55', 'NORMAL', '今天是 2025 年 7 月 3 日周四，早上果果起床跑步去了，我在家拾掇着那的，加加不愿意起床，很晚才出去锻炼的。\n又是忙碌的一天中午送他们去赵汝飞慌慌忙忙的吃饭去送加加上英语课回来送果果上英语课，在家没睡着，15 点 10 分接加加接果果，他们吃了冰棍，买些鸡蛋准备晚上炒蛋炒饭，买些冰淇淋放家里，备着吧。\n昨天去医院泰康报了报了 3640 多，不对呀，光 petct 一张就 6000 多了，那张没医保报销不知是不是这原因，下次去结算完了再说吧。不能耍小聪明，万一不报就亏大了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3379, 'WUuq6GKwBwvMEWRtPpAqvT', 1, '2025-07-01 20:30:00', '2025-07-03 21:47:13', 'NORMAL', '今天是2025年7月1日周二嗯，果果第一天起早起，和同学一起跑步，虽然起的有点晚了，他说他同学6点钟在草原集合，她 6点 20 才起床，加油慢慢就起来了。\n加加不愿意起床。然后我就自己出来，在公园里小河旁边溜溜了，\n昨天看了，嘴巴里面有3个口腔溃疡的泡，哎呀妈呀，疼死了，明天要问医生怎么才能改善些。\n过得好快呀，感觉刚抽空车位，今天就要挪车了，感觉我好笨像网上说的没有解决问题的能力，若我的话车位估计就解决不了，家里面内耗。\n\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3380, 'nJyGtZfLUQxoAuuCy4bAmv', 1, '2025-07-17 06:26:08', '2025-07-17 06:26:08', 'NORMAL', '今天是 2025 年 7 月 9 日(周三)，果果今天去看牙，补了 8 颗，中午没补完，下午又去的没回家，在旁边吃的逛了会，我和加加在家。\n今天加加只有英语课还好了比较轻松，\n果果回来没吃饭在房间看会书睡着了，吃饭也没醒，给她盖被子，敬回来后想她就在那睡吧睡到明天好了，进房间把空调的温度调低些，一会她醒了出来了。\n敬带加加爬楼梯说是能练习脚根的肌肉，矫正他踮脚走的习惯，回来后买了些卤菜吃的，虽然没钱还能偶尔改善下生活\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3381, 'VuHXeg3eyVJLBhAgzN2RYw', 1, '2025-07-17 06:28:39', '2025-07-17 06:28:39', 'NORMAL', '今天是 2025 年 7 月 14 日(周一)，敬带果果补牙，说要住院拔牙，有 2 颗智齿没长出来，才能纠正，嘿又要跑多少趟呀，幸好那里停车方便，不收停车费。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3382, '62bZ5B74v9H3N3N7yfkuAd', 1, '2025-07-17 06:35:45', '2025-07-17 06:35:45', 'NORMAL', '今天是 2025 年 7 月 16 日(周三)，去安医做 petct 了，第一个做了 2 遍，说是对比，等到 10 点半了才做好，回家敬下午还要上班呢，\n说好了在家和娃们保持距离，吃饭都是敬送过来的。\n\n在家把保险提交了，没一个到位的，等明天看泰康能否给钱吧，月初提交个没结算的，算了下应该是只赔偿了 60%，从新提交发票号也不一样了，看他们怎么弄吧，能把剩下的给我就好，没检查还不能开结算的票，系统不能智能些吗？\n\n晚上去公园逛，还挺能走的。走到大草坪也不围起来了，草也剪了剃头了，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3383, 'HyUhgrhoK6pvxgurQbaQ6i', 1, '2025-07-17 06:37:52', '2025-07-17 17:55:16', 'NORMAL', '今天是 2025 年 7 月 17 日(周四)，昨晚很晚才睡着，过点了就很难睡了，真是的，夜里还做奇怪的梦，居然把l 想象成男性，平行世界的他。嘿\n11 点多看了昨天的报告，情况不好，说是多转淋巴结，脊椎骨有问题，下午去拿报告去了，带给陈池义医生和敬说有 3 出癌，目前没什么感觉，也不当回事，可是安静下来一个人的时候就怕了。\n泰康的要寄发票，花了 8 元嘿真是的还不知明天能不能报呢，澳汀的补充居然还报了 80 多，嘿真好报一点是一点吧，惠民保应该是没戏了，太坑了门坎太难满足了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3384, 'SCmRZv3e8xNhfXYbSUAxpv', 1, '2025-07-21 10:58:32', '2025-07-21 10:58:32', 'NORMAL', '今天是 2025 年 7 月 21 日(周一)，果果开始上数学课了，加加被妈妈拽走去校区了，在那写作业去了，我在家睡了会，去接果果了，回来把加加拉在英语课的水杯拿回来了，放了快一周了，嘿。\n把 petct 的报告发给省立医院的肝移植的医生看了，还没有回复。\n天津上海的都没有回复看样子没那么简单了，不是吃药化疗能解决的了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3385, 'NbK7A9m4i9SFx3hkFpQEaZ', 1, '2025-07-22 16:51:00', '2025-07-23 16:51:00', 'NORMAL', '今天是 2025 年 7 月 22 日(周二)，果果忙碌的一天，中午数学书法课，下午英语课，看最近的要交的保单，近 4w 呀，好多呀，这真是在不停的花老本呀，我这还有 10w，到时候取个 2w 多吧， 不知敬那还有多少能坚持多久，明年如果王先峰说不挣钱把钱还了后面该如何挣钱呢，\n我还很担心自己，上海陈洁回复了句没用的话，还是助理回复的极其怀疑是故意的要不几天后问诊费就要退了，天津陈池义那边还是一直没回复，等的好着急呀，真担心他们觉得没得救了，怕面对家人\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3386, 'nPZ7vivgE9D4mJpu4DbNEs', 1, '2025-07-23 16:56:28', '2025-07-23 16:56:28', 'NORMAL', '今天是 2025 年 7 月 23 日(周三)，敬今天很累没起来我送的果果上英语课的，还走错路了😂。\n最近睡的时间不长了，有时 10 多分钟就醒了，想起之前在德清没钱的日子，去 atm 机，看工资到账了没有，今天也是在迫切的等着失业金的到来。不管怎么说终于到了。\n\n最近说广东那边蚊子传染疾病挺严重的，说那种蚊子安徽地区也适合它生存，好担心，就怕在出现一次大流感抗不过去。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3387, 'mYgUJ4fEiz44XRsgxa9EkJ', 1, '2025-07-26 09:54:49', '2025-07-26 09:54:49', 'NORMAL', '今天是2025年7月25日周五，早上加加在家想试试能不能把手机号过户给他，一个客服居然办好了，下午果果回来想把另外一个手机号过户给果果说年龄不还没法办理，我居然说中午办了一个了，嘴贱明明知道是不可以办的非嘴贱说下这下好了，对方查了后说稍后回复结果打电话说来说要把加加的那个更改撤回，嘿笨。知道违规的办好了就别讲了呗。后想明白了，办个啥呀，娃们大了愿不愿意用你的号还不知道呢，再说有钱了也不停在乎那点月租啥的。以后说不定政策优惠怎么改呢，他们说不定不稀罕呢，我觉得他们用的手机号接近他们说不定不喜欢呢。\n敬说上海陈洁回复了说去上海一趟，计划看周三的号，好折腾呀，她小姨又要来了，\n周一去安医测下血样浓度，周二的结果都应该能出来，\n准备上海的居住证办理，看小程序随申办可以办理居住证了不知道能否审核通过，愿一次过吧，说是不办报销的比例低些，能过最好吧，不过反正泰康也能报掉。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3388, 'hZZDLWGii8AYyMnRJpauYV', 1, '2025-07-29 19:35:09', '2025-07-31 13:31:43', 'NORMAL', '今天是 2025 年 7 月 29 日(周二)，\n这 2 天一直在幻想一件事回到高中时代报志愿时代。假如回去了怎么挣钱，买房，阿特币，以太币，股票，京东，小米，阿里，byd，宁德时代，嘿还想到一个问题这些是没法一下变现的，还是要想办法搞到第一桶金。没原始资本上面说的都没用，还是要实体经济才能积累，教培，家居建材，装修。还有感情的问题。突然想很多穿越剧不就这样的吗，他们那些作者也是不甘心吗，只是他们把不甘心写成文字短视频之类的，如果能记下彩票号码那就更方便了😁，赞也。\n中午睡不着，最近日记的应用很慢，想排查下原因发现是有个js 文件很大，想加个缓存整了快 2 个小时。下午张说做个代理，本是很简单的工作整了好几次，觉得挺笨的。\n果果来月经了，13 周岁了，好快呀。\n晚上座车去上海了，愿没什么事，吃点药就好了，做的卧铺去的，虽说是方便 8 点到上海 10 点多应该能到医院刚好，可总觉得消费降级了，真的中产返贫了，想刚来合肥的那些年，在德清过的，生孩子时只有 1w 的存款。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3389, 'TFZoXVQFCyCceYoLAEnWn7', 1, '2025-07-31 13:58:52', '2025-07-31 13:58:52', 'NORMAL', '今天是 2025 年 7 月 30 日(周三)，\n8 点到的上海站，做的地铁到医院的，下地铁天气不好打的去的，之前有人要在外面要材料，这次是在另一个房间里了，我还纳闷呢怎么会叫到我的号，去房间说医生还没来，原来是另外一个录资料病历的房间郁闷了，还是看时间差不多了敬去旁边了才进去录的，资料录进去后，看了看说去做个 CT 又跑了好远去的 11 点多了，想早点一天搞完，下着雨就打车去了，结果我两个都晕车了，我是干呕吐不出来，敬吐出一些头晕难受，想想也是一天没怎么好好吃东西了，早上就在车上吃了馒头和鸡蛋，\n到那边衣服鞋子都湿了觉得好冷，辛亏敬带了衣服我换上把袜子脱了，门口有装雨伞的单子套在脚上暖和一些了，爬着睡着了一会，单子开好后，休息了一会才去做检查的，检查很快，之前做ct 要 10 多分钟的这也就 2 分钟就结束了，设备新些的原因吗，这边医院是和医院联合的，说那个医院能看到结果手机上也可以，\n头还晕下着小雨，走这做地铁了，到医院附近的停车口骑自行车去的，下着小雨。\n到医院说在屋里等着，说依维莫司加量，说肝移植只是治疗的一个阶段好了后还是要回来的，她说的挺对的，我还以为移植完就结束了呢，这样也好，能有个医生一直跟踪着，了解情况就算给医学做贡献了吧，\n18 点多了在楼下罗森买个烤肠吃了没其他吃的了，看看票硬座也没了，到苏州有座位先买到苏州的了，在车站等了好久 23 点的车，敬吃了泡面我吃个苹果还是晕乎，进站台就问列车员说补票的在那 8 车厢，就去了里面挤的不行了我和敬说我先去座位那个，下车跑到 3 车厢了，手机还没电了，收到短信说补票卧铺了给敬电话就挤过去了，3 车厢走到 16 车厢和敬一起过去的，说补卧铺的也没人管，敬补的无座敬挤在另一头也睡着了，一夜睡的好好。\n做慢车的人还是很多的，还是有不少穷人呢，我也是呀，消费降级，返贫虽然不愿意听到事实摆在眼前了，在车上还说之前还小康水平。\n真是幸运的一天，虽然很辛苦把事情做完了，回来还睡着回来，在幸运幸福了。感谢宝宝，感谢给予帮助和善良的人们。\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3390, 'Mpz7o4dekiaL9wRuR4y7Kp', 1, '2025-07-31 14:03:06', '2025-07-31 14:03:06', 'NORMAL', '今天是 2025 年 7 月 31 日(周四)，回来的路上做地铁又晕车了，干呕，幸好是快要下地铁时，手机有个孩子，应该是放雨伞的不记得什么时候一直在口袋里了，下地铁两个厕所，我发现我晕都想上厕所蹲会拿点出来。\n骑共享电车回来的，我手机彻底开不好了机了，到家洗澡睡觉一会睡着了，睡了好几觉，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3391, 'CienHTf6qXE7JaUUKMrPSa', 1, '2025-08-01 08:21:08', '2025-08-03 09:36:06', 'NORMAL', '今天是 2025 年 8 月 1 日(周五)，时间过得好快呀，天天不干什么事，8 月份花钱大户呀，车险，寿险，还有理财的。\n受台风影响最近在下雨，阵雨，天也凉快了，\n\n加加早上 10 点多才起来，8 点多叫不起来，敬和矩亚发传单去了，我也跟着睡了，闹钟响了接果果才醒，我自己开车去接了，怕她放学晚故意晚去了会。回来桌子上有个饼果果说可以吃吗，加加说我要吃，果果给分点就切留一点，说果果不疼弟弟，想我小时候也是这样，真不希望他们大了能互相关爱帮扶。\n\n敬带回来个消息本来不想说的，我大伯去世了，想家族什么时候能兴旺呀，之前是出生，生应该暂时告一段落了，开始去世了，我还有多少时间呢，对未来的事情不要想那么多吧，也控制不了，珍惜当下每一天才是最好的。\n\n晚些我妈给我打电话说不让我回去了，明天我爸姐张恒回去，应该是张开车回去吧，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3392, 'D8kpGk2aouwGmi4kSsLofH', 1, '2025-08-03 09:41:37', '2025-08-03 09:58:47', 'NORMAL', '今天是 2025 年 8 月 2 日(周六)，我的生日，39 了，这下病历上应不会再写 38 了，对这个病好焦虑呀。\n\n今天想明白件事，矩亚不仅会嚷他自己小孩还会说加加果果，刚开始还不开心，一下想明白了疼你关心你才说你呢，要不才不管你呢，不像我对王毅扬不搭理，不老实，不懂事，咋咋呼呼的，他父母也都不这样呀，为啥他那么大的精力爬来爬去的。\n\n晚上出去玩问敬个问题，她家族三代是下坡的，为什么出在她爸妈上，她爷爷是教师他爸爸弄个开食堂的，弟弟又不能维持收支平衡，哪里出问题了，他几个叔叔姑姑还可以为啥呀因为他爸是老大的原因吗，不他爸懒打牌赌。对就是这原因。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3393, 'XtuWgkaVZsrXFRtJxzUtCs', 1, '2025-08-03 09:54:44', '2025-08-03 09:54:44', 'NORMAL', '今天是 2025 年 8 月 3 日(周日)，预约了科技馆的票，前几天也说好了，加加上完课后回来吃点就走，结果叫半天叫不起来说半天眼睛睁不开，一耳光打过去了，没那么多好心情哄着，天天这样上次围棋课也是起不来。这是对围棋没那么感兴趣了吗，难道不记得校长那次不让他参加比赛的事了吗，没志气。\n\n今天和果果说了，我们家培养人原则是谁有能力就培养没能力捡垃圾去吧不管他。养老的问题指望小孩可能性不大，现在哪有老人小孩住一起的。我的父母都指望不上我，敬父母也是，下一代也不可能了。\n\n早上起来嗓子疼喝了好些水，想了下应该就是王毅扬传染的，他们没事我有事，打喷嚏随意打，和人不保持距离，给人压迫感，可能是那边人的习惯，不招人喜欢。想管我自己吧 11 点多多喝水吃点药吧。\n\n#日记 \n\n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3394, 'dgUgVY9bnshSXPryVFdtpu', 1, '2025-08-04 08:00:00', '2025-08-05 09:58:49', 'NORMAL', '今天是 2025 年 8 月 4 日(周一)，今天张伟找我说身体怎么样怎么合作，我本想拒绝的，敬是想让我兼职在家干的，是呀我怎么想的家里花钱多没省下钱，挣点不好吗，说可以，后这么说怎么合作给多少工资，希望能定下来吧，能有份收入。敬发传单也挺累的，还会被业主保安说\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3395, 'CKzsx2LhMjrq8qyP8vA6qD', 1, '2025-08-07 06:30:00', '2025-08-09 08:16:08', 'NORMAL', '今天是 2025 年 8 月 7 日(周四)，还没通知果果住院拔牙，下午 15 点左右给医院那边打电话说明天过去吧，终于算赶上了要不 他们 14 号计算去青岛的计划就泡汤了。\n买车险让她问问周美玲她问张欣欣只返了 100 多，挺黑的我记得之前有小 600 的，也有 100 多的。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3396, 'KHHdcAnv3AwSnPUJxrkaMk', 1, '2025-08-08 07:00:00', '2025-08-09 08:15:03', 'NORMAL', '今天是 2025 年 8 月 8 日周五，敬一早就带果果去滨湖口腔医院了，13 点多回来了，还送果果去补数学课了，数学课本应该上午上的，敬在家吃饭做下午饭带着又去了，接果果直接去医院了，去接果果的路上说有条路有大车出入危险，差点碰到她车后怕。哪里我知道的在施工，出现这事应是开门的大爷不负责，不看。开车还是应该走大路安全些，\n看上海的居住证原来重新提交提交的是登记，一年过了就要重新申请了，妈的真麻烦，想试试用居住登记提交到安徽医保试试吧，不行就先取消到时在通过承诺的方式申请，要不说承诺一个月不提交材料不让在申请了这就麻烦了，提交了居然过了，开心。为啥还这么麻烦呀不外地就医不能直接用吗。信息肯定是能查查到的，故意给人找麻烦。\n3 岁前国家发钱了一年 3600 给力了， 幼儿园大班的学费也明确了免费说是幼儿园逐步免费，今年免大班的，明天加中班，后年加小班，嘿正好，想我小时上义务教育还收钱，我家孩子义务教育免费，孩子的孩子幼儿园免费学龄前发钱真好，之后会不会高中阶段也免费呢那就好了，初中和高中合并 5 年，能提前一年毕业。看到个扎心的大学学费涨了嘿，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3397, 'iSFks2kp3rVU8Svys28kdz', 1, '2025-08-10 19:18:42', '2025-08-10 19:18:42', 'NORMAL', '今天是 2025 年 8 月 10 日(周日)，想当年 10 号是发工资还花呗信用卡的日子，快一年没工资了，嘿，本以为张伟还会继续聊，后面怎么工作工资的事呢，也没下文了，再看看吧 10 月底去上海后有所好转了，张伟不找我，就试试投附近的简历吧。好好的一个人不能一直闲着穷着吧。\n这两天敬在医院陪果果今天也不回来了，明白为啥昨天前天回来了，因为果果有课，饭基本都是矩亚做的。\n今天阵雨，很大的阵雨，晚饭前出去拿快递玩了会，之后就没出去了，待了一天，时间就这么一天天的过去了。加加和王毅扬玩的很疯，我也不怎么说他们，矩亚会说，顺带加加一起说，王毅扬是一点也不老实蹦来蹦去的。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3398, '9uNNcpbQJB3Mb3xT73fKRB', 1, '2025-08-11 19:13:50', '2025-08-11 19:13:50', 'NORMAL', '今天是 2025 年 8 月 11 日(周一)，昨天夜里做了一夜的梦，加加夜里咳吵醒了，喝点水折腾了会，状态不太好。\n果果快 13 点做的手术，着急的等待呀，我也在家跟着着急，想我在手术室待 8 个小时敬在外面是多么着急，15 点出来了，嘴有些肿在吊水。\n昨天厕所的灯不亮了，下午折腾了一下午，前面是找不到东西，本想找个插头不用放在厕所吊着试，找个好久才找到，用之前的镇流器还打火挑闸了，给我下一跳，赶紧的总开关也关了，想买一套好了，免得折腾危险不值得，找到插头换个灯发现好用了，想这下好了，装在厕所还是不亮，晕了不知为啥呢，等到了换整套吧，吊顶换灯是麻烦，还是直接挂螺丝拧上就好了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3399, '9YPgVeUjK4TuBkwbvpikNV', 1, '2025-08-13 08:53:59', '2025-08-13 18:19:31', 'NORMAL', '今天是 2025 年 8 月 13 日(周三)，加宝晚上睡得很好夜里也没咳了，\n果果今天就出院了，住了 5 天了，拔牙受罪了。\n那小孩是真不懂事早上起来上厕所哐当一下把门打开了，上完厕所不冲不关厕所的门。他拿在家咋咋呼呼的，出去了一会一个电话，说明他也知道我不管他，不喜欢他。昨天矩亚给敬送饭去了，下午我带他们去公园下小雨在青壹社躲雨不下了，他自己骑着自行车跑了，即使他妈在前面等着也要和我说下吧。\n昨天晚上带加加出去回来时，加加在拿手机听三国，一个女的骑电动车看手机差点撞到加宝，我应该大声提醒的，娘的骑车眼瞎了。\n10 点多的时候敬带果果回来了，回来前还特意收拾下打扫卫生，自从那小孩来家里就没安静过。\n12 点多，敬去拿身份证买菜了，加加下棋，那小孩在旁边点个按钮让一步，导致棋输了，生气，拿棍子要打他，他居然拿着落地扇要还击，在那僵持着，想这小孩，想山东的老公真不能要，太彪悍了，民风不好。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3400, '3BmDxpVwNXDfBxsjutKgJL', 1, '2025-08-14 21:20:41', '2025-08-14 21:20:41', 'NORMAL', '今天是 2025 年 8 月 14 日(周四)，\n昨天做了一夜的梦，夜里还醒了最近不知为啥夜里都醒一会。\n敬和娃们今天要去青岛了，待 3 天之后回巨野柳林她爸妈那，祝玩的开心，其实俺是很想出去旅行的，只是这身体娃儿们现在走的地方都快比我走的多了。\n家里安静了，不适应，自己一个人做点饭吃，出去逛逛，要想干啥计划，不能天天刷手机。靠墙八段锦要继续了，收拾房间屋子，洗洗窗帘。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3401, '62pz7VrAbeS6HQg8HadaTR', 1, '2025-08-15 20:09:47', '2025-08-15 20:15:13', 'NORMAL', '今天是 2025 年 8 月 15 日(周五)，敬他们到达了青岛，\n昨天在桌子底下砸卡扣固定线，起来有些恶心，就想会不会是因为阿司匹林的问题吃了一次国产的，之前吃的都是拜耳的，想去医院抽个血看看吧，改药 15 天了，想上次安医没有阿司匹林这次该有了吧，上次开的抽血还没抽呢，原来还没有药。，就想去省立看半天也不知道该挂哪个号，就问问庚玖医院说有，算了就去那拿吧，应该可以报，到了挂了肿瘤科开的，泰康真报了。开心，总共花了 50 多，座车 6 块。\n妈打视频过来明显老了很多，回老家看了我姥，和我姥的合照都老了，发给我干嘛呀，我也不关心，我妈也没人说分担。\n中午睡了 10 多分钟就醒了，怎么回事呀，身体恢复了有体力了吗，之前都好能睡的，\n一个人在家好寂寞呀，晚上去公园，感觉人也少很多了，有娃时还会找找他们跑哪去了，今天再怎么也找不到的。没有社交没人联系要学会耐得住寂寞。\n想年轻那会有的是时间，接敬下班。那时在国风一个月工资也就 2k，那时还有 小 600 的房租， 不也过了 3 年。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3402, 'AhMYVS9UiqVWW2KLB9QzvD', 1, '2025-08-19 09:57:21', '2025-08-19 09:57:21', 'NORMAL', '今天是 2028 年 8 月 18 日(周一)，敬今天从青岛去往巨野了，一白天的车 10 点到 18 点一路辛苦了。\n我在家看了一天的电视，好无聊，被单洗洗晒晒了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3403, 'T3iFGC2ZjHhV2jL5k8UbBA', 1, '2025-08-19 10:00:38', '2025-08-20 20:28:52', 'NORMAL', '今天是 2025 年 8 月 19 日(周二)，今早去公园散步，出门看发现自行车没有了，前 2 天看到自行车被移动了，今天看没了，不开心，想应该是被小孩骑走了，小孩骑了大人不知道吗，还有可能是被收废品的顺走了不开心。前几天看到被挪动了就应该给弄回来之前就想是被物业保安挪的现在好了，可能有丢的风险。在一期群里问了下，让物业发朋友圈问下，结果晚上出门在网速场门口找到了想若是那个娃骑走了估计他家长也不定知道，现在孩子怎么这么随便呢，家长不管真怕一直成小偷了。\n\n耳朵后面应该是长了个包，好疼，应不是带口罩嘞的。最近口腔不舒服吞咽疼。天津陈池义消息也不回了，嘿。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3404, 'NsCfMjuKwhRAMwpxaj7dM8', 1, '2025-08-22 09:11:52', '2025-08-22 09:11:52', 'NORMAL', '今天是 2025 年 8 月 22 日(周五)，时间过得好快娃们一周的旅行结束了，今天就回来到家了，我这一周下来也没干啥，吃睡刷手机看电视，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3405, 'SzaymSB6hyua5EfS9rxoPc', 1, '2025-08-24 07:06:15', '2025-08-24 07:39:37', 'NORMAL', '今天是 2025 年 8 月 23 日(周六)，这两天很不顺，昨天去公园玩，他们刚回来有些累就没走那么远，在驿站附近玩了，加加飞天陀螺掉到草地里来了，扫地的阿姨来了句，里面都是泥，踩到地上还要拖，敬就不开心了，我也不开心。你就是干这个的，站在你的立场要求别人找骂，就是说我们给你找事干了。\n今天下午广场搞什么活动，投篮球，一个阿姨说篮球要自己捡回来，别拿走了，投后其他工作人员扔回来了，她来了句别给他们捡，敬就和她吵上了，现在人嘴怎么都那么臭呀，戾气太重。\n有次带加加去厕所出来后洗手，感性龙头出了一会水不停了，也是个清洁大爷来了句，让你搞坏了吧，虽说是逗孩子的话听着不舒服，这帮人在农村辈分大受人尊敬还没改过来适应。\n也明白为啥城里人不喜欢外来人了，比如上海本地人看不起外来的。最近宝能城改成回迁房 2 方都不顺眼了。\n还是身边都是些低阶的人，没啥文化，生活不易戾气重，看不得别人好。对于我们怎么避免呢，远离这些人呢，没事别去低端场所逛，娃们怎么可能呢。之前刚来合肥问句还想着第一问清洁工呢。\n敬今天开始上班了就打扫卫生了，其他也不知道，敬工资卡要换成杭州银行的，白跑一趟今天办不了，周末银行上班的人少吧。招人也不容易，还有些退课的不上的，是我我也不愿意地推。\n\n敬说楼下老公去世的，又找了个老公，一个月给 2000，好快呀，我若去了她也要找个呀。一个人生活太无聊带娃太累，\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3406, 'jaqePHeZszHzpkP2offtML', 1, '2025-08-24 17:11:53', '2025-08-24 17:11:53', 'NORMAL', '看开，不纠缠杂事\n世事浮云何足问，不如高卧且加餐。\n[唐]王维《酌酒与裴迪》\n人生，没有最美的事情，只有最好的心境;\n生活，没有最难的境地，只有最差的心态。\n大事，小事，烦事，想开就是常事；阴天,\n霾天，雨天，心宽就是晴天。\n《红楼梦》里有一副对联身后有徐忘缩手，\n眼前无路想回头。\n“月盈则亏，水满则溢”，贾府登高跌重\n盛极而衰的后果怎能不引起我们的警惕？\n是人就难免有欲望，我们所做的就是控制\n自己的欲望，若是被欲望控制，只会一步步深\n陷泥沼，沦为生活的傀儡。\n减一分贪念，多一分知足，守住本心，宁\n和安乐。\n不要在一件别扭的事上纠缠太久。纠缠久了，你会烦，会痛，会厌，会累，会神伤，会心碎。\n人生就像修剪花枝，你总要学会剪掉不好\n的树枝，才能够拥有郁郁葱葱的人生\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3407, 'jVo2CEZwdrsqRMMmjVwSbg', 1, '2025-08-24 17:13:36', '2025-08-24 17:13:36', 'NORMAL', '看透，不搭理闲人\n世事一场大梦，人生几度秋凉。\n—[宋]苏轼《西江月·世事一场大梦》\n金庸的《侠客行》中有首诗：“天地四方为\n江湖，世人聪明反糊涂，名利场上风浪起，人\n到头来却是输。”\n正所谓：心无增减，得失随缘。\n看透了，一切悲欢，一切忧乐，不过是由\n心生，随意灭。\n《庄子·秋水》中有这样一个故事，庄子\n正在濮水边钓鱼，楚威王派遣使者邀请他出任\n要职，却被庄子一口回绝：听说楚国有只死了\n三千年的神龟，你认为它是希望死后留下尸骨，\n受人尊崇呢，还是愿意在泥水中潜行呢？\n使者说：它自然是想在泥水中潜行。\n庄子微微一笑道：那么请回吧，我也希望\n自己能在泥水中曳尾而行、逍遥自在。\n生不逢时的庄子，一生都过着贫穷清苦的\n生活。若他想要功名利禄，则唾手可得。可他\n断然拒绝了显达，转而选择了穷困。\n功名富贵，人所向往。但在庄子看来，不\n是有德之人的追求。\n#精彩剪辑 \n\n', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3408, 'E3BkAxERk5sUHEgpGVw8sq', 1, '2025-08-28 11:07:24', '2025-08-28 11:07:24', 'NORMAL', '今天是 2025 年 8 月 27 日(周三)，看敬手机和王先峰的聊天说上个月亏了 2w，好担心呀，怕是生鲜传奇这门生意做不成了，本想一个月还能收入 5～6k 呢，希望是因为淡季的原因吧，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3409, 'TgZkvCwFx9gs8XRhgoL2rA', 1, '2025-08-31 07:33:18', '2025-08-31 07:33:18', 'NORMAL', '今天是 2025 年 2025 年 8 月 31 日(周日)，时间过得很快，娃们开学了，放假那会还觉得很漫长呢。\n这 2 天敬也忙起来了，赶紧在开学时招些人，要不就被别的机构抢走了，昨天郁闷了因为一个老师说他加了 57 个家长微信，敬才加了 6 个。对敬来说这应该是正常水平，那人说这估计也是吹吧。给人压力，让人不愉快，周六七夕校长给她发 3k，怎么有不好的预感，要加工资过节费在工资里发就好了，怕加工资其他同事有意见。不知怎的想的想到烽火台了，在那做兼职时关系比较好的同事请我吃饭，下周就和老板说了兼职不干了，当时那边也招到新的同事了，想是不是老板示意的。\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3410, 'f2sgzMbohLYjHdBZ47f2wo', 1, '2025-09-02 18:58:03', '2025-09-02 18:58:39', 'NORMAL', '今天是 2025 年 9 月 1 日(周一)，下着小雨我一早去省立医院抽血检查了，本想在拿些阿司匹林的结果没有，b 超好久没做了，开了检查好久才排到，快 12 点的回来的，\n娃们今天开学了，敬去送的，她今天不上班。\n下午去学校地推了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3411, 'FAqYzVLTgRR5WWMSaoG87a', 1, '2025-09-02 18:58:28', '2025-09-02 19:10:31', 'NORMAL', '今天是 2025 年 9 月 2 日(周二)，敬一早去送娃上学了，一起下去的我去公园溜达去了，带着羽毛球。敬送完回来后在公园打回球回去了。\n到家有些困迷糊了一会，给换燃气表打电话，装燃气表昨天说下午过来看的，说怎么没来，他一会来了，说要加个阀 120 元，这些资本家加阀就要钱的，他们是想把人工钱给挣回来呀。\n张伟打电话了说要做平台，app 要我做就着 2 天，做个简单版本领导都那么说做起来都不简单，看能给多少米吧，至少要 5k吧，发了工资先买个笔记本电脑。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3412, 'YzbxzUZfHy3gjfWP3xK8fV', 1, '2025-09-02 19:12:18', '2025-09-03 17:37:32', 'NORMAL', '今天是 2025 年 9 月 3 日(周三)，一早起来就听它发脾气，起床啥的，上厕所发现进水有问题，先把进水开关给关了，因为怕一直漏水，加加上过厕所果果上要冲，说先上，敬上厕所又要冲，气人，嚷着那的催他们快点。他们先吃的饭他们走后才吃的，吃完收拾放厨房去逛公园打羽毛球了。\n回来的路上上海肿瘤医院提醒缴费，ct 预约日期还没有 27 号的，敬问他们，医生还开了抽血的，敬不让交钱，这那的，我说你自己弄吧。想她不弄了，我把费交了，在挂后面2 天的号把其他部位的ct 也约了 3 个部位还要分开约 3 次。\n她弄好了没事人一样在那看阅兵了，想想气，\n我去看马桶维修的教程了，找到原因了进水有过滤网堵了，用牙签清理下进水快了，可是在安装时拧不紧了漏水，让物业人过来也没带专门的工具拧 2 下走了，嘿一点这不付责任呀。买工具买个进水阀吧回来安装，本想在群里找领居的想欠人情算了，总共 10 几块的东西。\n\n今天很生气，她还和我提说她看我的日记说我不和她结婚说不定我就不会生病的事，她还来气呢，本是因为早上早起忙慌，开学工作忙不适应，在家就刷手机，想和她说考教师资格证不当老师在培训机构当个助教也行，在不旅游免门票也好呀。想算了说啥呀，原因考就考不考拉倒。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3413, 'SuFZycRFMmCXsD6RdSrLyC', 1, '2025-09-06 14:35:50', '2025-09-07 16:14:53', 'NORMAL', '今天是 2025 年 9 月 6 日(周六)，中元节，昨天打雷下雨敬骑车回来说一路的电磁波呲呲的声音，我还纳闷说没听到，她到家这块没了，\n今天早上我出去，回来的时候她出去买菜回来说又听到了，我在门口确也听到了，一起下楼也听到了，敬把电动车骑走听不到了，折腾了半天原来是电动车发出来的，搜下说应该是电离空气的原因，今天农历 15 满月，说月全食血月什么的影响吧，因为昨天空气潮湿的原因没道理呀，\n下午送过果果加加后换了个电动车，2200 多还好开心，有隐患的电动车就要换掉，不能留隐患。\n马桶进水口的问题修好了，把滤网的地方拆下来了，用新到的管夹固定从上面拧进水管拆下来的，把管子缠绕些生料带好了不漏水把工具和新的进水管退了，就是怕进水管拧坏了备用的用不上就退了放家里也没用。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3414, 'Q6SX3ihAUPcmaXuZceEfZd', 1, '2025-09-09 15:46:41', '2025-09-09 15:46:41', 'NORMAL', '今天是 2025 年 9 月 9 日(周二)，最近天气变凉了，最近身上的疙瘩多了，疼难受呀，\n上周 二张伟说要项目启动一周没消息了，嘿不靠谱呀，可能和其它人的沟通不顺畅吧，别人上班好好的为啥要去你那边呀，工资给的也不给的高，还没啥前途多久才能上市呀，我是正常人我都不信。我也是只是想挣些小钱。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3415, 'fKvqGrFrbdZp83EfxrjKWx', 1, '2025-09-10 12:27:20', '2025-09-10 12:27:20', 'NORMAL', '今天是 2025 年 9 月 10 日(周三)教师节，昨天敬买些水果给加加的老师，数学老师没收，放在他小区门口老师一直没拿，昨天晚上敬回来时带回来了，娃们吃的还挺带劲，没和娃们说怎么回事，忽悠过去了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3416, 'nozGfvCfML2Qnucpy3dZcS', 1, '2025-09-15 13:23:30', '2025-09-15 15:14:27', 'NORMAL', '今天是 2025 年 9 月 15 日(周一)，今天看移植的群里有个小伙 19 年移植的，最近离世了，敬应该也看到了，什么也没说，没说就对了。\n最近口腔溃疡疼呀，有点咳嗽有痰，去庚玖医院了，开些中成的药回来了庚玖的药还是挺全的，开药的人也给开不像有医院有药也不给开要去挂的号。\n中午把晾晒衣服的钢丝绳换了，有根断了，挡着不能摇到位，上次没弄彻底，嫌换麻烦，这下好更麻烦，下次还是直接用根尼龙线方便，便宜还好换些，铁丝都搞不动。\n加加又要打乒乓球了，放了学带他去，好久没和他一起打过了，学校开学他带球在学校打，想多教练吧，\n隔壁 五一结婚收拾的房子，父亲不在这住了。昨天小两口搬家了，沙发油烟机都搬走了，应该是卖房子换了吧，嘿早知如此干嘛还收拾从新粉刷呀。不知他父亲去那住了，想我当初毕业在上虞敬来了也是没地方住，我爸妈去卖菜的屋里住了，虽然在厂里的院里不好对他们来说已是好的了。我至今仍想着他们吝啬不想着给我们租房子，如果我的娃我会舍得出房租住好一些，我的孩子长大了毕业了会怎么样和我当初一样吗，不要呀不行也做程序员吧，至少工资还可以。干个几年手头有些钱了在折腾。假如我资金充足当然不想他们中转了。\n还有挣钱的机会吗。给孩子们留些什么。\n昨天接果果去的时候下小雨，到那地方了，下大雨，咣咣的，加加还在家里呢走时说要睡觉，幸好厨房的火关了。等会不见小，冲吧，带着雨衣回家了，一路上眼睛都睁不开，到家洗个澡，因为雨水不干净。\n公积金里还有些钱 1k 多，上次没销户，结算利息了，就想着怎么弄出来，本想用租房租上海的房子呢，结果不行，看有个离职试试真可以，快速到账开心，这下好了和公积金彻底没关系了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3417, 'DtqWUNK8k5CPFimiJxUbXP', 1, '2025-09-19 09:14:50', '2025-09-19 09:19:13', 'NORMAL', '今天是 2025 年 9 月 18 日(周四)，嘴疼口腔溃疡还没好，脸上又要冒疙瘩了，后背还有个，感冒症状好些了，走会回来腿酸，\n加加回来说钢笔笔帽掉地上找不到了，嘿从网上买几个一次性的钢笔吧，也往好的方面看，他不心疼，这点挺好的，丢了坏了就坏了，不伤心难过向前看。\n半夜果果上厕所，敬嚷她，给我吵醒了（本就难受，后背疼，脸疼，生气，搞的我好久没睡着）说她大半夜拉，蹲的时间长，想办法帮她解决问题，大便顺便不就好了吗，嚷她也解决不了问题呀。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3418, 'eNDwetDLwXYMekr4trWpv8', 1, '2025-09-25 12:24:46', '2025-09-26 12:24:46', 'NORMAL', '今天是 2025 年 9 月 25 日(周四)，昨天夜里有蚊子加宝没睡好，我也醒了拍死一只蚊子，有只拍了好几次没有拍到，折腾的加加也应该没睡好。\n最近下了 2 天的雨了，今天 25 号 下午的时候总算不下了，昨天 24 号去开车接加加发现后车窗没关开的还挺大，下了一天的雨进了好多水，去的路上还想着这要走要晒了怎么办，到学校路边的车已经停一条了，对面有个车应该是不知什么时候走的侧方位停进去了不是很到位就这吧，去的早就在车里用纸吸水了一包纸巾下去总算捏不出水来了。去教室里把加加接走，回来吃些，敬今天下午没去上班，到点接果果了，到地方才想起来果果今天要要值日的，来就来了等吧，车不多了把车往校门口开开，回小区后单元门口一辆货车在卸货只能直接开进去了，明天下雨又要麻烦了。\n应上周五加加把泳冒拉在车上了， 23 号周二敬与司机联系说在车里让 16 点 10 分去校门口车里拿，我还提前了一会出门，看钥匙没在那里挂着，敬说早上把钥匙放在防风的袋子里了，就把车钥匙拿走了想电动车骑不了就开车，把电动车推出来（因天气不好都挤在车棚里不好推）里面没钥匙又把电动车放好，开车去了，快到学校路口看到游泳的车了，到校门口我还没地方停车，转了个弯，到大巴车那，学生下完了，问司机说让老师拿走了，老师都已经进去了，我也不知道包什么样子的我那知道呀，门卫室也看了没有，第二天失物招领出也没。\n今天还没拿到游泳的包，这老师脑子怎么想的，不想着还回去麻，肯定是 3 年级的几个班吗，几个班主任问问不就知道了，你就留些当吉祥物吧。\n最近和敬在一起待的时间长，两个人也没什么话说，她说我不和她沟通交流，我不想听她的唠叨，干什么事还怕她唠叨说该休息，帮她干这那的，不自由。\n这周加加和果果就没在一起送了虽然加加和果果一起起来，先送果果，加加在家看会书打卡什么的，到学校他也是玩。\n昨天放学回来问碎纸条从楼上丢下去为什么下不去，在我这没找到答案，又问了他妈，很好的性格只是爸妈对你的帮助有限。\n前 2 日嘴巴吐出血丝，担心怕阿司匹林的原因，大便还是时不时的有血，小腿也不清楚什么时候会酸，不想这些了。\n张这边一直也没消息不知回来了没，也不说工作薪资怎么合作的事，还不清楚有没又招人，有种预感感觉这一生和程序无缘了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3421, 'aQuK7TELqBniTr3trkU4rg', 1, '2025-09-28 17:32:41', '2025-09-28 17:32:41', 'NORMAL', '今天是 2025 年 9 月 28 日(周日)，因为十一调休的原因今天学校要上课，最近几日夜里都会醒，很快还能再次入睡，夜里也有蚊子，之前天很热开空调不觉得，门口的纱窗也拆下来了，应该原因不大，本也就没几只蚊子。\n最近在想着 memos 的事，因为浏览器下载一个大文件很慢等的我受不了了。找到了一个app，又因为版本的问题不兼容，memos 的版本高api 修改了，app 还没跟进给了个转发接口的项目一直还没配好，郁闷。\n张伟又打电话了，说对接平台，app 的事这次提了方案app 找别人搞吧，推荐了澳汀之前的同事，不想给自己搞的那么累。\n敬公司今天要搞去学校的路线怎么走的文档，纠结搞了几个小时。觉的还是网页的方便些。直接分享个地址，还能加打开地图的按钮。一个文件也不好看。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3422, 'YbHzTm678GcKBQH8UhgsQS', 1, '2025-09-30 10:59:21', '2025-09-30 10:59:21', 'NORMAL', '今天是2025年9月30日周二，明天就国庆小长放假了，不用想着早起的事了。\n手机端app弄memos的事也不想了，折腾就这样吧，管他干嘛，搞半天也搞不好，娘的也不知为啥算了，就这样吧，不知道啥原因的。升级后在手机上打开好像也没那么慢了。\n昨天去庚玖抽血了，正常的。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3423, '4WzH6fQybFCqjdaYmGUu24', 1, '2025-10-10 12:48:54', '2025-10-10 15:13:58', 'NORMAL', '今天是 2025 年 10 月 10 日(周五)，时间过得好快呀，10 号是信用卡还款的日子，加加配眼镜学校饭钱，钱又不够花的了。\n最近在想着搞日记记录的事，因为网络请求慢，想搞个app 或小程序折腾\n加加学校游泳课今天没去，天冷了，12 点接回来 16 点送过去接折腾了，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3424, 'ZxgVPCMSt6z2vnWeYMZhjD', 1, '2025-10-07 12:49:16', '2025-10-10 12:49:16', 'NORMAL', '今天是 2025 年 10 月 7 日(周二)，眼看假期就要结束了，娃们早上写作业，下午晚上出去玩就这样过去了。\n今天不知怎的腰疼，\n晚些果果让我查做游戏的亲子游戏，突然觉得果果在哄我玩。\n感觉在家待久了就会有矛盾了，不快活。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3425, 'goFfz7abwQgbGKBWiiR2Ab', 1, '2025-10-08 12:50:45', '2025-10-10 12:50:45', 'NORMAL', '今天是 2025 年 10 月 8 日(周三)，后背不疼了，\n敬今天加加去检查视力说近视了 100 度，嘿还以为加宝能不近视呢，下午敬还说要带他配眼镜，\n娃们上完课后带他们到淝河智慧公园了，配眼镜的地方就在这附近，在这等敬吧。17 点多了敬到了，一起去眼镜店了，到家快 19 点了。\n本以为 十一会有大学同学过来看我呢，没有些失望，人到中年玩的就是消失，嘿\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3426, 'gSXP8aYGqWDfWrSRad7bQt', 1, '2025-10-06 12:51:59', '2025-10-10 12:51:59', 'NORMAL', '今天是 2025 年 10 月 6 (周一)日中秋节，中午吃了丰盛的大餐，螃蟹汪丫，不敢吃螃蟹，下午娃们写会作业，\n快 17 点了他们才出门去融创玩了，原来融创乐园门票也开始收费了。就没进去，在商场玩了，吃个饭回来了。\n我在家给果果弄错题，检查数学，把中午剩饭热了吃了，出去走走，回来洗澡，没多久他们就回来了，感觉 4 个小时也没干啥。\n出去去公园给妈打个电话，他们在浇水。敬妈给她打电话说家里冷了穿毛衣了。\n敬说加加假性近视，户外运动少了。真不希望小家伙带眼睛，放学回家吃饭玩再写作业，晚上睡的时间又晚了。一天天的时间都去那了。怎么安排才合理呢。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3427, '74xtKq4fxfWfcuMR4K8V2H', 1, '2025-10-02 12:53:09', '2025-10-10 12:53:09', 'NORMAL', '今天是 2025 年 10 月 2 日(周四)，昨天睡得不好，夜里起了几次，想着白天项目跑不起来的问题，还有加加夜里咳嗽，我还睡在客厅和加加分开睡了呢。\n昨天他们 9 点多就去步行街了，18 点多才回来，我在家玩电脑看java 项目了，为后面的工作做准备，张要是不给钱就当做练习学了。\n今天 8 点多才起来的，敬也没起来，娃们没人叫也就一直睡了。\n下午 15 点多他们又去步行街了，把昨天的问题解决了，嘿只是一个配置文件的问题，。\n晚上去公园逛逛了走人少的路。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3428, 'BQsXzC7DBWePYhHoPYLSCY', 1, '2025-10-14 09:15:46', '2025-10-15 17:34:55', 'NORMAL', '今天是 2025 年 10 月 14 日(周二)，一早起来第一件事就是预约 10 月 27 号上海的检查，特意定了 3 次的闹钟今天终于可以约到了，6 点 27 时只有 7 个号了系统还挺繁忙多次出错，这下知道了说是 提前 14 天，要减去 13 天，前 2 天我和敬的票买过了，要给我妈买票了，\n这 2 天突然变冷了，炎热的夏天终于过去了，\n张伟还是没说给工资的事嘿没劲，每天也不知道干什么，一天天的主要任务就是接娃了。虽然有 1800 的失业没有挣钱的感觉，哪怕我挣的能够补贴家用也好呀。\n暑假看到的小区小男孩腿骨折的，今天自己下楼走了，虽然走的还不是很好，还是值得开心的事，3 个多月了，好快呀，\n昨天果果说让我看她画的画，突然说了句向漫画社投稿吧，不同意，想发小红书吧，小红书的挺好的，能传图片视频不像抖音视频号只能传视频门槛就高了，之前有微博，小红书是怎么火起来的呢，\n给我妈到合肥的票买好了，25 号晚上 19 点的，上铺\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3429, 'XAKiDUV5j3BCQadRJdiNhe', 1, '2025-10-15 17:34:03', '2025-10-15 17:34:03', 'NORMAL', '今天是 2025 年 10 月 15 日(周三)，前 2 天看到 vite 可以进行多页面开发，想 memos 如果做成多页面不是就可以了，改了几个小时发现不可以，多个页面里有路由跳转太折腾了算了大爷的不搞了彻底把项目给删除了，觉得自己好笨。\n最近好郁闷没啥开心的事，后背有时还会觉得疼，有些担心，这次检查就知道了不管怎样都面对吧，没啥大不了的了。\n家庭因为钱的问题并不和谐，还是我的想法不对，贝也是这么想的把父母的钱弄过来， 攥在自己的手里。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3430, 'hycCNC4iHvANpH638zmGWB', 1, '2025-10-18 16:09:59', '2025-10-18 16:09:59', 'NORMAL', '今天是 2025 年 10 月 18 日(周六)，中午果果做了次无间道，去成芳教育看他们怎么教的，学习不就是根课本同步吗，这样才能成绩出的快呀，单元考的就是这一单元的，提前学有学的好处，课堂讲的就轻松些。\n这 2 天天气明显冷起来了，裘衣都穿上了，喝水的目的也变成为了暖和了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3431, 'giAnp7LA9r629hUCWDdYZ4', 1, '2025-10-20 11:40:54', '2025-10-20 20:37:02', 'NORMAL', '今天是2025年10月20日（周一），\n天明显变冷了，早上送果果风乱的呼呼的，\n下载了cursor发现可以直接连接ubuntu18开心了，不用想着折腾了，把memos又给折腾了下，调整编译后最大的文件大小了500k了，用的不错，开心。\n把主卧的灯给换了换成吸顶灯了，这下好了之前买的灯都拆了，好几千块浪费估计这辈子也不会装修了，不会再当冤大头了。\n初中的知识确实难了好多呀，真麻烦。辅导孩子写作业也只能到初中毕业了，嘿，明天在家要学习下她的物理了。\n\n[cursor](Version: 1.7.52 (system setup)\nVSCode Version: 1.99.3\nCommit: 9675251a06b1314d50ff34b0cbe5109b78f848c0\nDate: 2025-10-17T01:41:03.967Z\nElectron: 34.5.8\nChromium: 132.0.6834.210\nNode.js: 20.19.1\nV8: 13.2.152.41-electron.0\nOS: Windows_NT x64 10.0.19045)\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3433, 'JXwg5RsCHEhd6DbvhDKM2y', 1, '2025-10-23 13:58:18', '2025-10-24 14:11:11', 'NORMAL', '今天是 2025 年 10 月 23 日(周四)，发工资的日子，到了 2000 多，开心，之前就看新闻说最低工资要涨了，上个月没多还以为失业金不调整呢，虽然不多一笔小钱也开心。\n最近和敬一起出去她送个不停，招生的，孩子的焦虑，感觉她把这些坏情绪都推给我，让我吸收，不回应还不行，我成了她的气球，一回来就嘟嘟嘟的一大堆，还说要换老公，我这不病不都是闷气吗，还这样感觉在家久了，闷气更多，\n弄电脑我都要背着她，怕她说我，我就不能有点自己的爱好吗，在家真不适合办公，一会叫一下的，不回应还生气，看你座在那就觉得你在玩，婚姻虽说互补，可更重要的是情趣相投。\n挤个疙瘩说挤的疼，擦的疼就是不知道改，那天那么大的气，非使劲的按擦。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3434, 'G6Qtt2RditQMRK99TUDiz5', 1, '2025-10-26 01:05:38', '2025-10-26 01:20:24', 'NORMAL', '今天是 2025 年 10 月 26 日(周日)凌晨，25 日夜间睡不着觉准确说是睡了一会了，又醒了，这 2 天都这样夜里睡不好，脚痒痒，起了好几个小泡，不知是不是穿那个鞋子的问题，有什么细菌啥的。在频繁的抹碘伏希望能早点好起来吧。\n老张这么久也没联系了，我是看开了，程序员这条路我是走到头了，后面只是给孩子辅导作业发过来孩子吗，好不甘心呀，\n孩子闹，有时会头晕，敬说多了也会，一个人待久了也会，怎么办心静不下来，真有钱了就不会乱想安心了吗，估计也不会，没有安全感。一生就这样了，好不甘心呀。\n敬说我挺自私的，觉得确是对孩子敬的关心却是少了好多。今天下午吃饭都没吃饱，加加吃 16 个混沌敬回来还要吃，果果也是吃完了还吃零食，家里还有豆干萝卜的可以炒的，想敬回来吃。怎么说呢家里也没啥菜吃的，敬一次只买一些中午回来买就导致中午的时候没吃的。\n多想着做些吃的吧，吃不完他们不吃倒掉了又好心疼可惜，我小时就是不吃饿几天就吃了，对孩子也有这种心理，还是觉得穷呀。要不也不心疼呀。孩子们希望你们以后不要因为钱焦虑。恐怕也难呀。要穷几代呀。\n今天晚上就要去上海了，后背腰有时会酸，希望没事吧，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3435, 'b9A2iLG3WQpjtNe9sPEopF', 1, '2025-10-27 01:07:20', '2025-10-28 16:25:42', 'NORMAL', '今天是 2025 年 10 月 27 日(周一)，去上海了，之前还觉得 3 个月之后是很久远的事呢，转瞬就到了。 一路座车比较顺利，敬去火车上铺睡的说比较挤，我这边是不知道那个呼噜声震天响，醒了几次很快又入睡了。\n到上海做地铁就过去了，火车还提前了一个小时开心，不用那么着急了，到浦东抽血，排ct 花了些时间，快 11 点了才做完，在浦东ct 室更衣室里还找到了充电的地方开心，12 点多到徐汇院区，原来下了地铁就是了真方便呀，医生说和上次差别不大，意思就是稳住了，没在继续恶化，挺好的了，前面还想后背酸是恶化呢，不敢和敬说开心。，医生来了句移植肝救了我的命，按原来的量继续吃药。\n13 点多些，买的是 23 点的车时间还早想带敬转转，去外滩南京路步行街，敬很失望啥呀。外滩还不如家旁边的公园呢，步行街买的多是糕点文创当然是真的贵。\n逛够了去车站，敬要改签看能不能早点回去，要个还有 10 多分钟就要发车的到那正在检票呢，上次没选好付款方式又试下成功了坐上车回家了。\n20 点多到家了，娃们在写作业，加加看到妈妈还一惊，果果还说不明天回来吗，\n果果洗漱慢被嚷了一顿，最近果果作业少了，做的也快了。开心时刻。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3436, 'kBcy64UVRCNVu6FRNShtbT', 1, '2025-10-28 16:26:22', '2025-10-28 16:30:39', 'NORMAL', '今天是 2025 年 10 月 28 日(周二)， 我妈送的果果，敬送的加加，我吃过上个厕所去公园了，打回球回来休息会去庚玖医院了，\n到医院开药阿司匹林本不用开的够吃的，只是找个借口顺利开了益生菌，既然有四联的真好开了给娃们吃，可以只给开一盒，其实主要目的是去皮肤科看脚上的水泡的，痒都挠破了。给开了药膏，额头的也开了希望能缓解些吧，泰康能一起报销了，上次就报了，只传皮肤科的发票不传病历。\n准备回家到电动车了想医院有没打虫药在医院开还便宜些果果的账号能报销些，让敬挂个果果的号挂不了了，中午的都下班了，去儿科问前台说没我说是你不知道有没，还是医院就没有，她去问医生，医生说有开心，直接用卡号就开出来了，缴费拿药 3 块保险 2 块 1 块还说从共济账号扣的，应该没了呀敬的我已经扣过了呀，反正不花钱更好，要是去药房之前 10 多块开心省了不少。即使庚玖的药比别的医院贵些比药店还是便宜的。\n回来和敬商量给我妈买了明天回上虞的票，\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3437, 'fxGeGUbNvxUsf3gnWkh2Pm', 1, '2025-10-29 06:39:40', '2025-10-29 14:22:44', 'NORMAL', '今天是 2025 年 10 月 29 日(周三重阳节)，夜里做奇怪的梦，居然变成富二代花花公子，哈哈哈，身体还是一样的移植了，还去内蒙古感谢那家人。我重生一年对他们来说可是一年的祭日呀。\n我妈今天的票回上虞的，8:54 的，送完加加后，还能在家休息一会。昨天接加加回来还说奶奶什么时候回去，听这语气是不想让她待在着呀，把不得她早点回去呀，那里做的不好惹他不开心呢，问他也不说。\n在南站停车到p2 在南广场，要走好远的路呀，奶奶的，送人要去北广场的停车场接人可以去南广场这下算是知道了。\n27 号周三在上海步行街逛时，张总发消息说回来了，让我去他公司聊聊怎么合作，说的今天去。送过我妈后就过去了，原来一路还挺好走的一路高架还不堵，和去市里上班的人刚好相反。\n到那边也很容易就找到了，说房租交了后面可以申请退钱，退不退的了再说了。到那聊聊现在的机器了，本以为就 2 台呢，好几台了，3 台组装好的，还有在组装的。说卖了几台了， 还以为没开张呢。说了澳洲那边的教育医疗。工资吗我看他说是想按项目来还是按月的支付，我是想按兼职的按月支付反正也说了，他说和凌燕商量下，随便他吧爱怎么怎么吧，不要拉倒，不行回来找找工作吧。\n园区停的车不多就那几个车也不收费，挺好的，一楼大太阳，比在澳汀那制药园好多了，极其怀疑澳汀楼上制药的放毒。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3438, 'DQufYJLoyWvGYNoH8VGpFJ', 1, '2025-10-31 11:22:21', '2025-10-31 16:40:35', 'NORMAL', '今天是 2025 年 10 月 31 日(周五万圣夜），10 月的最后一天了，太阳也出来了，心态放好静待花开。\n昨天一天的雨，没出去鼓捣电脑了？虽然没人付工资瞎弄嘿，对张没信心了，就想白嫖。\n昨天放学果果说，明天万圣节要糖，原来是同学之间还以为是老师呢，不给糖就捣乱。\n\n下午把mac 笔记本安装了 Windows 系统，运行起来很流畅开心，感觉又有台新电脑了。本以为很难呢，原来和 Windows 安装系统一样的，也不需要安装特别的驱动，只需要 win pe 引导就可以了。\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3439, 'ZUGaHFXHUcNt3X9p5VKDSY', 1, '2025-11-01 20:47:05', '2025-11-02 18:23:07', 'NORMAL', '今天是 2025 年 11 月 1 日(周六)，金一早就带果果去拔牙了，医生还要看之前的病历，10 点多就拔好回来了。还以为会难受一天了，中午吃的面条挺好的，比我那时拔好多了，我那时记得只能喝粥。找病历把之间存的全找出来了，柜子里有股霉味，能扔的都扔了吧。大多是我的。\n我 8 点多叫加加起来 9 点出门 11 点半到家就带他在公园逛累坏了，12 点多敬去上班了。\n送果果加加上英语课。我在家拾掇睡了会。 15 点包多去公园 17 点送加加上篮球课累屁的了，一天逛了 4 个多小时。\n晚上想着小爱音响，没啥用能不能刷linux 做个服务器，打开看看app 升级，发现有对话记录，试了下可以生成式对话了，高级开心，还以为小米放弃了这款产品了呢。\n鼓捣了下 cloudflare 的域名发现解析没问题国内访问不了，还没发备案算了\n\ngoogle cloudflare 账号\n\nhttps://domain.digitalplat.org/ \n404171231@qq.com \nDIGITALPLAThu0303@ \n \nhttps://dash.cloudflare.com/ \nproud2008@qq.com CLOUDFLAREhu0303@ \n\nGoogle.com proud2008@qq.com GOOGLEhu0303@\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {"hasLink": true}}'),
(3440, 'TDp5JuFNp4LAJ2mL9Wu9L6', 1, '2025-11-03 16:21:35', '2025-11-06 12:04:04', 'NORMAL', '今天是 2025 年 11 月 3 日(周一)，想着怎么弄互联网广告，搞些收入。\n很郁闷的以为很简单的，申请百度时还不过，应该时域名的问题或者内容不够多的吧，反正是没过，找了个国外的广告平台放了，没有那多要求，希望能有些收入吧。搞了好几天郁闷。5 号才弄好国外的。晚上邮件发过来说不合规，广告又给屏蔽了，娘的算了不鼓捣了。自己的博客也没啥流量，指望自己能有啥收入，还没想过把博客开放注册给人用，自己备份什么的，文件大都是工作量。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3443, 'Xit53u8mGvcbEsVqkRD6Rq', 1, '2025-11-06 11:49:20', '2025-11-06 11:49:20', 'NORMAL', '用力赚钱，就老实一点\n用脑子赚钱， 就机灵一点\n用钱赚钱，就狠一点\n用资源赚钱， 就圆润一点\n用人赚钱 就豁达一点\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3444, 'UvfUxoPiGgh4HuA99nh2U3', 1, '2025-11-06 12:01:08', '2025-11-06 12:01:08', 'NORMAL', '今天是 2025 年 11 月 6 日(周四)，送过娃去公园，有工人我用机器吹落下的叶子吵的人脑子嗡嗡的，往里面去找个安静的地方打会球，对公园太失望了，一点也不好玩，为啥景区会变成这样，湿地公园也是，搞得那样。在小红书发了一顿的牢骚，真希望建个寺庙追求一直的安静。\n回来的路上敬又是一顿的吐槽果果的成绩，好烦呢，她把这焦虑的情绪传导给我，眼睛不好焦虑眼睛，快期中了就焦虑成绩，没会心神安静的时刻。\n回来休息下，剪头洗澡敬也要洗，本想调皮下算了，讨不到好，惹她不开心，两个人都不开心，何必呢，忍忍就过去了。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3445, 'MH8iviUVcgAZ5xjNmRbnPe', 1, '2025-11-07 22:47:21', '2025-11-07 22:54:48', 'NORMAL', '今天是 2025 年 11 月 7 日(周五，立冬）阴雨天，昨天澳汀的财务给我打电话（张伟让打的），说我身体的事，费用的事，沟通交流汇报进度的事。今天一早给我发消息说写下工作量评估，需要多少时间，昨天想想着还能接受今天想一分没给就写这写那的，算了不搞了。在公园时和敬说不靠谱不在搭理他了，她也想明白了 4 月份让弄一份没给也没说给多少钱拉倒吧你。\n整个事我是明白了，张伟嫌我没进度，让财务交接和我说。张口口声声说不会亏待具体报酬多少怎么给提都不提，他以为和我说明白了，我想的是能收到钱，大家在这画葫呢。我也想明白了，给他干沟通成本太高，干不成供应商不积极开发用不了不会给钱的。他理所当然的认为我会催供应商来搞是会催一分没给催个屁呀，给自己找气受，给他们方案通讯协议的我都觉得亏了，算了这活不能干。\n晚上加加说他的草稿本在同学那里要不回来了，敬给他家长发消息之前还说没有，后说找到了说给孩子揍了一顿，理由是撒谎了打的好。即使捡到了别人和你要不还也不应该。打的好。\n果果昨天一张试卷忘记带了，敬让加加送过去，让他一到学校就送，我说课间去送，结果加加到学校看见果果老师在班级门口，没敢进去没送，敬担心的怕一到学校老师就要收了，我是想虽然是晨读大家都认真的去不好。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3446, 'd56JJDuGKHT9RrMPQH6o9U', 1, '2025-11-08 17:59:29', '2025-11-08 17:59:29', 'NORMAL', '今天是 2025 年 11 月 8 日(周六)，和张伟说了彻底是不做他的项目了，本以为不在搭理他了，敬的劝说下还是和他说了，算了彻底结束了，不会在有幻想他会转钱了。\n在小红书找了个说可以赚钱的，非要打电话结果是就是卖ai 工具的居然要 3w 真不要脸，还被敬笑话一顿，问个海外带货的居然也要收钱，算是明白就是骗钱的，什么免费传授经验怎么可能呢，谁会做慈善呀，再说了我有没流量怎么做，推广视频怎么来，还是安心找个兼职干吧，不想那些所谓的 0 成本创业了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3447, '4cKDbE99jp9ziqBJNpacKw', 3, '2025-11-09 14:46:15', '2025-11-09 14:46:52', 'NORMAL', '点善意暖人心\n\n秋天是金黄的，是丰收的，是凉爽的，是宜人的，是欢乐的。\n在这样的秋天里，我们迎来了一年一度的运动会。在开幕式上，当鲜艳的五星红旗冉冉升起时，我们庄严肃穆的向着国旗敬礼。\n这次是我有史以来第一次参加运动会，我怀着激动的心情在800米比赛的起跑线上望着周围密密麻麻的人群，忽然觉得有些胆怯，有些害怕。随着裁判的一声哨响，所有的选手都像离弦的箭一样冲了出来。我的脚上更是像踩了风火轮，跑得飞快。\n第一圈的状态很好，保持在第三的位置。可谁知道到了后面，我的速度越来越慢，就在离终点线不远的地方，我突然摔了一跤。我使足了劲儿才从地上爬起来。好几个同学已经跑过了终点线。后面的同学也陆陆续续的跟了上来。我一瘸一拐的走到了终点。\n走在了人群中。我难过极了，正打算往教室走，却发现同学们都围了上来。他们没有一个人问我的成绩，而是都关心的问问我哪里受了伤，那一刻时间仿佛凝固了，同学同学们那些关怀的问话就像冬天里的一束暖阳直射进我的心房。这次比赛虽然不是冠军，但却得到了大家的关心。大家的关心照亮了我前进的路，让我变得自信勇敢。\n生活中有许多的善意，也许是公交车上的一次让座，斑马线前帮助老人，在别人受伤时伸出援助，在别人难过时给予关怀……这些细小的善意遍布在城市的每个角落，它让我们的生活变得充实，让我们的世界变得精彩。\n\n20250218\n\n#作文', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3448, 'KsrJXGCVPFoJyWMivMtHBY', 3, '2025-11-09 14:54:08', '2025-11-09 15:13:06', 'NORMAL', '我的班主任\n\n我们班有形形色色的老师，和蔼可亲的于老师，幽默风趣的王老师，知识渊博的杨老师。然而，令我印象最深刻的却是我们的历史老师张老师。\n从小学六年级，我们换过几次班主任，不是语文老师就是数学老师，不是数学老师就是英语老师。不管怎样，都是主科老师。可怎能想到，到了初中，我们的班主任却由历史老师担任，这可是我前所未见的呀。\n张老师对我们是百般的关心。上课时，他常常像幽灵一般忽然浮现在窗口。每当我看到他时，都会不由自主的坐到板正。有一次他巡游的时候，偶然发现有同学在桌子底下玩平板。我注意他的嘴角弯了下来，不再带有微笑。她的眉毛皱成了八字，表情十分的严肃，我立刻心出一种不祥的预感。果真下课后他来到了班级，把刚才看到的事情告诉了我们，并且告诉我们下次不要再让我看见。语气中略带一些严厉。当时班里鸦雀无声，没有一个人敢说话，连窗外树叶沙沙的响声都能听得一清二楚。\n虽说张老师严厉，但他也有关心我们的一面。上周五，我们班的小王被跳绳打伤了眼睛，痛苦万分，眼睛都被流水浸湿了。待我们回到班级，张老师便赶了过来，询问小王的情况如何。现在的张老师脸上没有一点严肃，满是焦虑与关心，就像换了个人似的。同样是在周五，妈妈给老师发了一条消息，刚一收到张老师便来来报告，我点了点头。中午吃完饭，尽管他急着去开会，也不忘也不忘再提醒我一下，生怕我忘记了。听到这儿，我心里感到暖暖的。\n张老师就是这样的一个老师，有时严厉，有时和蔼，但我依旧喜欢他，希望在未来的两年里，依然能是我们的班主任，依然能为我们平平无奇的学校增添一点乐趣。\n\n20250304\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3449, 'DV7EYSGme9ujLdqoxCKSLy', 3, '2025-11-09 15:00:06', '2025-11-09 15:00:06', 'NORMAL', '大家好，今天我的演讲主题是踏青。\n\n清明节是一个怀念的日子。在清明节期间，我去了香港、澳门和珠海。这是我人生第一次坐飞机，有些紧张。\n到珠海后，我们在酒店住了一个晚上就出发去了香港。途中经过了港珠澳大桥，走了45分钟。在香港打打卡了星光大道，看到了许多名人的手印如成龙、周润发…还看了浅水湾，号称天下第一湾。\n在香港一共待了两天。第二天是自由行，我们选择了去香港迪士尼，坐了刺激的过山车，玩了有趣的旋转小飞象，看了精彩的狮子王演出，还吃了美味的冰淇淋。最重要的是，还观赏了烟花秀。\n又一次穿过了港珠澳大桥，到了澳门，澳门很小，又叫赌城，政府还会定期为市民发钱。\n在这里，我们看到了三巴牌坊，它被大火烧的只剩下一面墙，是澳门标志之一。还看了仿建的巴黎铁塔。晚上我们去了官也街，吃了牛杂和猪扒包。酒店也很好，还有一个大泳池。\n最后一天，我们去了珠海打卡了渔女像，据说渔女手里捧着的是定风丹，所以珠海从来没有出现过台风。之后还参观了罗西尼钟表博物馆，了解了钟表的历史。\n清明时节雨纷纷，希望大家都度过一个快乐的假期，并在今后的日子里勇往直前，努力奋斗。\n谢谢大家\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3450, '7XYip4FUA4NTdwJ4ogMnpu', 3, '2025-11-09 15:05:37', '2025-11-09 15:05:37', 'NORMAL', '终于，我读懂了你\n\n读到阿长，让我想起了奶奶。她和阿长很像，也爱唠叨，而且语气也不好。\n小时候，他很喜欢把我裹成粽子，而我却一而再，再而三的把它踢开。他也会一而再，再而三的回来。\n渐渐的，我和父母搬进了城市，每两年去见他一次。每次到他那儿都会站在门口等着我们，还帮我们把行李搬进了屋子。每次睡觉前都会打一个圆润的饱嗝。\n一天晚上，我半夜起床时发现他还在院子里干了什么。我蹑手蹑脚的躲在后，躲在柱子后，暗暗地观察他。正在这时她他一回头，忽然碰见了我，吓了一跳说：“都几点了还不睡？”我只能灰溜溜的跑回去睡觉了。第二天桌子就多出了酥脆的馓子。\n回家时，他恋恋不舍的挥着手，还不时的搬来一些土特产放进了我们的后备箱，直到把它装得喘不过气来。坐在坐在车上，眼角不禁泛起了泪光。也许是还没有在这儿玩够吧，也许是对爷爷奶奶的不舍。\n那一刻，我终于读懂了她。你那大声的唠叨，不仅是对我的教育，也充满了对我的关爱。\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3451, 'NZoYRfYQVNM5wrUqLaFsFp', 3, '2025-11-09 15:12:46', '2025-11-09 15:12:46', 'NORMAL', '在温暖下重新绽放\n\n“吾家喜县枝头树，朵朵花开淡墨痕”。初遇梅花，只见那一朵梅花像一个小小的笑脸，一朵朵梅花聚成一束，像一束阳暖阳照进了我的心房。\n寒假将至，而距离演讲比赛也不远了，而我却因为整天闲游被妈妈修理。一怒之下，我气鼓鼓地走出了家门。\n小区里公园里人烟稀少，百花不像春天那样争奇斗艳，百鸟也不再争鸣。此时，我觉得我就要与这世界融为一体。\n未见其花，就先闻见了一股细细的香气，跟随着自然的指引来到了一棵雪白的梅花下。我仿佛已经尝到了那淡淡的芳香。我伸出手想摘一朵，但我没有摘，我不希望这样的美丽就这样消失。我在那树下久久矗立，抬头仰望树冠与天空。\n回想起几年前的这里，也曾有过这也曾有过这样茂密的梅花。可不知为何，叶子慢慢变黄了，花瓣也在不知不觉中凋零了。后来竟只剩下一根光秃秃的树干。而如今他又重生了，长得甚至比曾经更艳丽更浓密。正在这时，天空变得明亮了，一缕阳光射了下来，被雨珠打湿的梅花在阳光下闪闪发光，我转过身，加快了步伐。\n回到家。我坐在书桌前，静静地把往事回顾。演讲比赛如约而至。我在台上看台下的观众，不禁感到无比的自豪。我用那激情的演讲和那有趣的互动赢得了观众雷声般的掌声。\n结束后的第一件事就是去看那一束梅花，它还是依旧的动人。\n在几天前的今天，我在这梅树花下迎头仰望，它就像一片冬日里的暖阳，照进了我的内心，也照亮了我前方蜿蜒的路。\n\n#作文 \n\n', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3452, 'hYcVFrYmh8Gy35KAY27vrr', 3, '2025-11-09 15:23:36', '2025-11-09 15:23:36', 'NORMAL', '终于，我读懂了你，\n\n“你怎么回事？怎么才考这点分？”我低下头，不敢说话，就像一只被猫吓破了胆的老鼠。\n那只猫便是妈妈。妈妈的脾气很奇怪，时好时坏，令人捉摸不透。所以每次我们都不敢随便说话。\n他的声音很大，我和爸爸都感到厌烦。\n可自从那件事后，我对他的情感发生了变化。\n那是一个夏天，蝉在树上知了知了的鸣叫，青蛙在池塘里开着演唱会，小虫小虫在草间伴奏。而我却还在被即将比赛的节目折腾的焦头烂额。\n终于熬到了比赛的当天。妈妈开着车把我送到了比赛的现场。一路上不停的唠叨。\n到那后报到，登记，练习。随着时光顺着绳间流逝，我渐渐变得紧张，失误也变得越来越多。终于明白所有的事情，只有当你失去时才会珍惜。\n当广播喊到我的名字时，我跌跌撞撞地走到了舞台。面对人们期待的目光，我几乎不敢睁开眼。但总要面对现实。我向评委鞠躬，开始了我的表演。跳绳在空中胡乱的飞舞，我注意到评委的眼神变得严肃，我的心提到了嗓子眼儿，又一次想到了他。\n结束后，我遇到了他，我悲喜交加。妈妈拍拍我我的肩膀，像猫一样温柔的说，这只是第一次，后面还会有机会的，家里还有礼物等着你呢。听到礼物，我立刻把所有的烦恼丢之脑后，随之上了车。\n到家后，书桌上摆着放了一块“金牌”。那一刻，我终于读懂了他，眼泪在眼眶里打转。我转过头抱住她。\n虽然她脾气古怪，虽然他声音大，虽然他爱唠叨，但他始终是爱我的。后来他每天看向我，我总会微笑的表达感激\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3453, 'XYwPCovAHRcynU7aCwWCUD', 3, '2025-11-09 15:58:02', '2025-11-09 16:02:50', 'NORMAL', '今天 2024年 4 月20日，今天上英语课时，老师告诉我们：“我去泰国玩了，还给你们带了礼物。”休息时，老师就把礼物发给了我们。有鳄鱼肉，有点像牛肉，有榴莲糖，很甜，还有芒果树铅笔，红色的。长大后，我也想去泰国玩\n\n#日记 \n', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3454, 'hCpedzYqJP4jeJvTuYV4yu', 3, '2025-11-09 16:00:03', '2025-11-09 16:02:40', 'NORMAL', '今天 2024年 4 月23日，今天第二次抽小马宝莉彩虹包，（5元一包），居然抽到了一张VR卡，加四张R卡，加一张TGR卡，概率是4:20。VR是音韵公主的，TGR是苹果嘉儿的美人鱼，还中了一张阿芝士三明治。\n经过妈妈店生腌传奇时，还买了一根冰棍儿。今天真是太开心了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3455, 'HCST2UEHyc94yyidVA67SU', 3, '2025-11-09 16:02:31', '2025-11-10 11:40:13', 'NORMAL', '今天是2024年4月26日，今天上完跳绳课我又去买卡了，今天买的是一个两元包和一个5元包，5元包空了(4张r卡，一张sr，一张Tr，)两元包中收到了一张紫悦的SSR，还是不错的。\n看来下次还是抽两元的比较好。对了，我们又吃了冰棍\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3456, 'cETFefs4f36wbHv5NfWTVH', 3, '2025-11-09 16:06:50', '2025-11-09 16:06:50', 'NORMAL', '今天是2024年5月12日，今天是贺宇宣的生日，我送给他一个笔盒和两只毛盲盒笔，还给自己买了一个两元包小马卡，抽中了一张云宝的VR哇\n\n我们这次居然是在外面吃烧烤，叶展琪妈妈为我们准备很多好吃的。吃完后，我们还去河里摘莲蓬，摘了桑葚和枇杷。后来，我们又骑着自行车在那里溜了好几圈，看了贺宇轩爸爸钓鱼，还和他一起捕捉到了几条迷你大的小鱼仔。\n美好的一天就这样结束了，\n作业还没写完\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3457, 'T7TzbNgBs96Re2ZkL8eutX', 3, '2025-11-10 11:41:38', '2025-11-10 11:41:38', 'NORMAL', '今天是2021年6月23日(周三)，\n小鸭子\n\n今天妈妈下班回来说，今天我给你们带回两个小家伙。我和弟弟赶紧说，快给我们看看。只见妈妈拿出了一个纸盒子，里面有两只小鸭子，一只黄色的，一只黑色的，十分可爱。小鸭子不喜欢吃东西，吃也只吃一口。我喜欢小鸭子\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3458, 'Rrf6ovtZKmniuxwthLx2wU', 3, '2025-11-10 11:44:17', '2025-11-10 11:44:17', 'NORMAL', '今天是2021年6月24日(周四)\n去上班。\n\n今天我一早起床，爸爸就说我今天带你去上班好不好？太好了，我说。\n吃完早饭，爸爸就带我去上班了。路上，我们上了一座大桥，桥好高，桥下是一条马路，马路上有来来往往的车辆。\n终于到了爸爸的公司了。公司的路真绕，像一个迷宫一样，终于把电瓶车推到了地下的车库，原来电瓶车也有车库。我们走到一个电梯面前，爸把脸对着电梯右边的一个机器人刷的一下，电梯的门就打开了，真神奇。\n时间一分秒的过去了。到了中午吃过午饭，爸爸带我去健身房。健身房里面有好多东西，跑步机、台球桌、乒乓球的，…\n下次我还要来上班\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3459, 'CjHrQwWdRQUf4pRLuedV8s', 3, '2025-11-10 11:46:27', '2025-11-10 11:46:27', 'NORMAL', '今天是2021年6月29日(周二)\n自己在家。\n\n今天爸爸说，你一个人在家好不好？为什么我问爸爸说，因为你老是是在公司里跑来跑去的。好吧。我说，\n这是我第二次一个人在家，我感觉好无聊。12点的时候，妈妈回来了。妈妈给我做了午饭，吃完午饭，妈妈就走了，我一个人就出去了。我一个人坐在床上看一会儿书，就去写作业了。写完又继续看书。14点的时候，妈妈下班了，我终于不用一个人在家了，\n我不喜欢一个人在家\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3460, 'eXf39qPWMJsRuTUbESeFp4', 3, '2025-11-10 11:48:06', '2025-11-10 11:48:06', 'NORMAL', '今天是2021年6月30日(周三)\n洗袜子。\n\n今天妈妈给我买了几双新袜子。妈妈说，你可以把这些袜子洗了吗？我说，可以，\n我来到卫生间，先把袜子放在盆里，再用香皂在袜子上涂了一点，再一直搓，一只袜子就好了。等所有的袜子都洗洗好了，再用水冲一下就好了。\n最后，我把袜子一个一个的晾在阳台上。\n今天真开心\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3461, 'BPEmzPn3DkoMfcxZRj4mnk', 3, '2025-11-10 11:50:28', '2025-11-10 11:50:28', 'NORMAL', '今天是2021年7月3日(周六)\n反思\n\n今天下午妈妈下班回来了。妈妈问我们要不要喝鲜奶，我说要妈妈给我倒了一碗，还给弟弟倒了一碗。\n喝奶的时候，弟弟和我是用吸管喝的。弟弟总是把奶吸到吸管里，然后把尖的那一头放在嘴里，使劲吹，把奶喷的我一脸都是，我觉得好烦人，就吓了他一下。弟弟被吓了一下，赶紧把吸管往嘴里放，结果就把嗓子戳烂了。\n喝奶的时候不应该打闹，也不要用吸管喝，用手捧着碗好好的喝，我不应该吓唬弟弟\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3462, 'V2rnAsFfg5Kt7WAbvWp4gh', 3, '2025-11-10 11:53:58', '2025-11-10 11:53:58', 'NORMAL', '今天是2021年7月7日(周三)，\n去别人家写作业。\n\n今天爸爸把我和和弟弟拉下床，爸爸刷牙洗脸就开始吃饭了。\n吃完早饭，我们就去杨文浩家。杨文浩家就在我们左边一栋楼上，二楼就是他家了。\n到了杨文浩家，我们先跟阿姨打招呼，就进去了。我进去的时候，杨文浩已经在写作业了。我问杨文浩，你这是第几页？他说，这是第二页，我们的计划是每天每本写3页，一共9页。我也拿出作业本来写，写着写着，我们听到咚咚的敲门声。阿姨去开了门，原来是王昕彦来了，于是我们三个人就在一起写作业了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3463, 'GLJUHE7kWZHp7Zpo3PFWWv', 3, '2025-11-10 12:51:35', '2025-11-10 12:51:35', 'NORMAL', '今天是2021年7月16日(周五)，\n上魔方课。\n\n今天上午，妈妈就让我和王昕彦一起去上魔方课。\n在路上，我们看到了杨文浩，就和他一起进去了。\n到了教室，我们三个人坐在一起。我们先复习一下前一节课讲的内容，然后又上了今天的内容。我拼着拼着，居然把魔方都给拼好了。\n后来，我们三个人都可以复原了，\n快下课了，我们三个人比了一次赛，我是第一名，王昕彦第二名，杨浩第三名\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3464, '23wMjcVtCKhmYUfTFjTW8U', 3, '2025-11-10 12:52:33', '2025-11-10 12:52:33', 'NORMAL', '今天是2021年8月9日(周一)\n打羽毛球。\n\n今天下午，我和小姨一起出去玩，刚好妈妈也回来了。妈妈同意我们出去玩。\n到了楼下，我们开始打羽毛球。打着打着，下起了小雨，一会儿又不下了。就这样，我们就一直打。终于大雨来了，我们只能回家了。今天真开心\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3465, 'CMDKkar97iTMAZe3DVHCLC', 3, '2025-11-10 12:55:10', '2025-11-10 12:55:10', 'NORMAL', '今天是2021年8月10日(周二)\n把尿撒了\n\n今天早上我们准备出去玩的时候，弟弟打了王毅杨一下。王毅杨打了弟弟一下，最后弟弟说要把王毅杨打死。王毅杨跑进房间，把门关上了。弟弟也追了上去，还故意把自己的小鸭子马子给提啥了，尿撒了出来。小姨把尿擦干了，我们就出去玩了。\n弟弟以后可不能这样了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3466, 'ibFjzBormkikEHHnnJDMFQ', 3, '2025-11-10 12:57:14', '2025-11-10 12:57:14', 'NORMAL', '今天是2021年9月1日(周三)\n上学\n\n今天是9月1日，是开学的第一天。首先，我来给你们介绍一下我的老师，我的语文老师，他姓崔，崔老师，我的数学老师姓王，王老师，我的英语老师姜老师，她姓姜。\n第一节是语文课，语文课下课，我们我们去操场看开学典礼，我们看了八二班的表演，真是太精彩了，等到所有的课都上完的时候，我们就可以放学了。我喜欢上学\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3467, 'Th77UioeQbpNNWaHL7XKka', 3, '2025-11-10 12:59:01', '2025-11-10 12:59:01', 'NORMAL', '今天是2021年9月5日(周日)\n上篮球课\n\n今天下午五点，我爸爸和弟弟一起上篮球课。到了上篮球课的地方，我发现那里一个学篮球的都没有，但是有很多叔叔在那里打篮球。过了一会儿，所有人都来了，我们一起投篮。我一共投进了五球呢，终于上课了。教练先让我们先运动跑三圈，左手两圈，右手两圈。接下来，让我们做基本的练习，投篮。就下课了。今天真开心\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3468, 'W3x3YTW2GV35GxrHPPkvRq', 3, '2025-11-10 13:00:40', '2025-11-10 13:00:40', 'NORMAL', '今天是2021年9月17日(周五)\n上学\n\n今天轮到我和孙浩泽检查了，所以我今天很早就来到了教室。七点不到我就进了班。我发现早来就是不一样，我来的时候一个四年级的都没有，都是一些高年级的。我们那栋教学楼也十分的安静，就像晚上一样。我进了班级，看见我的同桌张玉存已经来了，他在写同步训练，我也把同步训练拿出来写了，没一会儿同学们就陆陆续续的来了。\n今天是我来的最早的一次，以后我都要这么早来\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3469, '5PjfL2eyA4ymL7b2Ffyd6G', 3, '2025-11-10 13:05:11', '2025-11-10 13:05:11', 'NORMAL', '今天是2021年10月2日(周六)\n国庆趣闻\n\n今天早上我一起床就听见爸爸说一会儿吃完饭我们就去博物馆。到了这里，我高兴的从床上跳了下来。真的吗？真的吗？真的吃完饭就去。爸爸说太好了，我要快点吃完饭。\n终于吃完饭了，爸爸开着小汽车带我们去了博物馆。到了博物馆，哇，博物馆真大呀，我说。终于进了博物馆，一进门我们就看见了一幅一幅跟一面墙一样大的画，画上有山有水，好看的很。接着，我们来到一个展厅，展厅内有四季地星座，不同的季节地星座是不一样。接着我们去了二楼，二楼有古人用的盘碗杯子…，还有两个游戏机，一个是找相同水器的，一个是写成语的，真好玩，然后我们去了三楼，三楼是一些古建筑 其中我最喜欢的就是四世宫堡了，四世宫堡的4根柱子，四根柱子上各有一头大石头狮子，好看极了。\n我喜欢博物馆，下次我还要来\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3470, 'be6UHi2jcSEgriwbmUs53P', 3, '2025-11-10 13:09:41', '2025-11-10 13:09:41', 'NORMAL', '今天是2021年10月12日(周二)\n上学\n\n今天是星期星期二。我七点 20多就到了教室。我发现了一件事，我是我们组第一个来的，连我的同桌张钰存都没有来。过了一会儿，张钰存、陈宇轩、余默然都来了。等所有人都到齐的时候，我们就开始换座位了。我坐到了倒数第二排，\n很快就到了下午要数学考试了，我十分的紧张，害怕考不到90分。上课铃响了，数学老师来到了班级。他的手上拿着试卷发试卷了。我看了看试卷，哇，密密麻麻都是题目，我的眼睛都看花了。题目不但多，而且还非常的难，尤其是最后一题附加题一共有三小题，我只写出了一题，两道题不会。\n很快就到了最后一节课。最后一节课是美术课，终于可以用刮画纸了，上课了。美术老师说，今天我们要用刮画纸刮一幅画。在刮画纸上刮出什么都简单，就是刮人难。一节课完了我连一个人都没有画完，\n我喜欢上学\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3471, 'L3VuJkpEFd3BGqf6tJcMnF', 3, '2025-11-10 13:12:34', '2025-11-10 13:16:15', 'NORMAL', '2021 年 10 月 21 日\n写给革命英雄王二小的一封信\n\n今天是中国成立72周年，我们现在的幸福生活让我想起了放牛娃王二小。你是一个跟我差不多的小男孩，\n有一次你放牛的时候，来了许多日本鬼子。他们对你说，你能带我们去见八路军吗？你没有理会他们，继续放着牛。日本鬼子又问还用枪指着你说，你到底带不带我们去见八路军？你想了一会儿，说好吧，我带你们去见八路军。你走在前面，飞快的跑着，没一会儿你就把日本鬼子带进了八路军的的埋伏圈里。没一会儿，日本鬼子就全死了。剩下的日本鬼子十分生气，十分生气，就把你给射杀了。\n你非常勇敢，有了你，我们才能过上这样的幸福生活，才能有饭吃，才能住在这么好的房子里，你是我们的榜样\n\n\n亲爱的王二小，\n你好，\n你用你的爱心帮助了许多人。有一次，在你放牛的时候，来了许多日本鬼子。他们对你说，你能带我们去见八路军吗？你没有理会他们继续放着羊。日本鬼子又问，还用枪指着你说，你到底带不带我们去见八路军？你想了下，说，好吧，我带你去见八路军。你在前面飞快的跑着，没一会儿，你把日本鬼子带进了八路军的埋伏圈里，没过一会儿，日本鬼子就死了一大半，剩下的日本鬼子十分生气，就把你也射杀了。\n你非常的勇敢，有了你，我们才能过上这样幸福的生活，才能有饭吃，住在这么好的房子里，你是我们的榜样\n\n\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3472, 'PxuWe4igzVHkQSAFWAhpZ6', 3, '2025-11-10 13:16:53', '2025-11-10 13:16:53', 'NORMAL', '今天是2021年10月30日(周六)\n小乌龟\n\n小乌龟睡觉的样子十分的可爱，四肢又短又粗的，小脚丫向着四个不同的方向伸去，嘴巴一张一张的，十分可爱。我喜欢小乌龟\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3473, '8PpHgvetnLn7irsZG3jC6K', 3, '2025-11-10 13:17:48', '2025-11-10 13:17:48', 'NORMAL', '今天是2021年10月31日(周日)\n\n小乌龟的身上长出了许多的小斑，越来越明显。我觉得小乌龟是要冬眠了。果然，小乌龟中午就睡觉了。小乌龟还会自己挖土，他用又短又粗的小脚丫挖出了一个小土坑，住在了进去。小乌龟真厉害，我喜欢小乌龟\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3474, 'QdqNL56ZXovvLYovWDnaod', 3, '2025-11-10 13:21:13', '2025-11-10 13:21:13', 'NORMAL', '今天是2021年11月4日(周四)\n小乌龟\n\n今天早上我出去跑步，发现树上有许多的蜗牛。于是，我抓一只较大的蜗牛回了家，放在小乌龟的盆里。只见乌龟一屁股在蜗牛身上，用小爪子死死的按住蜗牛。最后，乌龟一口把小蜗牛吃了下去，真厉害，过了一会儿，小乌龟好像要睡觉了。果然，没一会儿，小乌龟就睡着了。小乌龟睡觉的姿态可真可爱，它的四肢又短又粗的，小脚丫向着四个不同的方向伸去，真可爱，你们觉得呢？\n突然我发现小乌龟的壳上有一个个小黑点，像是生病了。于是我便把小乌龟盆里的水倒掉，去小区挖了一大桶沙子，倒进了小乌龟的盆里。小乌龟身上的黑点渐渐的消失了，真神奇啊，小乌龟还没有醒呢，他睡得真沉。还是不要叫他了吧。\n我喜欢小乌龟，你们喜欢小乌龟吗\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3475, 'DTccqDQ7sGk3cf2xJkU2wJ', 3, '2025-11-10 13:49:03', '2025-11-10 13:49:03', 'NORMAL', '今天是2021年11月7日(周日)\n小金鱼\n\n今天早上，我上完写字课回到家，发现小金鱼在鱼缸里游来游去，好像饿极了。于是，我就倒了点鱼食给小鱼。小鱼嘴巴一张一张的吃着鱼食，好像十分喜欢这个鱼食。\n我喜欢小金鱼\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3476, 'd8k2a88sHCmshEH6Eifz7Z', 3, '2025-11-10 13:50:02', '2025-11-10 13:50:02', 'NORMAL', '今天是2021年11月20日(周六)\n小金鱼\n\n晚上。我吃完晚饭，发现小金鱼在鱼缸里一动也不动，可是眼睛却瞪得大大的，像是在睡觉，又像是在发呆。后来妈妈告诉我，鱼是没有眼皮的，所以鱼睡觉的时候是睁着眼睛的。原来是这样，小朋友，你们知道小金鱼为什么睡觉时会睁着眼睛了吧\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3477, 'jysJT3RzU6szdrDJSyTZUH', 3, '2025-11-10 14:05:53', '2025-11-10 14:06:22', 'NORMAL', '2021年11月30日\n白天鹅红珊瑚\n\n宁可一日无粮，不可一日无书。下面由我来给大家推荐一本好书，名字就叫做《白天鹅红珊瑚》。这本书讲述了有一只年轻的雌天鹅，全身洁白，名叫红珊瑚。\n灰肩雄成了红珊瑚的配偶。所有的家务都由灰肩雄来做。一对雏鹅出事了，她也基本甩手不管。\n一天上午，灰肩雄带着两只雏鹅下到湖里觅食，忽然芦苇里伸出了一只三角形的蛇头来。这种蛇名叫中华水蛇。灰肩雄还没来得及躲闪，就被中华水蛇咬了一口。过了一会儿，他全身变得僵硬，沉入水中。没有了灰天雄雏鹅们很快就也被苍鹰吃掉了。\n青宝和豆蔻是刚满一岁的年轻天鹅，就在他们的宝贝快要出时，不幸被一只红狐吃掉了剩下的4枚天鹅蛋红珊瑚把它们养大。就在两只天鹅出世的时候，飞来了一对凶恶的乌鸦，把两只可怜的天鹅吃进了肚子。剩下的两只天鹅分别叫做青青和蔻蔻。\n有一次，红珊瑚带着青青和蔻蔻正慢慢的向岸边游来，就在这时，湖面上出现一道黑影，是一只水獭。所有的雏鹅都上了岸，只有青青和蔻蔻还没有上岸。红珊瑚下了水，搏斗了起来。他的左脚被水獭咬断了。\n眼看就要就要到冬天了，可是青青和蔻蔻还不会飞，不能飞去南方。于是，红珊瑚想把富有经验的乌尾雄留下来，终于把乌尾雄留下来了。雏鹅也学会了飞翔，与乌尾雄一起飞去了南方。\n我们不要总是去依赖别人。\n\n\n#日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3478, 'XsTLatfdtE5XQp2fTkCwbt', 3, '2025-11-10 14:29:33', '2025-11-10 14:29:38', 'NORMAL', '跳蚤市场\n\n今天下午的最后一节课，也就是班会课的时候，我们的跳蚤市场就正式开始了。\n下午第三节课的铃声刚刚打响，我们就把自己的东西拿出来摆在桌子上。我卖的是泡泡胶，英语本，皮筋…，没有几秒钟，我的泡泡胶就卖完了。卖玩泡泡胶以后，我就再也没有卖掉任何东西。快下课了，我想我应该去看看别人都卖了些什么，买一点。于是我就去了程雨宣的桌子旁边看了看，觉得那盒糖果好像挺好吃的，就买了一盒，才一块钱，挺便宜的，\n今天真开心\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3479, '7CwjkiLg8MfX4WtR5triRW', 3, '2025-11-10 14:34:45', '2025-11-10 14:34:45', 'NORMAL', '2021年11月30日，\n许小河就是美。\n\n我家对面有一个小公园，名叫许小河。暑假里，爸爸带着我一起去许小河。\n一进门，我就闻到了一股清香。爸爸告诉我，这是桂花的香味。我们继续往前走，果然看到了好几棵桂花树。\n对面有三块长方形的大石头，上面写着许小河的由来。\n再往前走，就是别人种的油菜花田了，金黄金黄的油菜花，像一大块金黄的金子，又像金黄的地毯。\n再往前走就是咕咚泉了。咕咚泉是我为这个喷泉取的名字，因为这个喷泉喷水之后会咕嘟咕嘟的响，所以这个叫咕咚泉了。\n再往里走，是一片桑叶林，只要是家里养蚕的人都可以到这里来摘所需要的桑叶。\n对面有许多钓鱼的人，我也好奇的过去看了看，哇，许小河有好多水草，水草里面有好多小鱼，水面上还有可爱的水蜘蛛。\n突然，我看见一个大龙虾在往岸上爬，好辛苦啊，就让我来帮帮他吧。于是我拿起大龙虾的一根胡须，使劲一提，大龙虾就被我提上了岸。原来是个龙虾妈妈，她正在生小宝宝，我喜欢我们的许小河，你喜欢吗\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3480, '8LEZxBiBGhqamspzEanJ57', 3, '2025-11-10 14:39:11', '2025-11-10 14:39:11', 'NORMAL', '2021年12月7日\n假如我拥有超凡的力量\n\n每天我都会和弟弟因为和爸爸玩而吵架。所以我就很想要更多的爸爸。有一天，我来到学校，发现忘带语文书了。我急得团团转，心想完了完了，要是老师发现了怎么办？我都快急哭了。突然，我一不小心摸到了同桌的语文书，霎时，我桌子上就出现了一本和同桌一模一样的语文书。\n上体育课的时候，我忘带了跳绳，结果又摸到了同桌的跳绳。没一会儿，我手里就又有了有了一个黄灿灿的跳绳。\n放学后，我高高兴兴的跑回家，把这个消息告诉了妈妈。妈妈说，这下好了，你和弟弟终于可以不为爸爸而吵架了。是呀，这样我回答道。\n晚上爸爸回来，我对爸爸说，现在我只要我摸到我想要的东西，我就能变出一个一模一样的出来，那你现在就能变出一个我吧，你不是一直想要两个爸爸吗？好的，我也是这样想的。我说，于是我摸了一下爸爸，另一个爸爸出现了。我这个我和真爸爸玩，弟弟和假爸爸玩。\n真开心，现在终于不用为少爸爸而发愁了。\n我喜欢我的超凡力量，你们想学吗？如果想学的话，欢迎来我家\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3481, '9SyN3QmoEHm6d2oZGtpCoK', 3, '2025-11-10 14:44:00', '2025-11-10 14:44:00', 'NORMAL', '2021年12月14日(周二)\n彩虹课堂\n\n星期五，老师就要带我们去体验彩虹课堂了。终于等到了星期五，我们坐着大巴出发了。在大巴车上，我们唱起了许多歌，有踏山歌、半山雪、穷叉叉、超能力。\n没多久，我们就到了少年宫。老师把我们分成了两组，第一组和第二组。我被分到了第二组。\n终于可以进进到少年宫里了。首先，我们体验急救自护，急救自护老师给自己起了一个十分好玩的自然名叫做青蛙。于是我们便称他为青蛙老师。青蛙老师给我们说了许多急救的小知识，其中我最喜欢的就是心肺复苏了。心肺复苏是30次按压加5次人工呼吸是一组，按压的时候，两只手要放在两个乳头中间。人工呼吸是把自己的嘴放在别人的嘴上往里吹气。如果那个人的肚子动了，就说明你做的是正确的。\n第二站是剪纸课，剪纸课是在二楼，终于不在一楼了。到了剪纸教室，老师先给我们讲了该如何剪。老师说，你们只要把我画叉的地方剪下来就行了。就像这样。说完，老师就给我们每个发了一张彩纸。彩纸上画着一只小企鹅，真可爱。剪完后，老师还给我们拍了一张合影，我喜欢彩虹课堂，你们喜欢吗？\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3482, 'af5BizcJuUJ7KcuGwJQpvj', 3, '2025-11-10 14:49:54', '2025-11-10 14:49:54', 'NORMAL', '2021年12月24日\n两人三足\n\n大课间的时候，崔老师带着我们去了操场。你知道我们去操场干什么吗？猜对了，就是去玩两人三足。\n很快就到了操场。首先，老师让昨天他在语文课上选的人出来比赛。过了一会儿，人员都来了。老师就让我们分成两排，女生在左边，男生在右边。很快，我们就排好了。只见老师把手举过头顶，依次摆出了三二一开始，话音刚落，同学们就出发了。他们的动作各不相同，有的慢慢的走，有的飞快的向前跑，可能是害怕得不到第一名吧，还有的就更厉害了，跑的都要飞起来了。比赛结束了。\n第二局开始，第二局是自己想参加就参加，我也参加了，和聂梓涵一组，还是一样，老师把手高高的举过头顶，摆出三二一开始，话音刚落，我和聂梓涵就冲了出去，奇迹般的拿了第一名。我们晋级了。\n当然了第三局就是那些得了第一名的同学去比了，好紧张。第三局比赛即决赛开始了，同学们的心都飞快的跳着。比赛开始了，我和聂梓涵使劲儿的跑呀跑呀，可还没能得到第一名。看来想拿第一名还是很难的，那时候我要继续努力\n\n\n\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3483, 'ArCb89jPZbNhkKqtRUoY2Q', 3, '2025-11-10 14:55:05', '2025-11-10 14:55:05', 'NORMAL', '2024年12月23日\n\n亲爱的朋友，你好，很高兴能和你写信。我是合肥市师范学院附属西安路学校的程明月。你来过我的学校吗？知道我的学校是什么样子的吗？如果不知道，那就听我给你讲讲好吧。我的学校有三栋教学楼，A楼、B楼和C楼。A楼里都是五六七八年级的同学，B楼都是一二三四年级的学生我也在这里。A楼和B楼之间还有一大片空地，空地上有乒乓球桌，下课了学生们可以去那里打乒乓球。C楼是社团教室，等放学以后我们就能去那里上课了。B楼和C楼之间也能打乒乓球。我的学校还有一个很大的操场，每天的大课间，我们都会到操场上跑步做早操。体育课的时候，我们还会在操场上跑步玩耍。操场的后面还有一栋楼，这是体育老师的办公室、教学楼和和操场中间还有一个很大的广场，这就是中心广场了。一年级的学生在这里做早操，中心广场的中间还有一排银杏树。秋天它们的叶子金黄金黄的，就好像黄色的小扇子，中心广场的前面有一方鱼塘，鱼塘里有许许多多的小金鱼在自由自在的游着。前面就是中央图书馆了。上图书馆课的时候，我们就能进去看书了。图书馆你有琳琅满目的书，怎么也看不完。这就是我的学校了。你的学校是什么样子的？\n祝好好学习，天天向上，\n四五班程明月\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3484, 'FbKk2gzUjAiHfdgB96rHuo', 3, '2025-11-10 14:59:59', '2025-11-10 14:59:59', 'NORMAL', '2022年1月11日\n想起那件事我就紧张\n\n我紧张的时候，心会砰砰的跳，我害怕的时候，心会砰砰的跳，我激动的时候，心儿会砰砰的跳，我惊喜的时候，心也会砰砰的跳。下面就让我给大家讲一讲，我心里砰砰跳的去试吧，\n期中考试过后的第二天，上课铃一响，同学们就立即回到了座位上，有的同学还在下面窃窃私语，过了一会儿，老师来了，教室里立刻就鸦雀无声。老师说，这次我们班考的不是很好，只有3个100分的。我的心都提到了嗓子眼儿里，怀里像揣着一只小兔子，砰砰的跳个不停。心想，我有没有考100分呢？如果没考100分，那会是多少分呢？过了好久好久，老师还没有叫到我的名字，我不禁害怕起来。突然，老师喊说到程明月，这次考了…我的心里打起鼓来了，完了，完了，这次我考的一定很差。我想，老师接着说，程明月考了100分。我高兴的合不拢嘴，兴冲冲的跑到讲台上拿了试卷。到了讲台上，老师说，blackboard的前面不要加空格。我的心提到嗓子眼了，害怕老师把我的分数改了，幸好这次只是提醒。\n你的心儿，什么时候会砰砰的跳啊\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3485, 'BG6ukwKFbfZMyM5WFtyjax', 3, '2025-11-10 15:02:59', '2025-11-10 15:02:59', 'NORMAL', '2022年2月18日\n体育课\n\n昨天的天气不是很好下小雨，所以我们的第五节课体育课就只能在教室里上了。因为是在室内，所以老师就和我们玩了一个游戏，叫你演我猜，游戏规则是这样的，首先邀请一男一女上讲台上来演。演什么呢？当然就是演老师告诉你的啦，直接说可能会被讲台上的同学听到，于是老师就把要讲的内容打在手机上，给讲台上的人看，看完后再表演出来，让讲台下的同学来猜，猜对了还有奖励。老师一共让同学们演了十几个，可是我一个也没猜对，\n你们玩过，你我猜吗\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3486, 'T8NLtEkVGh58dpL5dmj3Ke', 3, '2025-11-10 15:07:18', '2025-11-10 15:07:18', 'NORMAL', '2022年3月11日\n我的小秘密\n\n三八妇女节就要到了。我打算送给妈妈一个惊喜。今天是星期六，我要上画画课。老师说，你们认真的画，画的好，可以获得积分。积分多的话，可以换礼物。我们的礼物是什么呢？有男孩子们喜欢的乐高，卡片，女孩子喜欢的项链、手链。老师回答，哇哦，真多呀，我感叹道，突然，我想到了一个点子，心想，快到妇女节了，我送给妈妈一个礼物吧，就选个手链吧，妈妈一定会喜欢的。这是个惊喜，我可不想让妈妈知道\n你们想送什么礼物给妈妈呢\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3487, 'GvTHdJdYnYVTpxtC3Mqrm2', 3, '2025-11-10 15:09:06', '2025-11-10 15:09:06', 'NORMAL', '我的小发明\n\n每个人都有自己想发明的东西，当然了，每个人想发明的东西都是不一样的。我想发明一个会变大变大变小的书包。\n这个书包里有许许多多的按钮，按钮上都有汉字，有的是铅笔，有的是钢笔，有的是尺子，有的是教科书，还有的是文具盒。它的形状像一个巨大的黄色的正方形馒头，\n它的功能可厉害了。例如我按下铅笔这个按钮，书包里\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3488, 'TadjpwS6gnNRHyYs3dkBja', 3, '2025-11-10 15:14:25', '2025-11-10 15:14:56', 'NORMAL', '一件快乐的事\n\n2022年2月26日是我的生日，我已经等了很久了，\n终于等到了，我这一整天都十分的着急，什么都不想做。终于第一个客人王昕彦来了，他送给我一个手账本套装。我和她等了很久，却没有人再来了。我们决定去楼下等等，果然没一会儿就来了第二位客人余默然，他送给我几张贴画，几张胶带和一把紫色的美工刀，忽然妈妈打过来一个电话，说程雨宣和赵涵晨已经到了，我怎么没看见？算了，不管了，先回去再说吧。到了家，程雨宣和赵涵晨果然在家里。我我提议道，不如等我们把饭吃好了再下去等梁敬喆吧。OK, 他们说。诱人的美食一盘盘的被端上了餐桌，我们根本停不下来，大口大口的吃着。把去等梁敬喆的事忘得一干二净。等我们吃饱了才想起来要去等梁敬喆。可是现在我们已经不想去了。晚餐结束后就到了玩耍的时间，我们一蜂窝的跑到门外玩起了游戏。\n今天真是快乐的一天\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3489, 'kaUKkXXtVTr9Z8zdfCrr2o', 3, '2025-11-10 15:18:08', '2025-11-10 15:18:08', 'NORMAL', '2022年3月22日\n乡村生活\n\n如果有人问我，你最想去哪里玩？我会毫不犹豫的告诉他，乡下。记得有一次暑假，我爸爸和妈妈弟弟去一起去乡下。乡下离我们这儿并不远，三～四个小时就到了。\n一下车，我就奔向奶奶说，奶奶，我们去玉米地里摘玉米去吧，我最喜欢摘玉米了。好。奶奶说完，她便开着三轮车带我们去摘玉米了。到了玉米地，我就看见一个个又大又胖的玉米挂在玉米杵上。这个玉米肯定很好吃，我想。我把玉米的大叶子掰开，把金灿灿的玉米掰了出来。不一会儿就把三轮车装满了。我们开着装满玉米的三轮车回到了家，\n正巧妈妈在做饭，我们把刚掰下来的玉米递给了妈妈，说，妈妈，你把我们刚掰下来的玉米榨成玉米汤吧，肯定会很好吃的。好，我现在就给你们炸，妈妈说。玉米汤榨好了，雪白雪白的玉米汤真好喝，我要多喝一些。\n心想，乡下真好玩，下次我还要来玩\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3490, 'eydTLfGyjygkvgYUnPfr9P', 3, '2025-11-10 15:22:01', '2025-11-10 15:22:01', 'NORMAL', '2022年3月28日，\n校园的一角\n\n你们最喜欢校园里的什么地方呢？我最喜欢的是操场。操场的中间部分是深绿和浅绿相间的，有生机勃勃的感觉。操场的外面一圈是一条红色的跑道，一共分为四个段，最外面一圈是单杠、双杠和一个小沙滩。这个小沙滩是在我们跳远的时候用的，\n每次上体育课的时候，我们都会来到操场，先在红色的跑道上跑两三圈，然后再做热身操。做完热身操后，再跳3组跳绳后就可以自由活动了。每次自由活动的时候，我们都非常的高兴，因为终于可以想玩什么就玩什么了。\n我玩过许多的游戏，我最喜欢的就是跳大绳的，首先要两个人拿着绳子，另外几个人跳都行。一开始我还有点不太会，一跳就会被绳子缠住，可是慢慢的也不知道是怎么了，就能跳过去了。\n我喜欢在操场上玩\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3491, 'X9bNLad337cVhzCh29Bv2a', 3, '2025-11-10 15:24:58', '2025-11-10 15:24:58', 'NORMAL', '2022年4月6日\n第一次划船\n\n这是一个阳光明媚的日子。我爸爸妈妈和弟弟要去塘西河划船了。\n我们开着车，有说有笑的出发了。到了塘西河，我们直奔沙滩而去。哇，这里有好多人呢，我们选了一个红色的船，这只船是用脚踩的。船在水面上一晃一晃的感觉好危险，哪里危险了。爸爸说说完，他便一脚踩了上去，真的没事儿，过了一会儿，我妈妈还有弟弟也上去了。我说我想踩。好妈妈爽快的答应了。我双脚踩着踏板，手抓着方向盘，真好玩。妈妈说，不如我们去桥下看看吧。好，我答应了我开着船向桥下开去，风在我们身边的呼呼的吹，可是我一点儿也不觉得冷。桥下的人可真多呀，数都数不过来。\n时间不早了，我们也该回家了，我下次还要来划船\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3492, 'HbRydcLUjQhfxsZaU8vCkU', 3, '2025-11-10 15:25:48', '2025-11-10 15:25:48', 'NORMAL', '我的动物朋友小乌龟，\n\n今天王昕彦来我家，我要向他介绍一下我的小乌龟。\n小乌龟的样子十分可爱，\n它非常贪吃，\n它非常喜欢游泳。\n这只小乌龟真让人觉得可爱，因为它给我带来快乐\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3493, '6P4M6g4dVc2HVQaLd7HrCu', 3, '2025-11-10 15:30:40', '2025-11-10 15:31:01', 'NORMAL', '2022年5月9日\n五一趣事，做凉皮\n\n今天是五一假期的第三天，再过两天就要开学了。\n中午爸爸正准备做饭，我便立刻跑过去对爸爸说，爸爸，我们做凉皮吧，好啊，爸爸说，首先我们要准备做凉皮的材料，两个铁盆，一盆水，一个盛水的碗和一袋面粉。材料准备好后，我们就开始做凉皮儿了。我们首先需要盛两勺面粉，再把面粉倒进其中的一个铁盆里，之后加上水，使劲的搓揉，揉到一半我就揉不动了，可是还没没有揉好，因为因为爸爸说要揉到很软才行。我揉了差不多一个小时了，终于好了\n第二步是洗面，我们要先把揉好的面拿出来放在另一个铁盆里，在盆子里倒上水，等洗到水几乎变透明就行了，洗完面后我们需要静静的等上10分钟。等过了10分钟就可以开始蒸了。首先，我们需要油和一个铁盘。先在铁盘里刷上一层油，再在铁盘里中倒入从面里洗出来的水，放进锅里，过个几十秒就好了。好了之后，只需要把凉皮拿下来就可以了。拿下来后，需要把凉皮切段，加上自己喜欢的蔬菜就能吃了。你没有自己做过饭吗\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3494, 'aHFybZFnwGKNwFTqVLPMjk', 3, '2025-11-10 15:33:46', '2025-11-10 15:33:46', 'NORMAL', '2022年5月13日\n湿地公园\n\n周末，我爸爸妈妈和弟弟去湿地公园。我们开着车不一会儿就到了。\n进入公园大门，首先映入眼帘的是三个小喷泉。小喷泉很小，只有一个轮胎那么大，但是它喷出来的水却有一丈高。\n绕过喷泉就到了车站。车站里有自行车、旅行车，走出车站就到了树林。树林里有一条用鹅卵石铺成的小路，小路旁边都是翠绿的高高矮矮的大树。进去后从外面看都看不见。\n走进树林就到了儿童乐园。儿童乐园一共分为两个区域，左边是攀爬区，右边是玩耍区。左边区域有一个攀爬架，上面有一架飞机。飞机是可以爬上去的，爬上飞机后，从飞机上往下看，地上的人就只有蚂蚁那么小了，玩耍区有秋千，各种各样的，有的是正方形，有的是圆的，有的是三角形，有的是长方形，有的是双人的。\n湿地公园真好玩，下次我还要来玩\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3495, 'Vg6HFZU4fp923HTQ5ritvn', 3, '2025-11-10 15:35:28', '2025-11-15 14:00:34', 'NORMAL', '2022年5月17日(周二)一周总结\n\n今天是星期日，又到了练字的时候。练完字，我拿给爸爸看。爸爸看我满意的点点头。写完字就开始写作业了。写完作业，我又拿给爸爸。爸爸却板了脸说，你写字的时候都能写得好，为什么写作业的时候就不行了呢？因为写作业的时候我写的太快了。我说。爸爸接着说，写字不在于快和慢，在于你的用心程度。听完爸爸的话，我对爸爸说，爸爸，你放心，以后我写作业的字一定能和练字是一样\n\n#作文 ', 'PRIVATE', 0, '{"tags": ["作文"], "property": {}}'),
(3496, 'iDscMsc9echc7SHSVATnW4', 1, '2025-11-10 15:58:17', '2025-11-12 18:16:24', 'NORMAL', '今天是2025年11月10日(周一)还款的日子 \n昨天把果果房间书架给整理了一下。把一格给空出来。 书桌拾干净。我在上面扒了一下午还觉得挺舒服的。又找到了一个好的学习环境。\n整理果果的本子发现他之前的作文本。就把作文本里面的。内容放到memos 上。本以为是很简单的一件事情。原来还是很需要时间的。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3497, 'dt8m763SJBvrTs7Vx3V7ww', 1, '2025-11-12 18:21:43', '2025-11-14 10:28:44', 'NORMAL', '今天是 2025 年 11 月 12 日(周三)，这 2 天在弄边缘计算的事cloudflare 的搞定了，国内没发访问翻墙才可以，今天搞腾讯的没搞好郁闷。\n在弄录题的事也郁闷在电脑上鼠标太难用，用平板代替数位板发现画的位置根本没法确定了太难用了，认真看她的需求可以用试用版的，看的不认真，真是的。工具的使用呀。\n用平板录制发现不用电容笔写的太丑了，控制的还是不好，等那天果果把电容笔拿回来了再试吧。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3500, '6qqMT5VJd3UTAihZ4vRfhF', 1, '2025-11-14 10:10:20', '2025-11-14 10:10:20', 'NORMAL', '今天是2025年11月14日(周五)，这2天整了pages相关的，把cloudflare的和腾讯的edge给玩明白了，还挺简单的，玩了好久真是挺笨的发现自已挺笨的。\n果果这两天期中考试，挺重视的，希望能考好，给自已信心，让自已觉得自已也可以考好，我相信她，小学能考双100，初中希望能满分100考90就可以了。\n早上手机亏电了，只剩余1%开机，结果充不了电了，搜了下说是电池休眠了，用小功率的电充，用慢充的头还不行，需要用电脑的usb口充，真充好了，开心，学习到了新技能。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3501, 'MhbzTHVYJtmB4MavqdnsWZ', 3, '2025-11-15 14:02:06', '2025-11-15 14:02:06', 'NORMAL', '今天是2022年1月18日(周二)上班，\n\n今天是个晴朗的日子。早上等爸爸去送弟弟上学，我才起来。我起来了，爸爸刚好也回来了。爸爸给我盛一碗饭，吃完饭，我就要和爸爸去找妈妈了。\n到了妈妈的公司（生鲜传奇），我没看见妈妈，于是我就把书包放进了办公室。我放好书包走出去之后，就看见了妈妈。于是，我悄悄地走到妈妈身后，一下子抱住了妈妈，把妈妈吓了一跳。妈妈说，去写作业吧，OK, 我说。\n到了办公室，我发现有一个小弟弟也正在写作业。于是我在他的对面坐了下来，写起了作业。不知不觉，我就把英语作业写完了，真是个奇迹啊，写完作业，我就开始画画画了一会儿，我就坐不住了，好想回家呀，\n我再也不想去上班了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3502, 'Lj3qLJDJDgM2dNomWvqEMM', 3, '2025-11-15 14:04:41', '2025-11-15 14:04:41', 'NORMAL', '今天是2022年1月19日(周三)，上学与放学\n\n今天要领成绩单了。我6:50才起来，吃完早饭，我们就下了楼。\n到了楼下，我发现了一件事，我们小汽车的车玻璃都冻住了，看来今天有点儿冷啊，我们开着车出发了，可这车玻璃上在太白了，路都看不清了。于是爸爸走下车，把车玻璃擦了一遍，车玻璃终于不是白色的，还没高兴多久，我们又看不清了。这回车玻璃不清楚了，为什么还是看不清呢？原来是前面有雾，不过这雾也太大了吧，都快什么也看不见了。我们只能慢慢的开。\n终于放学了，是妈妈开电瓶动车来接我的。放学了还有很多的雾，但是比上学少了很多。过了一会儿，我们就到了妈妈上班的地方。生鲜传奇，\n我一点也不喜欢雾\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3503, 'bsXZuH6UV86gEAbaF83jVJ', 3, '2025-11-15 14:08:41', '2025-11-15 14:10:21', 'NORMAL', '今天是2022年1月31日(周一)，放炮。\n今天晚上爸爸带我们去放烟花。一出门我就想起运动还没有打卡，于是又回家拿羽毛球。幸好到了楼下，天还没有黑，打完了卡，我们就开始放烟花了。弟弟想出一个有趣的玩法，在烟花的一头一次性放两个。弟弟还给这个有趣的玩法起个响亮的名字双头炮。我觉得这个玩法很有意思的，就也跟着玩了起来。一开始，我连拿都不敢拿。好不容易才玩完了一根。可是就在我要玩第二根的时候，爸爸打火机伸到我身边，说想把我变成双头炮。我吓得一下子扔掉了手里的烟花。玩了一会儿，我又对妈妈说，我们散散步吧，等我们走了一圈，等我们走了一圈回来的时候遇见了我的同桌张钰存，他们也是下来放炮的，但是他们一共带了3种不同的炮一是烟花、二是摔炮、三是旋转烟花（我不知道它的名字），我最喜欢的是旋转烟花，因为它能像陀螺一样旋转，在旋转时还会发出不同颜色，十分的好看，有时转得太快还可能会飞起来。你们喜欢什么烟花呢\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3504, 'YnWySKNitzm23Yu9JZ83wU', 3, '2025-11-15 14:10:14', '2025-11-15 14:10:14', 'NORMAL', '今天是2022年2月1日(周二)，出去玩儿。\n今天是星期二，我们要去融创茂，\n离我们一点也不远，开汽车20分钟就到了。到了融创茂，我们就进了酷玩城。里面有许多玩的设施，我印象最深刻的就是钓鱼了。玩这个游戏，我一共获得了5枚超大的扭蛋，一共花了我28个游戏币，就剩三个游戏币了。该玩什么呢？要不就玩抓娃娃吧，真是好运，第一次就抓到了，今天真的太开心了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3505, 'esHyW8yGb6EW74p2W92nPS', 3, '2025-11-15 14:11:13', '2025-11-15 14:11:13', 'NORMAL', '2022年2月13日(周日)反思，\n不推弟弟，\n不打弟弟，\n让着弟弟，\n分享东西，\n不抢弟弟的东西\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3506, 'GkYgBvHCKYnuWdo48rFruj', 3, '2025-11-15 14:16:38', '2025-11-15 14:18:23', 'NORMAL', '今天是2022年6月30日(周四)，去上班。\n今天是一个阳光明媚的日子，一大早我就被爸爸拉起来去举办散学典礼了。\n终于开始了，我都快急死了。过了一会儿，老师来了。老师说今天我们要开跳蚤市场，开跳蚤市场，我高兴的跳了起来。幸好我带来了班豆，不然就玩不了了。\n跳蚤市场开始了，同学们都把自己从家带的零食玩具都摆在桌子上，可是我什么也没有带。不过没关系，我可以买。说完，我就开始买东西了。我这买买买，那买买买，不一会儿就只剩下10块班豆了。看着这么多的玩具，真是开心，跳蚤市场结束了，我也到了放学的时候，可是妈妈却怎么也没有来我等呀等等呀等，可是妈妈依旧没有来，于是我就和我的同学玩了起来。我们玩的是猜颜色。第一局我摸到了黄色 他摸到了蓝色。第二局我摸到了黑色，他摸到了红色。我还是没有猜对。后面三句局我还是没有猜对。过了一会儿，我妈妈就来了，我我跟她匆匆忙忙的骑着车去他的公司生鲜传奇。终于到了，我走到生鲜传奇的大门就看见一个小弟弟。原来啊，那个小弟弟的妈妈是妈妈公司里的员工，所以他才会来到这里。了解了解了情况后，我们就互相介绍啊，原来他叫盛明强，才二年级。介绍结束了，我们就开始玩游戏。我们玩的第一个游戏叫鬼抓人。我发现他虽然才是二年级，可是速度却并不慢，时间不早了，我要回家了，我又变成一个人了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3507, 'nyrvNWZuCAxd6RUCeKtz9c', 3, '2025-11-15 14:18:13', '2025-11-15 14:18:13', 'NORMAL', '今天是2022年10月15日(周六)，反思\n今天下午，我和王子涵、吴章卓、孙浩泽、余默然和汪军一起去地下室车库骑自行车。我们骑的很快，不一会儿就没影了。\n我们一直玩到了晚上，等爸爸来找我的时候，怎么也找不到结果，把整个小区找烂了。终于，他在物业门口发现了我。\n到了家，妈妈告诉我地下车库车很多，那里骑自行车不安全，听了妈妈的话，我发誓，我再也不会自己去地下车库了\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3508, 'BSjLmqLrGEjT5hiTXveWTD', 1, '2025-11-16 15:42:24', '2025-11-18 15:51:46', 'NORMAL', '今天是2025年11月16日(周日)，果果和他同学去步行街玩 说要玩密室逃生。\n敬和加加去骆岗公园里面的儿童乐园玩了。\n下午和加加一起做了拼豆的玩具，真伤眼睛脑子嘿。做出来还可以，回收塑料有毒。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3509, 'ST5BABgNshSDEZfdYLHJKu', 1, '2025-11-18 15:55:07', '2025-11-18 16:07:21', 'NORMAL', '今天是 2025 年 11 月 18 日(周二)，昨天电容笔到了，试了下讲课发现敲击屏幕的时候有声音，而且写字的时候容易断，感觉录课这碗饭还是不好吃的，要不怎么一直有招聘的，说明很多都是不合格的。\n发现免费二级域名 dpdns.org 在国内可以访问，微信也可以直接访问，开心。cloudflare 的 worker 的绑定也整明白了开心，耶\n刷视频找到了蜂小推这个平台，原来才发现夸克的资源分享是可以赚钱的。通过他们分享的点击注册，阿克可以获得一个T的空间，正常注册只能用10个G\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3510, '9zFavPvkXYuYspUZUSRmwP', 1, '2025-11-19 11:32:24', '2025-11-19 14:55:10', 'NORMAL', '今天是 2025 年 11 月 19 日(周三)，前 2 天好冷，今天暖和了风也小了，去公园打羽毛球脚疼，回家看下，干裂了，嘿涂点香香\n看录题的公司招聘标题的，了解了下发现还是没那么简单的，考核没过，这点活都干不了觉得挺笨的。还能干什么呢。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3511, 'WCh3nLkRidpXhz2KkhsuGh', 1, '2025-11-21 15:50:11', '2025-11-21 15:50:11', 'NORMAL', '今天是 2025 年 11 月 21 日(周五)，昨天在果果房间陪读，楼下的 10 点半多又一惊一乍的，可能之前没在次卧待过那么晚不知道吧，今天和物业沟通了，找了哈哈的音频晚上在听到，一早就把音响放蓝牙音响放出去，在屋里一直循环着放，不信睡那么晚早上还会起那么早。\n今天开家长会，敬给我找事干，到学校找语文老师挨批评，好紧张。\n加加老师说上课和同桌说话，罚站到后面了，给他换同桌了，我相信我家的不会调皮的，肯定是邻桌的问题那个小女生话多的很。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3512, 'mztwjUkPjVh8Ua9nd3MmoL', 1, '2025-11-23 18:23:40', '2025-11-23 18:23:40', 'NORMAL', '今天是 2025 年 11 月 23 日(周日)，习惯了这种生活了，也不想着找程序员工作了，也找不到，发现挣点钱挺难得。\n中午围棋课结束之后去公园画画了也没画啥，到家吃的面条，\n敬这 2 天都挺忙的，好几个试听的，期中结束了，家长会一开家长焦虑想着报班了，也就这周了，下周\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3513, 'WsYAtdJnq5mKpLUwkkLFnT', 1, '2025-11-25 16:44:46', '2025-11-25 16:55:38', 'NORMAL', '今天是 2025 年 11 月 25 日(周二)，阳台的窗户之前 2 扇玻璃扣在一起打不开了，今天终于分开了，开心\n昨天在客厅睡，刮风阳台的纱窗成就扣的不紧给我吵醒了，就想着弄好，加加有些咳，敬和他一起睡了。\n网盘分享收益了 7 元，最起码有收益，不骗人。这挣的也太少了，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3514, '6MzabRTeFFRHnznAjuskvP', 1, '2025-11-26 18:02:37', '2025-11-26 18:02:37', 'NORMAL', '今天是 2025 年 11 月 26 日(周三)，白天整了下关于网盘资源做成网页的项目，找了 2 个比较满意的，可是问题又出现了，怎么让用户知道你的网站是个问题，嘿挣点钱不好好搞呀。挺笨的花了不少时间。\n加加来开看有的班主题是合伙人见面会，比较有创意。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3515, '6uCtZJkGeQBiwsC3RZefTv', 1, '2025-11-28 12:54:36', '2025-11-29 09:01:27', 'NORMAL', '今天是2025年11月28日(周五)，一早去公园把自行车给安装好了，别天整了半天没整明白，骑了下还挺不错的，\n最近再弄cloudflare的问题，服务器只配置了http没配置https，发现域名只有http的可以访问，https的不行，折腾了半天原来是ssl配置的问题，不能选择完全要选择灵活模式。这样就好了，还搞了各种重定向还没研究明白，怎么重定向的，娘的，坑呀，\n要给敬长工资到 8000 元，敬和贝贝妈说不要加没干啥压力会大，几天前我还想一年了加不加工资呢，我是希望加的生活宽裕些，交保险就 4w 多了只靠敬的工资生活费就没啥了，今年有离职的补助好些，晚上说长 1000不给那么大压力，嘿真是第一人会觉得工资多的？替别人着想她挣得肯定比你多多了，觉得自己的劳动不值钱。想到雷军直播一帮穷鬼给百万富翁打赏。自己过的紧巴巴，还不愿涨工资。今年这样了下次啥时候还不知道呢，嘿别人已经觉得你可怜了。\n业绩做梦还梦关于工资的事，想开了，2 小孩都在那里学习，也是不小的费用。说不定能留个好印象呢，以后\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3516, 'KE5WQeyuFVWSxMEKQsBpjp', 1, '2025-11-29 10:17:04', '2025-11-29 20:24:15', 'NORMAL', '今天是 2025 年 11 月 29 日(周六)，昨天加加夜里咳嗽厉害，敬过来陪加加睡，我去外面了，早上起来嗓子难受，突然不好的预感流感了，麻烦了。就怕严重了，去庚玖一趟吃点药，赶紧好起来。在家也带口罩吧，加加这 2 天咳嗽。流感季节家里还是要防的不能，家里外面都一直带着吧。\n抽血做流感检测阴性的，可能是假阳性，那些流感的药，退烧药备用了，\n加加上完英语课后，说腿酸，让她睡会，敬回来量体温 38 去庚玖了，拿了小孩吃的奥司他韦，回来了一样2 天就能恢复了吧。\n在庚玖时柳说要把租房的给注销了，说是租给别人了，后想不会是卖了吧。\n#日记', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3517, 'HtSrNXyVLvWeXDEe7jHibp', 1, '2025-12-01 14:49:46', '2025-12-01 16:07:27', 'NORMAL', '今天是 2025 年 12 月 1 日(周一)，一早就想今天要把电话卡的事给弄下，把敬现在用的手机卡给注销了不可以在领取奖励了，结果通知每月返回 10 元就纠结了只要 19 元每月了，联通开通流量 10 元 4g 的一会有一会没的，后也不纠结了按计划取消了开通联通的流量了，先用一个月看看吧，不够了再从新办个流量卡吧。\n嗓子还是不舒服，这该死的流感。在接写吃药，把药吃完吧，我很怕严重了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3518, 'ZcyGexypSF3zrvAThwQBtg', 1, '2025-12-05 09:43:15', '2025-12-05 09:47:10', 'NORMAL', '今天是 2025年 12 月 5 日(周五)，日子过的好快好快呀，不知不觉 12 月就这么多天了，月末领去旅游滑雪的日子就近了。\n最近天冷早上我也不送娃们了，都敬送的。感冒还没好彻底夜里还咳了嘿。赶快好起来了吧，天都暖和了。\n网盘分享搞钱在小红书发，压根没用搞不到钱，但现在一共才不到 15 块嘿，搞点什么挣钱呢。\n昨天做几道物理题感觉脑子不够用的。要看清楚范单位。同种物质对应。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3519, 'f6TsG4qckbse2DkU96igSg', 1, '2025-12-09 12:08:09', '2025-12-09 12:08:09', 'NORMAL', '今天是 2025 年 12 月 9 日(周二)，约好了 1 月 26 日去上海复查做ct，\n上周五接果果放学送她去上数学课的路上被车撞了，8 号周一去处理对方的责任，嘿周五还不承认自己错，调监控不嘴硬了，责任确定后去 4s 店修车，打车回来的，\n敬昨天感冒了，嘿冬天为啥这么容易感冒呢\n今天早上准备的早饭感觉我好久没准备过早饭了，果妈辛苦了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3520, 'MEnStsCgMu2w77puz5g8cT', 1, '2025-12-11 08:48:03', '2025-12-12 08:48:03', 'NORMAL', '今天是 2025 年 12 月 11 日(周四)，加加放学带他去公园逛玩，要上厕所口袋里只有一张纸，怕不够用的，去驿站买一小包 2 块心疼坏了，真贵在在网上买不到 1 块。\n到点接果果，到家热饭着急包子没热透，打的豆浆也凉了。加加吃了说肚子疼自责。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3521, 'mwUf74C5cVpYaZBYcdG3R4', 1, '2025-12-12 08:52:08', '2025-12-12 13:08:58', 'NORMAL', '今天是 2025 年 12 月 12 日(周五)，\n中午带敬去包河苑办移动卡了，把之前联通的给取消了，2016 年 11 月份办的 9 年了，移动有划算点的就转走了，谁让我改给 5g 流量的套餐就不让改的，同样的价格有流量宽带也提速了没有不换的道理不确定 3 年以后多少钱了别调成 59 了，那可就是后话了那是说不定收入多了或有别的活动再转走去他大爷的。就是耽误敬上班了中午没去成。\n顺路去物华车开回来了，\n\n早上敬回来生果果的气，晚上要和果果聊聊，\n决定早上让她自己去上学。\n穷的日子，努力学习\n字写大点好看些\n小白兔小黑兔的事，不招人喜欢\n挤出时间，效率，复习，卡壳，份数问题\n周计划，周任务\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3522, 'UQT3JkHoVfvkthQpJg7oSD', 1, '2025-12-18 10:16:19', '2025-12-20 07:53:26', 'NORMAL', '今天是 2025 年 12 月 18 日(周四)，前几天洗澡暖风开关坏了电源开关按不下去了，几年前就不好用了从网上买了个，昨天研究了半天线改如何接，敬送果果加加在吃饭我在家里鼓捣还真接好了，可以用，后想了下暖风每次都一起开，可以把旧的暖风 1 和电源的开关换一下，2 个暖风用一个开关一起控制不就好了吗，还想着就的留着备用后想不知多少年呢，就用旧的新的退了吧搞定开心省了 30 块。\n最近在搞怎么看电视直播，整播放源的事还有在 kodi 中输入电视源，想做个短链一下午搞定觉得挺笨的电脑用的不溜。直播源准备使用github 的 action 定时抓取在研究下吧找到了开源的项目研究下。\n换成移动的宽带光猫没有 wifi 功能必须配路由器用之前老的好多年了。昨天电脑发现在房间里信号不好，拿到外面了也不好，前天果果学校的平板连不上 wifi 不忍了买个路由器。一个月省 10 块，这下一下 130 没了，想网快了信号强了也值得。毕竟还多赚个路由器呢\n晚上澳汀陈振说欧洲服务器的 80，433 端口开了，是我开的，可不能承认嘿，以后再也不搞定这些了。\n敬回到家说她看到校门口家长评理，校园霸凌的事，嘿说了就心烦，如果我家孩子遇到了不知该如何处理。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3523, 'JtgwUhvc9JqL8U36B34mm8', 1, '2025-12-19 09:33:26', '2025-12-19 09:33:26', 'NORMAL', '父爱则母静，母静则子安，子安则家和，家和万事兴。\n父懒则母苦，母苦则子惧，子惧则家衰，家衰败三代。\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3526, '5hYyZ5caRjy6WbffdRHyFV', 1, '2025-12-23 22:21:03', '2025-12-23 22:21:03', 'NORMAL', '今天是 2025 年 12 月 23 日(周二)，前一段时间牙疼，最近腰疼休息一会就好了，希望是因为休息运动少出门少，天冷休息不好的事，\n昨天做了不好的梦，梦见我癌，可是我白天从没想过这事呀，慢慢的忘记了怎么会梦到呢，而且还有和我同样的情况的 11 年去了。\n最近整小网站能了短链接，blog ，iptv 直播源，还有免费的 docker 仓库的事挺好用的不同的地址对应不同的端口，接下来不知道干嘛了。\n明年还趁着机会找工作上班吗，家庭开支不够花的呀，虽是够花的没存款，以后怎么帮衬孩子呢\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3527, 'P6NfN8ZYkCAa6pQdm8NrgN', 1, '2025-12-25 15:57:52', '2025-12-27 16:29:08', 'NORMAL', '今天是 2025 年 12 月 25 日(周四)圣诞夜，这 2 天决定学 2 建准备报考，挂靠至少能混个保险要不等到 27 年的时候，没保险了要自己买，又是一笔钱，对我来说保险是刚需呀，这样一来回一个月就省 1k 呢，挂靠还能拿些钱，再报名费和培训费 1800，后期审查抽到了 3000。要花不少的时间精力想想还是考吧，闲着也是闲着。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3528, 'jSuze6vXqnTcdzZebP9Z4g', 1, '2025-12-27 15:58:09', '2025-12-27 15:58:09', 'NORMAL', '静静的小溪，藏在通往儿童乐园的小路旁。冬天来了，岸边的青草已经枯萎，只剩下一地浅黄。溪边散落着许多石头，要想到达对岸，就得踩着这些石头慢慢走过去。\n \n石头的一部分埋在泥里，一部分浸在水中，还有一小截露出水面——那就是路。浸在水里的石头周围，长着一圈细细的绒毛，大概是水里的微生物吧。\n \n现在是枯水期，水很少，只是慢慢、慢慢地流淌着，安静得几乎让人察觉不到它在动。水很浅，也很清澈，一眼能看到底，却找不到一条鱼。\n \n古人说：“水至清则无鱼。”我这才真正明白——正因为没有鱼搅动泥沙，溪水才会这样清澈。\n \n小溪安静得有些孤独，可我愿意常来陪它。等明年春天，我再来看看它。\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3529, '5Mijj7AV4nQTGgk4tuRnpo', 1, '2025-12-27 16:37:32', '2025-12-27 16:37:32', 'NORMAL', '今天是 2025 年 12 月 26 日(周五)，这两天中午敬参加西安路学校的开放日，我在家收拾好听去年的二建课了，听会法规还挺上头的老师总结的很好，真要自己看书是挺费劲的。\n下午敬回来告诉个消息说社保不是一直挂在一个企业的，最长一年几个月就会换单位不用了就要等下个，还会中断的，搞得好心烦意乱，也听敬的意见扒拉扒拉一堆也不知是想让我考还是不想。\n算了不考了还是命重要，以后社保实在不行交灵活就业吧一个月 230 多，现在觉得一个月挣 3000 都好难。希望能找个在家可远程开发的工作 5k 就可以。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3530, 'W9o5gbUFCM9SinjqLhGmbn', 1, '2025-12-27 18:57:01', '2025-12-27 22:01:55', 'NORMAL', '今天是 2025 年 12 月 27 日(周六)，中午娃们没课睡醒了脑子很清醒开心。\n夜里做了奇怪的梦，手机的屏幕碎了，好奇怪呀，之前也做过同样的梦，手机屏碎了。\n中午带加加去公园，想去看看儿童乐园吧，整个公园就那里人多，想有生之年居然还能走到这里真的不易呀，11:20 多往回走，加加下午还要上英语课，到家累屁的了，加加是拽着拉回来的。吃过饭娃们上学了我睡觉了。睡了一个多小时敬送过娃买菜回来。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3532, '8oyXmEETmAjbdsoQUuK72a', 1, '2025-12-31 20:52:44', '2025-12-31 20:52:44', 'NORMAL', '今天是 2025 年 12 月 31 日(周三)，25 年的最后一天了，郁闷的一天本想用那个工控机做电视盒子的，没有很适合的方案，直接用 Android  x86 没声音，蓝牙才可以，用 bliss 没声音蓝牙还打不开，想切换回 Android  x86 发现引导又整不好了，看了买个好点的盒子才 300 块，折腾个啥呀，一天也没好好的休息，去他大爷的。\n加加上午上课下午搞了晚会，玩的很嗨，回来饭都没吃几口，回来洗澡没出去。天气不好刮大风了，夜里有雨夹雪，希望明天能看到雪吧，今年跨年是不顺利了。\n敬和果果不知玩的应该挺嗨，看还抓到了鱼，她们也没给加加打电话怕加加想她们吧，加加也没闹着找妈妈真棒我小时候可不愿意和我爸一起待着。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3533, 'BEEtFsWxchjMJcRr6p437E', 1, '2026-01-02 11:35:59', '2026-01-02 11:35:59', 'NORMAL', '今天是 2026 年 1 月 2 日(周五)，在小区看发现桃花开出花骨朵了，这是天气要变暖和了吗，\n中午加宝写会作业，一会写一会玩的也没写多少，效率低的很。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3534, 'YGP6oPocXHickdiGC9uRxK', 1, '2026-01-05 18:07:38', '2026-01-06 09:53:31', 'NORMAL', '今天是 2025 年 1 月 5 日(周日)，在搞图片备份的事，昨天敬说她手机满了，就给她整下把图片放在阿里云盘了忘记怎么弄了没找到快的方法折腾了一会，她要放到硬盘里放在网上她说不安全。就想到了之前搞的飞牛了，今天知道了怎么扩展硬盘了，原来有 2.5 的硬盘位，把后盖打开硬盘插进去就可以了开心。2.5 的机械硬盘便宜多了，主要是知道怎么扩展了，可惜了之前把笔记本扔了，把里面的硬盘抠出来现在用多好。\n一天天不干啥，有些焦虑。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3535, 'GpF9CToF5wyNFpyQQw75QA', 1, '2026-01-06 09:56:40', '2026-01-07 11:48:24', 'NORMAL', '今天是 2025 年 1 月 6 日(周二)，最近嘴又长口腔溃疡，头上也长疙瘩了。虽然不疼，之前都忘记了自己生病了。还想着找工作呢。\n再整照片的事想把图片按年份放到不同的文件夹下结果好些照片视频的创建日期本就不对，这下好了还是错乱的，至少把重复的给删除了，大部分是对的吧。\n下午接加加没接到，还挺紧张的还以为今天是周一呢，想也不该值日呀给老师发消息打电话才知道今天是周二加加再值日，天天过的晕乎乎的。\n去物业拿米了上次交物业费没礼品了说到了。嘿看着信用卡待还的心烦呢。没点收入，敬还想没月存点。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3536, '2A7xrzB72zwLPpsY7bKAGp', 1, '2026-01-07 11:38:17', '2026-01-08 13:08:14', 'NORMAL', '今天是 2026 年 1 月 7 日(周三)， 今天收到了面试邀请就在小区写字楼希望能成功，能不耽误送娃休息。\n敬公司的手机收走了，幸好昨天把卡还回去了，插在我手机上本想当流量卡用的，要不就臭大了。就为了 省 10 元的流量费，还是自己购买个流量包吧，用自己的安心。\n蘑菇屋说收小学生了教新概念，小学的单独招老师。希望是能小学学完能直接引到初中的，要不这批初中的走了，学员就少了，看样子这几个校区还是盈利的，要不不会扩大呀。\n加加前些时候捡的无患子，它让我把籽给洗干净，挑了些圆的，用电钻打洞做了 2 个手串送给娃们，还是敬想的周到一人一个本只想做一个的。小的反而不好大洞，大的好打些，震得手疼，还挺结实的，主要是圆的不好固定，用钳子夹着固定的，娃们也没想的那么开心。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3537, 'gQ3aZGt39cGyeiqHCQPkKF', 1, '2026-01-08 13:09:39', '2026-01-08 13:09:39', 'NORMAL', '今天是 2026 年 1 月 8 日(周四)，不知道干嘛，早上起来有痰，中午好些了。\n整整做视频的发现还挺麻烦的，还要对口型，啥的，即使ai 也没想的那么简单\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3538, 'NXtKcfkadxmLnLPViQLuRZ', 1, '2026-01-13 15:45:22', '2026-01-13 16:15:12', 'NORMAL', '今天是 2026 年 1 月 13 日(周二)，日子过得很快马上又要去上海复查了，昨天晚上没休息了，想着工作兼职要不要干的事。\n本该今天挂号的结果忘得完完的还以为明天开始预约挂呢，看时已经没号了。嘿加号不要等太久了呀。\n一早和人事说先把合同签了工作性质定了，一直也没回复算了，和那人和不来，影响心情不值得。今天听说那人说面试过我的事，是不是觉得他有优越感，压我一头，把自己放在领导的位置。是我的话我也不愿意在旁边有个大佬，在澳汀面试年龄大的都不要的。不好管理，他和我也是同样的想法吧。\n再找找看吧，不要外包性质的，最好相关的工作只有我一个人。\n把我妈的票和我和敬去上海回来的票买了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3539, '58yGZvqjfRXY89nsq8QTJj', 1, '2026-01-12 15:57:51', '2026-01-13 20:08:30', 'NORMAL', '今天是 2026 年 1 月 12 日(周一)，上午去写字楼的公司看了就一个人聊了才知道是运维 ERP 的，今天他不在我还进不来呢，本想能和那人聊聊能安排号点啥呢。\n9 点多说下车 发代码资料看下。 10 点多走了发过来了，下午去看运行起来了，之前还说不是现成的框架，这不就是吗？只要按尺寸位置放好，数据填充就好了。图什么样式什么的都要自己想着搞。\n16 点多走了，说在自己本地环境搞，把数据库导出发给给，这是不相信我呀，怕我删库跑路呀。\n接加加时，他在群里发消息说晚上加班，比较生硬，不知是不是故意的，也有可能吧，他本就不想要我。\n他说 19 点半我 20 点到没人在群里说了，他说一会到，又说吃完饭拉倒吧说走了，他来 2 个表情尴尬。反正老板也在群里，不知道他怎么看，反正我是开心，至少表达我是授信的人\n说话生硬加班，不守时不开心了，晚上也没休息好。\n接加加去公园看向日葵，向日葵的头都被砍掉了，在那边玩会发现他耳朵流血了，说可能是钻到向日葵丛林划到了。和加加再一起睡夜里总是会醒。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3540, 'nzGyABfifvjHY8JSCi3y3g', 1, '2026-01-10 16:08:41', '2026-01-13 16:08:41', 'NORMAL', '今天是 2026 年 1 月 10 日(周六)，微皖的人事打电话过来说去复试，我还说你那周六不是休息吗？\n到那老板和那个技术的也在，老板是想要的，那个技术的不想要，他又提到面试我的话题，给我搞的一头雾水。他们说项目紧，说最近晚上可以过来，不知怎的就准备干活了，回家还拿硬盘把他那电脑系统给装了，程序环境给装了。问他周日不来公司我也不来，在家呆着吧。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3541, '6VhrQGQaunBu4egkXfXxi5', 1, '2026-01-09 16:12:32', '2026-01-13 16:12:32', 'NORMAL', '今天是 2026 年 1 月 9 日(周五)，去和昌写字楼一家公司面试，面试技术的说面试过我，给我搞一愣，还没见过这么跟我开头的。不停的回忆，然后就说技术的没啥好问的就结束了，我以为就结束了呗，就回去了，按到家楼下了人事说要我回去老板要面试说了我的情况，他一直说干 3 个月试试。就先回去了。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3542, 'AtyoERi9JdyMhEkv4FaZBw', 1, '2026-01-14 12:09:32', '2026-01-14 19:31:05', 'NORMAL', '今天是 2026 年 1 月 14 日(周三)，微皖被踢群了，知道了着急的项目都是坑，正常情况也是入职公司的机会。\n把澳汀代理的密码给改了不能被连接不限制用超了，澳汀在找到我就不好了。幸好之前设置的 22 端口不限制ip，要不还麻烦了。\n就想有什么方案可以把 cloudflare worker 代理浏览器上网就好了。\n果果上周日去配眼镜，今天到了，中午时带果果去码了。一路比较顺利来回 50 分钟，带上后说清晰了些。\n敬今天体检说有囊肿，希望没什么事吧，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3543, '4JUL85wXEZAcSrURc5uitn', 1, '2026-01-16 16:05:52', '2026-01-16 16:05:52', 'NORMAL', '今天是 2026 年 1 月 16 日(周五)，在 zeabur 中配置了 xray 翻墙代理成功了，开心，自己偶尔用下应该不会被限制的，限制禁用了也无所谓用的是小号，没认证啥的就个电话邮箱，能付什么责任。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3544, 'MCVW7r5z8ekyq4e92unmZZ', 1, '2026-01-20 13:15:11', '2026-01-21 15:45:00', 'NORMAL', '今天是 2026 年 1 月 20日(周二)，夜间下雪了，早上起来地上都白了 9 点多停了，果果做公交车去的，加加没去上学。\n夜里睡的不好，不知是楼上吵的，还是想着事情，在弄memo 怎么放到 zeabur 上，要备份还原的昨天没弄好，在想着哪里出了问题，今天算是搞定了，算是在 guthub gitee都备份了吧，还是先用服务器的吧，哪天服务器不能用了再说。至少把 GitHub action 整的差不多了。\n上海挂号的问题 2 月 2 号有号先挂了，不用付钱，ct 不能改到 2 月 2 号在取消。\n最近腰疼不知道是不是因为最近出门少运动少的原因，希望不是因为癌的原因。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3545, 'bQTsKens3xWN3zEHKuVehY', 1, '2026-01-19 13:20:25', '2026-01-20 13:20:25', 'NORMAL', '今天是 2026 年 1 月 19 日(周一)，预报会降温下雪，果果上学和她说让她带着公交卡，下雪了就座公交车会来，放学时下盐子子刮风都没去接，她座车回来的，说公交车晃。\n白天在家弄 memos 迁移到 zeabur 没弄好，没法访问，之前的记录没法恢复，搞的头疼。\n晚上老师放通知明后天自愿去学校不讲新知识复习，本想加加不去了果果去，睡前敬看没几个不去的，跟加加说哭的哇哇的。\n跟果果一起写作业头晕。\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3546, 'jpGNsRAT3EE4FahqRqrDVc', 1, '2026-01-22 12:29:09', '2026-01-22 19:48:03', 'NORMAL', '今天是 2026 年 1 月 22 日(周四)，白天睡了 2 觉，2 天还是 3 天没拉了今天终于拉出来了一点，腰疼躺下去好些，接加加在公园玩会好疼，忍着回家接果果回来，这可如何是好呀，夜里感觉也醒了好几次在床上转来转去的。\n快点好起来吧，心理的预期再一点点的降低，手术还想着能回澳汀上班，后想着能赚点外快，现又想着能好好的能不疼。愿越来越好吧\n今天把关于程序员的公众号都删了。不想在从事相关的工作了，好好的安心的活着吧，看着娃们长大毕业独立就够了。\n最近 2 天好冷接果果看有人在发传单，我拒绝了，想我老婆也是干这个的，她是不是也有好多人拒绝，下次应该支持下，能帮助下就帮助下吧。大家都这样社会会更完美。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3547, 'YvotJaKnbdR3sWxJFVYyia', 1, '2026-01-21 15:43:49', '2026-01-21 15:46:14', 'NORMAL', '今天是 2026 年 1 月 21 日(周三)，夜里没睡好，腰疼后背疼，早上起来更疼了，好担心是因为癌的原因，还想着卡里还有 8 万没花呢。\n中午去公园走走，中午回来睡会睡着了，起来不怎么疼还挺舒服的。起来敬上班去了。\n我把日记的给弄了下，用 zeabur 平台搭建了，不用澳汀的服务器了，备份的都写好了，就这么用吧，希望不出问题，就怕服务重启了，日记恢复到以前的就不好了。备份 GitHub gitee 仓库，邮箱，ALIST 足够了。\n下午接加加怎么晃呀，还去公园吗，我还能走动不，担心去上海一路累疼，赶紧恢复吧，希望是灵说的，睡觉扭到了。和加加一起睡放不开\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3548, 'BcrPodyxTaV8u2nF2JyMFg', 1, '2026-01-24 16:11:08', '2026-01-24 16:11:08', 'NORMAL', '今天是 2026 年 1 月 24 日(周六)，肩膀腰还是疼。在床上有躺了一天，娃们上学都是敬送的，最近明显觉得胀气难受，在吃益生菌，健胃消食片揉肚子，赶快好起来吧，好多天大便都没，要吗就一点点，昨天用了开塞露也拉不出来。\n我妈今天晚上到了，可我很担心明天怎么去上海。一路的颠簸劳累。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3549, 'itX9zDucNJAQnfdNCT3dt7', 1, '2026-01-25 15:11:36', '2026-01-25 15:17:01', 'NORMAL', '今天是 2026 年 1 月 25 日(周日)，昨天腰疼的实在受不了，就想不能再耽误了，去医院看看吧，晚上和敬一起睡的，我妈和加加在一个床上睡的。\n先去的省立核磁检查没人做不了，去了庚玖我是这么想的万一去上海看过ct 报告说要做不就麻烦了，而且医生说的对万一要调药什么的别耽误了，正好今天状态也好一些去吧，不能拖了。\n去庚玖做核磁说没压迫神经，拿点胀气通便的药。希望能缓解吧。\n路上吃过午饭放了几个屁，开心的事。希望晚上去上海一路顺利。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3550, 'N76rnnAodjk6bMgYkgUQKo', 2, '2026-01-26 20:39:48', '2026-01-26 20:41:02', 'NORMAL', '[12223]\n\n\n- [x] 3535\n- [ 12222] \n\n- ', 'PROTECTED', 1, '{"property": {"hasTaskList": true}}'),
(3551, 'i757mZrZ2ZjoLtPEQFt2mf', 2, '2026-01-26 20:42:01', '2026-01-26 20:42:01', 'NORMAL', '122', 'PROTECTED', 0, '{"property": {}}'),
(3552, 'FmqZihTp2Ao3U3gLFd6tsj', 2, '2026-01-26 20:42:41', '2026-01-26 20:42:41', 'NORMAL', '255', 'PROTECTED', 0, '{"property": {}}'),
(3553, 'Xd475GtEBhzeDVK4wzYGDo', 1, '2026-01-27 08:12:56', '2026-01-27 08:12:56', 'NORMAL', '今天是 2026 年 1 月 26 日(周一)腊八节，在上海跑了一圈，CT 检查对比说没什么变化接着吃，因为是加的号看的比较晚 18 点才结束，拿药也没下班了火车还要改签嘿\n\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3554, '63s6XS6ARsimN6NFsQjLxk', 1, '2026-01-29 18:35:33', '2026-01-29 18:35:33', 'NORMAL', '今天是 2026 年 1 月 29 日(周四)，最近腰还是疼，昨天晚上睡的也不好，夜里被手机吵醒了好久睡不着，大腿根还疼，疼的难受。夜里也不管敬该转身就转，她估计也没睡好。\n以后身体会越来越糟糕，还会出其他状况，怎么办呀。\n要快点好起来呀。着急呀，周六我妈回去了，怎么送娃呀，我当然着急了躺一个月，不管怎么说上周四五时好多了，那真是忍着疼接送娃们，现腰不阵疼了。\n只是觉得敬不怎么关心我，老是觉得我装的，她也忙工作也心烦。娃们这几天考试也紧张。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3555, 'MMEQA3E8XNk6oGGKkpank7', 1, '2026-01-31 23:20:25', '2026-01-31 23:26:11', 'NORMAL', '今天是 2026 年 1 月 31 日(周六)，还是好疼，现主要是腿疼，感觉腿部和腰部一样了，一用力就好疼，好想出去逛逛公园呀，拉个痛痛快快的大便，已经 6 天没拉了，虽然通气还是担心呀，水也喝的少了，怕上厕所。\n家里面还是一样的鸡飞狗跳，我妈和敬又不可调和的矛盾，敬总是觉得我妈对她不好，我妈觉得好，可她不知道表现的很明显。给我倒水要给我捏，不达目的不罢休，一遍一遍的在天津时就够够。吃个饭刷锅积极的很，干完了就来回逛晃看的心烦，自己不想着出去走走什么在外面晃晃，就在家撅着，家里人没一个喜欢她的，加加洗澡不愿意让她擦看，果果虽然不嚷她，也不跟她聊说啥。这样对她不好，希望那天我走个她也没那么伤心吧。\n敬上班忙，心烦，还有给娃讲作业，没那多时间管我，理解算了本就是个废人，还给他添堵干嘛，没时间管就不管吧，咬咬牙忍一忍就过去了，心态好一些，他们才是未来。\n知道自己时日不多，想开点我会离去，想开点今会改嫁。孩子吗我也不知会怎样。一家人就散了。敬上班是有钱就存，理解她的焦虑为自己以后考虑为孩子考虑。我妈把钱转给我不直接给敬不是也有她的心思吗，知道是为了我，怕敬不管我了让我有点保障，有个屁用自己都动不了了钱有个屁用呀。大家都都自己的心思。\n一家人心不齐，天天鸡飞狗跳的，怎么能有好的未来。孩子们爸爸帮不了你们，对不起，注定你们也是苦命的，自己努力了\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3556, 'EqWptqWLVmknLgvbhkpsx2', 1, '2026-02-01 08:54:33', '2026-02-01 08:54:33', 'NORMAL', '今天是 2026 年 2 月 1 日(周日)，昨天没睡好，夜里左腿好疼，可能昨天晚上走路多了些吧。\n今天比较开心的事，拉大便了，很顺便好多，看样子乳果糖还是挺好使的，比较温和，要一天左右，不会直接拉稀。亲自做了尝试了，哈哈哈\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3557, 'CKLubuAxgJbBSQJCGKNNvu', 1, '2026-02-03 10:41:50', '2026-02-03 10:44:22', 'NORMAL', '今天是 2026 年 2 月 3 日(周二)，前些天因为数据的问题记录日记的容器重启了导致数据恢复了不能再写了否则下次恢复数据就乱了，今天用 MySQL 当做数据库，想之后可以直接连接数据库备份，目前在数据传输上卡住了，因为数据格式不一致恢复有些麻烦了，嘿事可真多呀，直接写脚本这麻烦呀。明天在想办法吧。\n腰疼好很多了，可以下来走了要不是今天搞这个就出去了。\n明天去学校开家长会拿通知书，敬问了果果的成绩 463，好伤心呀，这样下去可怎么整，数学 86 还没有及格，明天和她一起去吧，听听老师说什么，\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3558, 'YnMuSRw7vuBnuDNqnDsDFM', 1, '2026-02-03 10:45:02', '2026-02-03 10:45:02', 'NORMAL', '亏妻，百财不入；亏夫，百病缠身；亏孝，百事不顺；亏身，脏腑不和；亏心，天地不容。\n​\n- 你提供的扩展版（八句）\n亏妻者百财不入，家宅不宁，福气远行；\n亏夫者百病缠身，心力交瘁，诸事不顺；\n爱夫者富贵相随，携手共进，幸福满盈；\n夫妻同心，其利断金，恩爱相伴，万事兴旺！\n\n#精彩剪辑 ', 'PUBLIC', 0, '{"tags": ["精彩剪辑"], "property": {}}'),
(3559, 'mEirPbeTzqm7dLD4ccpaB8', 1, '2026-02-05 13:19:53', '2026-02-05 13:19:53', 'NORMAL', '今天是 2026 年 2 月 5 日(周四)，今天跟果果一起讲物理时嚷她，突然有所想，如果很喜欢一个东西会想着破坏它吗，爱它都来不及怎么会伤害它呢，对人也是呀，如果很心疼她关心爱护她怎么可能会嚷她呢，让她伤心呢，说明没慢慢的不太在意她了。\n按照这个理论是不是敬动不动的嚷我吵架是不是她一直都这样的，没那在意我，根本不是说控制不了自己的情绪，还是不够在意。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3560, '9otU6nWk5NMk3cFeoodm4f', 1, '2026-02-06 22:40:39', '2026-02-06 22:40:39', 'NORMAL', '今天是 2025 年 2 月 7 日(周五)，给我妈买的今天的车票回去吧，在这她也不开心，天天在家里晃来晃去的，一点不想着别人，洗衣服不想着关门，写个作业问这问那的。随便的很。\n昨天敬说加加招过生日了，我妈去外面买些卤菜吃，给敬转了 200 元。 夜里 2 次被我妈咳醒了，不知是不是冻的，她就想着我，其次是加加明显的很，可怜之人必有可恨之处呀。真对。2 代人观念不一样天天吵架，敬也有点从男轻女。可能母亲更喜欢儿子吧。\n夜里做梦去公园又去超市的找敬没找到在卖房的地方睡着了，醒了发现自己是在家里，原来是被人送回来的，晕倒了，还旁边的人说我家在那的医生检查说依维莫司吃多了，乱七八糟的嘿又是那么的真实。\n\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}'),
(3561, 'HoisYKhDeNGe725U7fmQx5', 1, '2026-02-19 01:50:59', '2026-02-19 01:50:59', 'NORMAL', '今天是 2026 年 2 月 19 日(周四)，腰疼的问题算是康复了开心，还是要忍着疼运动的。\n最近公园里的人好多，和春晚分会场的原因吧，大家都想看看，有很多人来旅游的。\n最近小家伙在听封神演义。\n#日记 ', 'PRIVATE', 0, '{"tags": ["日记"], "property": {}}');

-- ----------------------------
-- 表结构: memo_organizer
-- ----------------------------
DROP TABLE IF EXISTS `memo_organizer`;
CREATE TABLE `memo_organizer` (
  `memo_id` int NOT NULL,
  `user_id` int NOT NULL,
  `pinned` int NOT NULL DEFAULT '0',
  UNIQUE KEY `memo_id` (`memo_id`,`user_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 memo_organizer 无数据

-- ----------------------------
-- 表结构: memo_relation
-- ----------------------------
DROP TABLE IF EXISTS `memo_relation`;
CREATE TABLE `memo_relation` (
  `memo_id` int NOT NULL,
  `related_memo_id` int NOT NULL,
  `type` varchar(256) NOT NULL,
  UNIQUE KEY `memo_id` (`memo_id`,`related_memo_id`,`type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 memo_relation 数据

-- ----------------------------
-- 表结构: migration_history
-- ----------------------------
DROP TABLE IF EXISTS `migration_history`;
CREATE TABLE `migration_history` (
  `version` varchar(256) NOT NULL,
  `created_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`version`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 migration_history 数据

-- ----------------------------
-- 表结构: reaction
-- ----------------------------
DROP TABLE IF EXISTS `reaction`;
CREATE TABLE `reaction` (
  `id` int NOT NULL AUTO_INCREMENT,
  `created_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `creator_id` int NOT NULL,
  `content_id` varchar(256) NOT NULL,
  `reaction_type` varchar(256) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `creator_id` (`creator_id`,`content_id`,`reaction_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 reaction 无数据

-- ----------------------------
-- 表结构: resource
-- ----------------------------
DROP TABLE IF EXISTS `resource`;
CREATE TABLE `resource` (
  `id` int NOT NULL AUTO_INCREMENT,
  `uid` varchar(256) NOT NULL,
  `creator_id` int NOT NULL,
  `created_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `filename` text NOT NULL,
  `blob` mediumblob,
  `type` varchar(256) NOT NULL DEFAULT '',
  `size` int NOT NULL DEFAULT '0',
  `memo_id` int DEFAULT NULL,
  `storage_type` varchar(256) NOT NULL DEFAULT '',
  `reference` text NOT NULL DEFAULT (_utf8mb4''),
  `payload` text NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uid` (`uid`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 resource 数据

-- ----------------------------
-- 表结构: system_setting
-- ----------------------------
DROP TABLE IF EXISTS `system_setting`;
CREATE TABLE `system_setting` (
  `name` varchar(256) NOT NULL,
  `value` longtext NOT NULL,
  `description` text NOT NULL,
  PRIMARY KEY (`name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 system_setting 数据

-- ----------------------------
-- 表结构: user
-- ----------------------------
DROP TABLE IF EXISTS `user`;
CREATE TABLE `user` (
  `id` int NOT NULL AUTO_INCREMENT,
  `created_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `row_status` varchar(256) NOT NULL DEFAULT 'NORMAL',
  `username` varchar(256) NOT NULL,
  `role` varchar(256) NOT NULL DEFAULT 'USER',
  `email` varchar(256) NOT NULL DEFAULT '',
  `nickname` varchar(256) NOT NULL DEFAULT '',
  `password_hash` varchar(256) NOT NULL,
  `avatar_url` longtext NOT NULL,
  `description` varchar(256) NOT NULL DEFAULT '',
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 user 数据

-- ----------------------------
-- 表结构: user_setting
-- ----------------------------
DROP TABLE IF EXISTS `user_setting`;
CREATE TABLE `user_setting` (
  `user_id` int NOT NULL,
  `key` varchar(256) NOT NULL,
  `value` longtext NOT NULL,
  UNIQUE KEY `user_id` (`user_id`,`key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- 表 user_setting 数据

SET FOREIGN_KEY_CHECKS = 1;
